-- Poems batch 102
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('56a2356d-145f-4b73-b50e-d1d2040e1757','送春','王十朋','宋','宋诗','song-poetry','','[]','楊花榆莢滿天飛，九十風光別我時。',32,'全唐诗/poet.song.119000.json','["楊花榆莢滿天飛，九十風光別我時。", "鳬鶩成行報公事，簿書中作送春詩。"]'),
('11adc600-7cfe-4238-a960-32047bb76bcc','州院獄空贈知錄孫聽','王十朋','宋','宋诗','song-poetry','','[]','把麾承乏楚邦東，獄及期年始報空。',32,'全唐诗/poet.song.119000.json','["把麾承乏楚邦東，獄及期年始報空。", "顧我自慚無德政，同僚深喜有于公。"]'),
('6206b40d-c485-4de8-810c-2f13f46f3115','鄱江樓分韵得月字','王十朋','宋','宋诗','song-poetry','','[]','尊酒相逢人二八，年少壯夫予白髮。',32,'全唐诗/poet.song.119000.json','["尊酒相逢人二八，年少壯夫予白髮。", "明年何處更登樓，遥望鄱陽江上月。"]'),
('84cba92e-8937-4d8d-838e-04705ad883bb','前端午一日會飲鄱江樓十有六人既分韵賦詩又戲成短篇','王十朋','宋','宋诗','song-poetry','','[]','佳節江樓上，同僚共把杯。',48,'全唐诗/poet.song.119000.json','["佳節江樓上，同僚共把杯。", "人如舜才子，名半漢雲臺。", "詩占城南首，音參古磬枚。", "宜添兩學士，相約訪蓬萊。"]'),
('3c3121fc-1563-4bd1-bcd8-cff3dc3e4467','五月二十日閔雨','王十朋','宋','宋诗','song-poetry','','[]','仲夏百穀長，中沐群龍分。',48,'全唐诗/poet.song.119000.json','["仲夏百穀長，中沐群龍分。", "此邦得何龍，行天莫辭勤。", "願於呼吸間，山川走風雲。", "亟下霈然澤，捄我心如焚。"]'),
('8119c96f-3e69-46b1-8252-522782c6027b','次韵葉樞密言別','王十朋','宋','宋诗','song-poetry','','[]','流落江湖歲月侵，九重側席念公深。',64,'全唐诗/poet.song.119000.json','["流落江湖歲月侵，九重側席念公深。", "漢庭寬大頒綸綍，楚閣清和襆枕衾。", "大壑巨魚欣復縱，虛舟積羽可能沉。", "乾坤整頓須元老，芝嶺柯山未許尋。"]'),
('94e6f21a-34e3-4cd6-924a-d09cbfeaba4e','洪景盧以郡釀飲客于野處園賦詩見寄次韵','王十朋','宋','宋诗','song-poetry','','[]','老境厭吏事，歸心遶丘園。',120,'全唐诗/poet.song.119000.json','["老境厭吏事，歸心遶丘園。", "日月忽有夏，炎蒸變春溫。", "芝堂孰新釀，誰共論文尊。", "緬懷蓬山舊，情好素所敦。", "殷勤十從事，往掃東坡軒。", "深杯滑琉璃，不比田家盆。", "醉吟到高處，舞月成清歡。", "我獨坐空齋，靜對忘憂萱。", "萱多憂未忘，香清思猶昏。", "懷君不成寐，兩處一聲猿。"]'),
('a2784a65-ac03-4e06-9f3d-2ed9ecdfac05','剡紙贈嘉叟以詩爲謝次韵','王十朋','宋','宋诗','song-poetry','','[]','仁義知君學子輿，豈惟詞賦似相如。',32,'全唐诗/poet.song.119000.json','["仁義知君學子輿，豈惟詞賦似相如。", "剡溪百幅敲冰紙，換得臨池小草書。"]'),
('30fde4b5-6aea-4ed9-b2f4-1e9ff042d626','伏日四望亭分韵得月字','王十朋','宋','宋诗','song-poetry','','[]','伏日何處游，危亭陰清樾。',48,'全唐诗/poet.song.119000.json','["伏日何處游，危亭陰清樾。", "十客同我登，詩興浩然發。", "四簷山在眼，奚用更拄笏。", "小飲未成醺，天邊見新月。"]'),
('4c3ec82f-35e0-416c-b299-a20c019e2801','次韵趙通判喜雨','王十朋','宋','宋诗','song-poetry','','[]','政拙時時費禱求，心憂赤子餓填溝。',32,'全唐诗/poet.song.119000.json','["政拙時時費禱求，心憂赤子餓填溝。", "一聲霹靂中宵雨，洗出江湖萬里秋。"]'),
('ed3ba31e-e2da-4299-9af1-73f40866d734','徐孺子亭','王十朋','宋','宋诗','song-poetry','','[]','一室不暇掃，心期掃天下。',240,'全唐诗/poet.song.119000.json','["一室不暇掃，心期掃天下。", "一榻不妄設，所待必賢者。", "南州傑出士，林泉事瀟洒。", "閉門謝弓招，道合不吾舍。", "誰云性少通，得一不爲寡。", "豫章豈私交，端欲重宗社。", "漢廷無此賢，忍使遺在野。", "交章薦天闕，聘禮備車馬。", "高人竟不屈，清風凜華夏。", "寄聲郭有道，一木難支厦。", "肯同樊處士，聲名祇虛假。", "鷄酒弔知音，韜光老松檟。", "倘令居孔門，行藏似回也。", "江西今仲舉，吏事飾儒雅。", "神交千載友，丹青妙摹寫。", "作亭古東湖，鱗鱗萬椽瓦。", "序嗤滕閣王，詞偪長沙賈。", "佳客從公游，湖光瑩尊斚。", "孺子真可師，世途何土苴。", "行矣浙東西，鉏犂各歸把。"]'),
('5c550ded-b4a4-46a8-9a00-39fd38c4c116','張安國舍人以南陵鄱陽雨暘不同示詩次韵','王十朋','宋','宋诗','song-poetry','','[]','春水平原天可拍，夏日如焚天可拆。',96,'全唐诗/poet.song.119000.json','["春水平原天可拍，夏日如焚天可拆。", "哀哉農民亦良苦，厭見常暘與常雨。", "去秋鄱陽偶中熟，巨室猶言廩無穀。", "萬畝家輸數千斛，路旁安得黔敖粥。", "吾君罪己同禹湯，思起傅巖調雨暘。", "暫勤千騎作南伯，要使炎嶠無餘殃。"]'),
('ba7009f6-3cf3-4455-8cb0-6b9225153cce','又次韵閔雨','王十朋','宋','宋诗','song-poetry','','[]','長夏蚊蠅倦驅拍，忽得緘封手親拆。',96,'全唐诗/poet.song.119000.json','["長夏蚊蠅倦驅拍，忽得緘封手親拆。", "新詩首及民疾苦，更閔鄱陽境無雨。", "鄱陽假守仁不熟，作郡端如種焦穀。", "匈中賸有愁千斛，闔門百指顔公粥。", "紫微好善嗤弘湯，眉間和氣如時暘。", "行歸廊廟贊化育，善人宜賞淫人殃。"]'),
('cb878a8d-ca45-4685-9c2d-8dc54942952d','次韵安國讀楚東酬唱集','王十朋','宋','宋诗','song-poetry','','[]','麾把江湖遇列仙，賡酬篇什滿鄱川。',64,'全唐诗/poet.song.119000.json','["麾把江湖遇列仙，賡酬篇什滿鄱川。", "竇家兄弟聯珠日，廬阜峯巒夕照天。", "三郡美名俱赫赫，一臺遺墨尚鮮鮮。", "紫微妙語題詩後，光艷真能照簡編。"]'),
('0db22d3e-99d7-4735-9fe8-85a82212e503','安國讀酬倡集有平生我亦詩成癖却悔來遲不與編之句今欲編後集得佳作數篇爲楚東詩社之光復用前韵','王十朋','宋','宋诗','song-poetry','','[]','六逸中無李謫仙，詩筒忽得舊臨川。',64,'全唐诗/poet.song.119000.json','["六逸中無李謫仙，詩筒忽得舊臨川。", "枝芳又類燕山桂，馬立欣瞻刺史天。", "公似虞臣宜作牧，我慙鼠技濫烹鮮。", "新詩不減顔公詠，貴若山王定不編。"]'),
('74dec34e-26c1-4301-b565-160779a956a1','次韵安國讀薦福壁間何卿二詩悵然有感','王十朋','宋','宋诗','song-poetry','','[]','金華遽作鬼中仙，嘆息真同子在川。',64,'全唐诗/poet.song.119000.json','["金華遽作鬼中仙，嘆息真同子在川。", "何遜詩猶在東閣，杜陵家不上青天。", "忠隨奏疏留丹闕，字落禪房照碧鮮。", "客過楚東吟楚些，唱酬新集定須編。"]'),
('2be1c8d5-bdcc-4f8a-8087-0f5a162a28ca','五月二十五日餞安國舍人于薦福洪右史王宗丞來會坐間用前韵','王十朋','宋','宋诗','song-poetry','','[]','尊酒相逢半八仙，鬢絲我類杜樊川。',64,'全唐诗/poet.song.119000.json','["尊酒相逢半八仙，鬢絲我類杜樊川。", "江東渭北四方客，楚尾吳頭五月天。", "蓮社濫陪陶令飲，兵厨聊擊陸生鮮。", "待將紅藥翻階句，別作鄱陽一集編。"]'),
('8f2644fd-79c7-439e-ab4a-cfbf545169f9','再用韵送安國','王十朋','宋','宋诗','song-poetry','','[]','辟穀留侯早得仙，慶鍾苗裔福如川。',64,'全唐诗/poet.song.119000.json','["辟穀留侯早得仙，慶鍾苗裔福如川。", "少年爲佛魁千佛，今日生天作二天。", "西掖代言詞俊逸，東湖題壁墨澄鮮。", "此行定有詩千首，莫惜因風寄數編。"]'),
('76dd01e6-4e97-4192-a385-e69fefd872f3','易芝山五老亭名曰五峯安國書之因成短篇','王十朋','宋','宋诗','song-poetry','','[]','三秀呈祥處，危亭壓衆坡。',48,'全唐诗/poet.song.119000.json','["三秀呈祥處，危亭壓衆坡。", "眼驚廬阜近，峯類夏雲多。", "喬嶽神咸會，蒼穹頂共摩。", "紫微新鐵畫，輝映楚江波。"]'),
('e8b23fb9-5899-487c-a5e2-a8c0c52e56fc','次韵安國題餘干趙公子養正堂堂張魏公所名也并爲作銘','王十朋','宋','宋诗','song-poetry','','[]','去歲西來路偶同，一言不肯話飄蓬。',64,'全唐诗/poet.song.119000.json','["去歲西來路偶同，一言不肯話飄蓬。", "銘成養正首示我，室坐不欺深念公。", "大盜欲纏遥拱北，群言交亂卒居東。", "可憐未戰身先死，貫日精忠化白虹。"]'),
('eac8a64e-2ba0-40e0-9a12-9336481d4272','次韵安國題清音堂','王十朋','宋','宋诗','song-poetry','','[]','堂上清音樂奏仙，洲如孤嶼媚中川。',64,'全唐诗/poet.song.119000.json','["堂上清音樂奏仙，洲如孤嶼媚中川。", "餘干遥服三苗國，陸羽高飛百越天。", "風過琵琶聲不斷，水來雲錦色長鮮。", "留題重遇張公子，又入詩中第一編。"]'),
('7c3f0c40-c061-436c-b5f4-70fa09e08762','郡齋舊有假山暇日命工葺之取石之嵌者繂置山頂汲水筩竹引而激之自頂而下有懸崖飛瀑之狀予既以蕭洒名齋因鎸二字于石戲成古風','王十朋','宋','宋诗','song-poetry','','[]','山從何來石無根，水從何來山無源。',166,'全唐诗/poet.song.119000.json','["山從何來石無根，水從何來山無源。", "忽然幻出如自然，群峯崒嵂聲潺湲。", "石工貌愚性機巧，兩手頃刻成陶甄。", "坐移野景到城郭，解使平地生林泉。", "香爐瀑布名天下，雁蕩龍湫更蕭洒。", "名山不見典刑存，得趣何須論真假。", "君不見晉公元勳兼盛德，綠野堂前羅澗石。", "又不見行行正直韓退之，汲井埋盆成小池。", "二公匈中有佳致，澗石盆池聊自戲。", "世間萬事皆戲耳，何止茲山與茲水。"]'),
('27a81c6f-02da-48f8-975e-808116c31f55','予自饒易夔以七月九日行饒人遮道挽留易轎由間道而去提點何德獻相追不及以詩見寄云斷橋截鐙亦堪憐始信林間別有天微見兵機第一義朱轓暫席廣文氊因次其韵','王十朋','宋','宋诗','song-poetry','','[]','誤辱鄱陽士庶憐，閉門不許出朝天。',32,'全唐诗/poet.song.119000.json','["誤辱鄱陽士庶憐，閉門不許出朝天。", "間行雖乏相如璧，得句全勝子敬氊。"]'),
('03f08a1f-f8ad-4af0-b44b-6d4ab22c69eb','同官酌別','王十朋','宋','宋诗','song-poetry','','[]','無德於民愧寇恂，斷橋留我荷鄱人。',32,'全唐诗/poet.song.119000.json','["無德於民愧寇恂，斷橋留我荷鄱人。", "同僚送別四十里，滿酌不辭三數巡。"]'),
('009e3b9c-9cd5-4f8b-9fde-18fc17fce5e9','途中寄何德獻','王十朋','宋','宋诗','song-poetry','','[]','邂逅江湖兩白頭，公方東駕我西游。',64,'全唐诗/poet.song.119000.json','["邂逅江湖兩白頭，公方東駕我西游。", "韓張呼酒情雖重，孔李通家好未修。", "慶朔詩高魏提點，秋香賦愧范饒州。", "驛筒從此相來往，別後何妨却倡酬。"]'),
('26b51f0d-bcb2-4130-a67b-3b06fc681e1e','宿何山孫氏竹軒觀張安國題壁因用其韵','王十朋','宋','宋诗','song-poetry','','[]','往來真箇及瓜期，見竹還思種竹時。',32,'全唐诗/poet.song.119000.json','["往來真箇及瓜期，見竹還思種竹時。", "今日賦詩添舊集，明朝不是楚東詩。"]'),
('25dc3c6c-9529-439d-9697-ef8ef715bb77','望廬山懷鄱陽同官','王十朋','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','五峯亭上同登日，遥望廬山在杳冥。',32,'全唐诗/poet.song.119000.json','["五峯亭上同登日，遥望廬山在杳冥。", "今日廬山真滿眼，回頭却望五峯亭。"]'),
('95504a1b-845f-4a2e-a725-9a845b2b026d','夢觀八陣圖','王十朋','宋','宋诗','song-poetry','','[]','易任夔子國，身猶在重湖。',72,'全唐诗/poet.song.119000.json','["易任夔子國，身猶在重湖。", "夢魂輒先往，臨江觀陣圖。", "奇才蓋三國，壯志吞兩都。", "惜哉功不遂，英雄爲欷歔。", "胡爲恍惚間，微茫見規模。", "清時耻談兵，武侯其戲予。"]'),
('8de803fb-4d9a-49fa-8cdc-918f4b2bd7c8','讀喻叔奇送行六詩','王十朋','宋','宋诗','song-poetry','','[]','鄱陽同事九十日，尊酒相呼恨不多。',32,'全唐诗/poet.song.119000.json','["鄱陽同事九十日，尊酒相呼恨不多。", "送別六詩詩似杜，絕勝劉子竹枝歌。"]'),
('5c1c0114-10b5-4f13-8cda-024ca777816d','都昌道中望廬山思故鄉','王十朋','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','肩輿終日在山間，忽見廬山憶雁山。',32,'全唐诗/poet.song.119000.json','["肩輿終日在山間，忽見廬山憶雁山。", "我亦無心入蓮社，願隨征雁及秋還。"]'),
('a3cecde2-5823-4124-bf70-8683565a7ded','過五柳灣','王十朋','宋','宋诗','song-poetry','','[]','出守江湖日念還，又扶衰病入巴山。',32,'全唐诗/poet.song.119000.json','["出守江湖日念還，又扶衰病入巴山。", "不能早作歸田計，愧過淵明五柳灣。"]'),
('20060282-4b3e-402b-802d-5d77b8402f48','宿栖真寺','王十朋','宋','宋诗','song-poetry','','[]','林間古剎號栖真，高躅難尋晉宋人。',32,'全唐诗/poet.song.119000.json','["林間古剎號栖真，高躅難尋晉宋人。", "我正迷途倦奔走，何繇來向此栖身。"]'),
('e9ea1db0-b6b4-47e1-bc84-885f6bd5d940','懷鄱陽士民','王十朋','宋','宋诗','song-poetry','','[]','來去鄱陽各有因，却疑行止亦由人。',32,'全唐诗/poet.song.119000.json','["來去鄱陽各有因，却疑行止亦由人。", "此心可鑒惟天日，公論難欺有士民。"]'),
('7b1e24ad-1e7b-4471-b9dc-2e0ea5a40c90','觀淵明畫像','王十朋','宋','宋诗','song-poetry','','[]','蕭洒風姿太絕塵，寓形宇內任天真。',32,'全唐诗/poet.song.119000.json','["蕭洒風姿太絕塵，寓形宇內任天真。", "絃歌只用八十日，便作田園歸去人。"]'),
('8e3a4d8f-bcc6-47ff-8066-6f425b0a847c','題翠軒','王十朋','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','淵明舊隠名棲真，中有栖真閑道人。',64,'全唐诗/poet.song.119000.json','["淵明舊隠名棲真，中有栖真閑道人。", "廬山咫尺脚不到，開軒種竹清且新。", "我到山中越三宿，似與道人緣分熟。", "皇恩若許歸故鄉，拭眼重來看修竹。"]'),
('31224d0b-13d7-4a63-ab44-4f41387d6e71','寓栖真四宿時二兒寓上庠未知去留又祠命未下頗以爲懷','王十朋','宋','宋诗','song-poetry','','[]','白帝知何處，黄山且少留。',48,'全唐诗/poet.song.119000.json','["白帝知何處，黄山且少留。", "心慙陶靖節，政愧范饒州。", "桑下越三宿，江邊將半秋。", "家書及祠命，何日解吾憂。"]'),
('d8ce91c2-95af-4bdb-bdab-02360d341fb5','望大孤山','王十朋','宋','宋诗','song-poetry','','[]','鄱陽古渡留遺冢，湖口烟鬟露淡粧。',32,'全唐诗/poet.song.119000.json','["鄱陽古渡留遺冢，湖口烟鬟露淡粧。", "九女何由從童子，兩姑那肯嫁彭郎。"]'),
('9d638b75-62c5-4e90-96a6-e4da5fb058ca','題湖口驛','王十朋','宋','宋诗','song-poetry','','[]','蘆花洲渚江人邦，我來把酒臨西窗。',64,'全唐诗/poet.song.119000.json','["蘆花洲渚江人邦，我來把酒臨西窗。", "五祖六祖山照眼，清流濁流水同江。", "孤山大小各嶄絕，鍾石上下相舂撞。", "千帆出沒烟雨裏，何如鷗鷺飛雙雙。"]'),
('7765a686-8cc5-4a62-a3c7-6ebc5d895f79','至江州','王十朋','宋','宋诗','song-poetry','','[]','遥與齊侯會，江人故國存。',24,'全唐诗/poet.song.119000.json','["遥與齊侯會，江人故國存。", "夷吾嗟不見，北望是中原。"]'),
('7e9fe61e-7431-488c-8839-d8bb3f0263fe','和叔奇見寄','王十朋','宋','宋诗','song-poetry','','[]','荔子黄甘豈不香，路經九折歎王陽。',32,'全唐诗/poet.song.119000.json','["荔子黄甘豈不香，路經九折歎王陽。", "羨君松竹吟哦處，橘在懷中母在堂。"]'),
('1e6edc8c-f0d2-45f1-8ae6-1e28264c174c','讀趙果州詩','王十朋','宋','宋诗','song-poetry','','[]','眉宇胸襟兩不塵，唾成珠玉更清新。',32,'全唐诗/poet.song.119000.json','["眉宇胸襟兩不塵，唾成珠玉更清新。", "惜哉不使蘇仙見，題品寧先趙德麟。"]'),
('5fb3eb20-565d-4289-a647-65c76e69e855','讀王文正遺事','王十朋','宋','宋诗','song-poetry','','[]','太平宰相王文正，盛德真宜有子孫。',32,'全唐诗/poet.song.119000.json','["太平宰相王文正，盛德真宜有子孫。", "舊國今餘幾喬木，三槐陰滿宋乾坤。"]'),
('aedf4e48-2e73-448a-b819-ad5b39559a92','題庾樓呈唐守立夫','王十朋','宋','宋诗','song-poetry','','[]','遥望香爐氣欲烟，坐觀湓浦浪舂天。',64,'全唐诗/poet.song.119000.json','["遥望香爐氣欲烟，坐觀湓浦浪舂天。", "山川滿目古今迹，雲水千帆名利船。", "萬點白鷗家浩渺，一聲赤壁酹嬋娟。", "詩篇細讀張耘叟，倚遍闌干思黯然。"]'),
('7cd43a6c-f56f-4763-b9ae-2f9f7db7eacc','宿太平興國宮  其一','王十朋','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','此來端不爲行春，欲向廬山訪隠淪。',32,'全唐诗/poet.song.119000.json','["此來端不爲行春，欲向廬山訪隠淪。", "聖主如容食祠祿，願爲主管太平人。"]'),
('89af6759-7d6e-4187-993c-fc3b1ad9978b','宿太平興國宮  其二','王十朋','宋','宋诗','song-poetry','','[]','九天使者號真王，聖治峯前古道場。',32,'全唐诗/poet.song.119000.json','["九天使者號真王，聖治峯前古道場。", "五百年間聖君出，太平治效過明皇。"]'),
('728cbe83-549d-46ab-b48a-4334dd62a21d','宿東林贈然老','王十朋','宋','宋诗','song-poetry','','[]','儒服方袍兩禿翁，兩家元是一家風。',64,'全唐诗/poet.song.119000.json','["儒服方袍兩禿翁，兩家元是一家風。", "歸田我欲效元亮，結社師真如遠公。", "雁蕩此生看未足，虎溪一笑偶然同。", "清風明月處處共，寧間江西與浙東。"]'),
('9c452c1a-3f08-4e6d-b233-bf436887b409','白公草堂','王十朋','宋','宋诗','song-poetry','','[]','廬阜雙林寺，爐峯幾瓣香。',24,'全唐诗/poet.song.119000.json','["廬阜雙林寺，爐峯幾瓣香。", "日烘烟嫋紫，敬爲白公堂。"]'),
('65e47a7a-7eb8-4f89-9e07-31ac3def3522','蓮社','王十朋','宋','宋诗','song-poetry','','[]','淵明修靜不談禪，孔老門中各自賢。',32,'全唐诗/poet.song.119000.json','["淵明修靜不談禪，孔老門中各自賢。", "送別虎溪三笑後，白蓮流水兩淒然。"]'),
('10aa2754-0412-47f7-9d47-e49ea113afb8','題東林聰明泉','王十朋','宋','宋诗','song-poetry','','[]','遠公白蓮社，旁有聰明泉。',72,'全唐诗/poet.song.119000.json','["遠公白蓮社，旁有聰明泉。", "飲此誰聰明，社中十八賢。", "堯舜不曾飲，聰明本諸天。", "我輩雖飲之，聰明不加前。", "爲愛此水清，一酌滌塵緣。", "却恐愚此水，愚名自今傳。"]'),
('5587d959-4ab0-4fe8-9966-8539a320644d','游圓通','王十朋','宋','宋诗','song-poetry','','[]','夾徑森森鬰老松，烟霞深處忽聞鍾。',64,'全唐诗/poet.song.119000.json','["夾徑森森鬰老松，烟霞深處忽聞鍾。", "虎溪水隔侯溪水，馬耳峯聯石耳峯。", "遺像人猶思後主，開山僧不畏先鋒。", "明朝杖屨山南去，噴沫飛流看玉龍。"]'),
('bfa0a2c9-5ca4-4323-aec5-b7385740246e','贈訥老','王十朋','宋','宋诗','song-poetry','','[]','路入侯溪無故侯，梵王祠宇占清幽。',32,'全唐诗/poet.song.119000.json','["路入侯溪無故侯，梵王祠宇占清幽。", "語言文字真吾病，喜共維摩大士游。"]'),
('27a818c2-b7d8-4325-bec0-88058c115d2e','題至樂亭  其一','王十朋','宋','宋诗','song-poetry','','[]','雙閣壯緇林，一亭餘古屋。',48,'全唐诗/poet.song.119000.json','["雙閣壯緇林，一亭餘古屋。", "庭垂祖師柏，風動禪房竹。", "山禽語晝寂，巖花吐秋馥。", "此樂本來無，行人慕幽獨。"]'),
('4561683a-a95e-48f8-b056-29086e3d640c','題至樂亭  其二','王十朋','宋','宋诗','song-poetry','','[]','石散山形在，池乾水意存。',24,'全唐诗/poet.song.119000.json','["石散山形在，池乾水意存。", "游心山水外，至樂不容言。"]'),
('6fd7d3ae-794b-4858-beb0-7aac821ea7ac','勝書記蜀僧也和予游玄通一詩用贈訥老韵酬','王十朋','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','未向夔門訪武侯，禪房杖屨謾通幽。',32,'全唐诗/poet.song.119000.json','["未向夔門訪武侯，禪房杖屨謾通幽。", "題詩况有詩僧和，深喜廬山得勝游。"]'),
('cd32d979-e2dc-4f9e-a440-4cc68127709f','次韵唐立夫以日者命狀見寄','王十朋','宋','宋诗','song-poetry','','[]','天下名山欲徧看，未能高卧愧陳摶。',32,'全唐诗/poet.song.119000.json','["天下名山欲徧看，未能高卧愧陳摶。", "山人誤說潛夫命，只慕冥鴻不慕官。"]'),
('9fb09758-4dd9-4f8d-8b1b-6e7557005da1','趙果州致羊酒走筆戲酬','王十朋','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','十日廬山游，蔬腸作雷鳴。',96,'全唐诗/poet.song.119000.json','["十日廬山游，蔬腸作雷鳴。", "對食有長鋏，論文無麴生。", "清浄似齋戒，遲留欲修行。", "翩翩佳公子，憐我厭藜羹。", "魚酒致遠意，詩篇慰西征。", "薑新微带糟，鮓美香流罌。", "今宵羊踏園，魂夢定須驚。", "回首白蓮社，姑作陶淵明。"]'),
('3b5fb6d4-5cc8-4b3b-a1fc-1a8ec5e15248','題訥菴','王十朋','宋','宋诗','song-poetry','','[]','休論摩詰與文殊，試把菴名扣大儒。',64,'全唐诗/poet.song.119000.json','["休論摩詰與文殊，試把菴名扣大儒。", "君子於言端欲訥，賢人終日只如愚。", "樂山自昔稱仁者，利口由來惡嗇夫。", "聽法雙峯空聳耳，老禪惟要一言無。"]'),
('9e11c4e2-3898-4d45-b17a-3a542637960b','題康王觀','王十朋','宋','宋诗','song-poetry','','[]','趣在烟霞世味輕，天將廬阜慰西征。',64,'全唐诗/poet.song.119000.json','["趣在烟霞世味輕，天將廬阜慰西征。", "且須細看康王谷，未用遥尋白帝城。", "星子地分天上宿，谷簾泉占酒中名。", "凌雲仙客知多少，肯向風波世路行。"]'),
('219658c6-6616-4c6f-8f16-cf7aa343781f','湯泉','王十朋','宋','宋诗','song-poetry','','[]','占得乾坤造化爐，地中沸出巧工夫。',32,'全唐诗/poet.song.119000.json','["占得乾坤造化爐，地中沸出巧工夫。", "泉猶自作炎凉態，休說衆生垢有無。"]'),
('3f853ae6-5540-4010-a3ee-da78f4614705','宿歸宗寺','王十朋','宋','宋诗','song-poetry','','[]','好山無數不知名，路入禪林氣更清。',64,'全唐诗/poet.song.119000.json','["好山無數不知名，路入禪林氣更清。", "巖石有時開鏡面，溪流入夜作鸞聲。", "臨池墨客餘風韵，拭眼高僧避寵榮。", "安得清風生兩腋，紫霄峯頂望寰瀛。"]'),
('32c9168a-4d36-4c24-8678-cf6a15997362','簡寂觀','王十朋','宋','宋诗','song-poetry','','[]','縈迂草徑少人行，忽有黄冠洞口迎。',64,'全唐诗/poet.song.119000.json','["縈迂草徑少人行，忽有黄冠洞口迎。", "自笑荒蕪陶靖節，更尋簡寂陸先生。", "朝真惟有壇前石，流水猶餘絃上聲。", "欲聽金雞上金闕，紫霄峰際白雲橫。"]'),
('0859a844-ac7e-4be0-8931-6b982b917a16','游開先寺觀香爐瀑布諸峯讀李蘇二仙詩知廬阜之勝在是記以十韵','王十朋','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廬山何處好，勝地有開先。',120,'全唐诗/poet.song.119000.json','["廬山何處好，勝地有開先。", "瀑水漱寒玉，香爐生紫烟。", "紫霄長近日，黄石不知年。", "雁蕩靈湫合，酆城寶劍連。", "龜行似朝斗，鶴唳欲沖天。", "馬尾只自洗，牛頭奚用穿。", "雄詞惟太白，妙句更蘇仙。", "寺占星流處，橋飛月出邊。", "碑方閲華藏，夢已到栖賢。", "明日游三峽，歸心定决然。"]'),
('814d00bd-4892-4ba3-a3ee-58354b67bb92','游萬杉院  其一','王十朋','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','誰栽沙苑千株柳，爭似廬山萬本杉。',32,'全唐诗/poet.song.119000.json','["誰栽沙苑千株柳，爭似廬山萬本杉。", "如欲歲寒長不改，更栽松栢滿幽巖。"]'),
('52feeb68-127c-4e6e-9a00-1381592e99c0','游萬杉院  其二','王十朋','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廬山三百六十所，長有神光照萬杉。',32,'全唐诗/poet.song.119000.json','["廬山三百六十所，長有神光照萬杉。", "借問山中有何寶，仁宗飛白字非凡。"]'),
('9fa98a11-ad1f-4057-a186-695f8bdc6fd6','游萬杉院  其三','王十朋','宋','宋诗','song-poetry','','[]','一水遥分瀑布餘，萬杉深處散明珠。',32,'全唐诗/poet.song.119000.json','["一水遥分瀑布餘，萬杉深處散明珠。", "不知散却珠多少，能買人間富貴無。"]'),
('cc7d1ca7-9a73-41e7-b4b0-9f7995bb36db','飛橋','王十朋','宋','宋诗','song-poetry','','[]','蘇仙詩裏見飛橋，欲看虹霓踏玉腰。',32,'全唐诗/poet.song.119000.json','["蘇仙詩裏見飛橋，欲看虹霓踏玉腰。", "我到山中虹始見，楊輝有月印青霄。"]'),
('d1346302-789a-4c66-9746-d3ebd8f5f463','三峽橋  其一','王十朋','宋','宋诗','song-poetry','','[]','三峽橋邊杖屨游，此身疑已到夔州。',32,'全唐诗/poet.song.119000.json','["三峽橋邊杖屨游，此身疑已到夔州。", "題詩欲比真三峽，深媿詞源不倒流。"]'),
('416eda68-9cee-4e72-8e70-ea78e18b237e','三峽橋  其二','王十朋','宋','宋诗','song-poetry','','[]','灧澦瞿塘在眼前，便應從此上青天。',32,'全唐诗/poet.song.119000.json','["灧澦瞿塘在眼前，便應從此上青天。", "秋風脫葉隨流下，疑是十帆出峽船。"]'),
('28589c61-2be2-4eb4-bb92-d5d59aaa6884','五老峯','王十朋','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','投老山林興已濃，廬山欣與老人逢。',32,'全唐诗/poet.song.119000.json','["投老山林興已濃，廬山欣與老人逢。", "定須容我來同老，五老峯邊更有峰。"]'),
('fbc052da-59d6-420c-948a-f4ec78ec43c5','玉淵','王十朋','宋','宋诗','song-poetry','','[]','誰决銀河落半天，飛流濺沫五峯前。',32,'全唐诗/poet.song.119000.json','["誰决銀河落半天，飛流濺沫五峯前。", "山中草木皆光潤，知有含輝玉在淵。"]'),
('9b3b6f18-ca54-44aa-bdc7-ad62069183c4','宿栖賢','王十朋','宋','宋诗','song-poetry','','[]','瀑水聲中夜不眠，星河影動半秋天。',48,'全唐诗/poet.song.119000.json','["瀑水聲中夜不眠，星河影動半秋天。", "誰云灧澦瞿唐遠，只在洋瀾左蠡邊。", "師子吼成方外法，石人參得定中禪。"]'),
('b847e839-792e-4a77-905b-4422dae56824','游楞伽  其一','王十朋','宋','宋诗','song-poetry','','[]','涉水穿雲一徑迂，朱砂峯下訪僧居。',32,'全唐诗/poet.song.119000.json','["涉水穿雲一徑迂，朱砂峯下訪僧居。", "鳥鳴蟬噪更幽處，中有人藏萬卷書。"]'),
('cfead0c9-b4ea-4670-8009-2fbefcd9d53a','游楞伽  其二','王十朋','宋','宋诗','song-poetry','','[]','老僧元不服朱砂，境靜心灰壽自遐。',32,'全唐诗/poet.song.119000.json','["老僧元不服朱砂，境靜心灰壽自遐。", "廬阜招提三百所，只餘折桂與楞伽。"]'),
('a655c9b5-2f1e-409a-8935-e9fbf954a4ee','游楞伽  其三','王十朋','宋','宋诗','song-poetry','','[]','藏書閣在已無書，山色依然滿舊居。',32,'全唐诗/poet.song.119000.json','["藏書閣在已無書，山色依然滿舊居。", "留得婦人三墨竹，金鍾聲裏尚扶踈。"]'),
('4c6f03d3-7bad-459d-86f3-6cfc69294b6e','游南山入康谷以不觀谷簾泉爲恨南康李守致上尊乃此泉名也戲成一絕','王十朋','宋','宋诗','song-poetry','','[]','不飲谷簾山下水，徒觀瀑布下長川。',32,'全唐诗/poet.song.119000.json','["不飲谷簾山下水，徒觀瀑布下長川。", "使君破我游山恨，酒寄人間第一泉。"]'),
('0f6a57ca-9930-48cc-b939-b94d09477017','石鏡溪','王十朋','宋','宋诗','song-poetry','','[]','山中有鏡石爲臺，雲霧深藏未肯開。',32,'全唐诗/poet.song.119000.json','["山中有鏡石爲臺，雲霧深藏未肯開。", "別有一溪清似鏡，不須人爲拂塵埃。"]'),
('d2b223f8-1f99-49b7-86f2-ccd9645aa5d5','廬山紀游四十韵','王十朋','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','我性好山水，思向廬山廬。',288,'全唐诗/poet.song.119000.json','["我性好山水，思向廬山廬。", "五老招我游，有約芝山初。", "茲行適所願，孰曰非天與。", "入眼庾公樓，興已先籃輿。", "雲開聖治峯，石扣仙人居。", "香爐望烟靄，浄社觀芙蕖。", "虎溪聊自笑，天池步宜紓。", "半月圓通留，幽亭樂有餘。", "趣如六一翁，境似山環滁。", "侯溪煮月泉，石耳供巖蔬。", "破戒戲魚酒，踏園夢羊豬。", "賢關得家音，天恩拜新除。", "抗章復辭免，行色仍躊躇。", "遂作南山游，首過荆林虛。", "凌雲入康谷，臨流清可漁。", "欲飲第一水，山深足趑趄。", "湯泉本何來，忽從龍口噓。", "鸞溪尋故家，墨沼波猶潴。", "石鏡不可見，懸崖照誰梳。", "尋真到簡寂，入觀驚丘墟。", "緬懷黄與陸，何處飄霞裾。", "眼明見飛瀑，澗壑鳴瓊琚。", "何落句思李，練飛詩陋儒。", "新橋跨虹霓，出月明蟾蜍。"]'),
('bf847ac6-4437-4e1e-ae31-7cae318537de','歸宗樅老言廬山有對云簡寂觀中甜苦笋歸宗寺裏淡鹹齏予因以湯泉石鏡戲成一絕','王十朋','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','參禪得味鹹齏淡，學道忘憂苦笋甜。',32,'全唐诗/poet.song.119000.json','["參禪得味鹹齏淡，學道忘憂苦笋甜。", "石鏡與時爲顯晦，湯泉涉世有凉炎。"]'),
('34fd0b76-d3b0-4045-963f-0ceb4e3d1d1e','開先僧贈石菖蒲','王十朋','宋','宋诗','song-poetry','','[]','結根拳石伴孤僧，對我還同道眼青。',32,'全唐诗/poet.song.119000.json','["結根拳石伴孤僧，對我還同道眼青。", "莫遣塵埃侵九節，會須重作玉衡星。"]'),
('4c57f33c-8ab9-4776-9f65-15c491a29ee3','別廬山','王十朋','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','山北山南已徧游，又移行李向西州。',64,'全唐诗/poet.song.119000.json','["山北山南已徧游，又移行李向西州。", "身如孟子論行止，心愧淵明任去留。", "峯頂今宵應好月，人間明日是中秋。", "天池一塔遥相送，深喜浮雲爲我收。"]'),
('986b88eb-a109-4a46-8af3-1738f6c013fc','題天華院','王十朋','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','游徧廬山寺，茲山亦自佳。',24,'全唐诗/poet.song.119000.json','["游徧廬山寺，茲山亦自佳。", "數宵緣石耳，一飯爲天華。"]'),
('d24056bf-1208-4781-bc1f-643f489f58ea','中秋宿瀼溪驛  其一','王十朋','宋','宋诗','song-poetry','','[]','半月游廬阜，中秋宿瀼溪。',48,'全唐诗/poet.song.119000.json','["半月游廬阜，中秋宿瀼溪。", "祠尋元子隠，樹認赤烏栖。", "坐待雲開月，行愁雨作泥。", "鄱人應話我，身在九江西。"]'),
('b3c6eee8-6985-4e9e-9add-aefa5bb97530','中秋宿瀼溪驛  其二','王十朋','宋','宋诗','song-poetry','','[]','浪士舊游處，旅人今兩宵。',48,'全唐诗/poet.song.119000.json','["浪士舊游處，旅人今兩宵。", "赤烏曾紀瑞，銀杏敢興妖。", "照眼水名瀼，回頭山憶堯。", "男兒四方志，寧憚蜀天遥。"]'),
('0cfe8e79-22c4-4f55-a916-97b569fcb5c3','瑞昌李宰贈元次山集','王十朋','宋','宋诗','song-poetry','','[]','蒼然山色泠然聲，次山之文讀可驚。',64,'全唐诗/poet.song.119000.json','["蒼然山色泠然聲，次山之文讀可驚。", "令君贈我有深意，欲以漫浪更吾名。", "我雖有官真漫耳，誰遣夔門稱刺史。", "開卷欣逢子元子，尤愛清泠瀼溪水。"]'),
('bed5af54-3245-40e2-8599-a05aa8864967','中秋思鄉用瀼溪韵','王十朋','宋','宋诗','song-poetry','','[]','今夜中秋月，還應滿故溪。',48,'全唐诗/poet.song.119000.json','["今夜中秋月，還應滿故溪。", "遥知千里共，深羨一枝栖。", "歲月飄如夢，年時醉似泥。", "可憐佳節裏，兄弟各東西。"]'),
('80b56535-2a30-4cc7-9e84-604e8e9b7b9f','宿多福院','王十朋','宋','宋诗','song-poetry','','[]','古剎名多福，初來宿上方。',48,'全唐诗/poet.song.119000.json','["古剎名多福，初來宿上方。", "蜂窠懸敗壁，燕壘滿空梁。", "蝙蝠沸盈室，塵埃堆滿床。", "香燒數炷柏，移下小僧房。"]'),
('0371802d-0b1c-4606-b6bc-fe7bc603241e','昨日飯金城觀今日飯石田驛','王十朋','宋','宋诗','song-poetry','','[]','城縱是金非願得，田雖有石尚堪耕。',32,'全唐诗/poet.song.119000.json','["城縱是金非願得，田雖有石尚堪耕。", "欲隨秋雁蕩中去，却向杜鵑啼處行。"]'),
('39e9ede6-e5a2-400c-a5c7-c6f09bdd2d59','瑞昌永興道中作','王十朋','宋','宋诗','song-poetry','','[]','蜀道青天手未摩，肩輿從此上危坡。',64,'全唐诗/poet.song.119000.json','["蜀道青天手未摩，肩輿從此上危坡。", "永城朝過路方永，多福夜眠僧不多。", "岡畔泥深愁欲雨，渡頭舟小喜無波。", "青山滿眼森高木，正爲人稀免斧柯。"]'),
('19b528bd-cc8d-4117-b2b0-5f68f16c3759','宿真如寺  其一','王十朋','宋','宋诗','song-poetry','','[]','迢迢脩嶺踏朱紅，林壑深藏古梵宮。',32,'全唐诗/poet.song.119000.json','["迢迢脩嶺踏朱紅，林壑深藏古梵宮。", "一閣摩雲鎖宸翰，神光長照大江東。"]'),
('0fba89fc-9932-454b-a69b-77956209a90d','宿真如寺  其二','王十朋','宋','宋诗','song-poetry','','[]','白帝孤城在何許，遥想西風急砧杵。',32,'全唐诗/poet.song.119000.json','["白帝孤城在何許，遥想西風急砧杵。", "我行初至渫泉山，御書閣下眠秋雨。"]'),
('76912b20-9399-4f1a-aed6-6712042f9493','至興國軍  其一','王十朋','宋','宋诗','song-poetry','','[]','一宿真如飲渫泉，鍾聲催上渡頭船。',32,'全唐诗/poet.song.119000.json','["一宿真如飲渫泉，鍾聲催上渡頭船。", "夜來一雨湖光好，擬把窮愁洗富川。"]'),
('550c5e19-7460-4b52-ae21-0cd05b438d81','至興國軍  其二','王十朋','宋','宋诗','song-poetry','','["\u897f\u6e56"]','近涵州郭遠連天，明月清風不計錢。',32,'全唐诗/poet.song.119000.json','["近涵州郭遠連天，明月清風不計錢。", "欲比西湖及西子，品題須喚舊蘇仙。"]'),
('56f8aba8-17d2-46a3-b4e6-48dc5e478cdf','題懷坡閣贈王景文國正  其一','王十朋','宋','宋诗','song-poetry','','["\u897f\u6e56"]','窮途喜見富川波，已覺茲行所得多。',32,'全唐诗/poet.song.119000.json','["窮途喜見富川波，已覺茲行所得多。", "杭潁西湖堪鼎足，兼懷六一與東坡。"]'),
('649c1933-8f20-4bbb-afda-d567f237ee5a','題懷坡閣贈王景文國正  其二','王十朋','宋','宋诗','song-poetry','','[]','眼中十里是烟波，天遣江山助子多。',32,'全唐诗/poet.song.119000.json','["眼中十里是烟波，天遣江山助子多。", "自是玉堂揮翰手，不應此處久懷坡。"]'),
('b91128b6-3e88-4497-8d01-52064bc946b4','贈陶永州','王十朋','宋','宋诗','song-poetry','','[]','雲作愁天風怒號，遥瞻白帝夢猶勞。',64,'全唐诗/poet.song.119000.json','["雲作愁天風怒號，遥瞻白帝夢猶勞。", "口吟太白路難蜀，心慕淵明人遇陶。", "富水已厭家食久，浯溪行看石崖高。", "人生五馬何曾貴，堪嘆相逢各二毛。"]'),
('81fc7ccf-2355-424f-a7ac-146aa7fc3372','次韵王景文贈行四絕  其一','王十朋','宋','宋诗','song-poetry','','[]','聖主龍飛白首郎，誤蒙親擢與南牀。',32,'全唐诗/poet.song.119000.json','["聖主龍飛白首郎，誤蒙親擢與南牀。", "言多妄發汲長孺，心不敢邪蘇世長。"]'),
('7756b658-1060-41af-8e6a-dcba2bb079ee','次韵王景文贈行四絕  其二','王十朋','宋','宋诗','song-poetry','','[]','天涯行客正悲秋，况向鶻孫愁處愁。',32,'全唐诗/poet.song.119000.json','["天涯行客正悲秋，况向鶻孫愁處愁。", "歌聽竹枝劉刺史，詩懷慶朔范饒州。"]'),
('40659e10-f8c6-4fd0-8821-a95a99560ffe','次韵王景文贈行四絕  其三','王十朋','宋','宋诗','song-poetry','','[]','吾道從來自不孤，果蒙好語慰榛蕪。',32,'全唐诗/poet.song.119000.json','["吾道從來自不孤，果蒙好語慰榛蕪。", "孜孜相勉惟名節，官職何須校有無。"]'),
('daad1059-e3e9-465b-b5aa-d122f2a00b1f','次韵王景文贈行四絕  其四','王十朋','宋','宋诗','song-poetry','','[]','君年方壯我顔蒼，敢以宗盟論雁行。',32,'全唐诗/poet.song.119000.json','["君年方壯我顔蒼，敢以宗盟論雁行。", "孝子忠臣公論在，送行詩似少陵章。"]'),
('aca73a87-bf4e-4862-8405-ef344586db1c','題謀野堂','王十朋','宋','宋诗','song-poetry','','[]','滿目江山富一堂，公餘身在水雲鄉。',64,'全唐诗/poet.song.119000.json','["滿目江山富一堂，公餘身在水雲鄉。", "遥岑更作有無色，西子爲誰濃淡粧。", "荷有香能清燕寢，纓無塵可濯滄浪。", "使君坐此謀何事，境靜心清百慮忘。"]'),
('b2b5f170-086b-44ed-b221-7c1a23eded80','聞詩聞禮不赴秋試以七月二十五日離太學八月二十六日至興國軍喜其來也因作是詩','王十朋','宋','宋诗','song-poetry','','[]','不將蝸角與人爭，走侍雙親蜀道行。',64,'全唐诗/poet.song.119000.json','["不將蝸角與人爭，走侍雙親蜀道行。", "免爲家書憂子美，飽聞情話悅淵明。", "一名所得知多少，萬事真宜審重輕。", "更願相隨且歸去，田園薄有要同耕。"]'),
('d2ebd4ce-8f47-4295-92c2-c4f556899510','途中遇雨','王十朋','宋','宋诗','song-poetry','','[]','夜宿佛圖市，曉穿山障中。',48,'全唐诗/poet.song.119000.json','["夜宿佛圖市，曉穿山障中。", "泥愁行滑滑，雨厭落濛濛。", "晚稻短長熟，野花深淺紅。", "江西又湖北，馬首幾時東。"]'),
('889d39bd-b8cd-406b-bdb6-4b82e59ae646','宿大冶縣','王十朋','宋','宋诗','song-poetry','','[]','隔岸呼舟子，湖山日欲曛。',48,'全唐诗/poet.song.119000.json','["隔岸呼舟子，湖山日欲曛。", "人家數點火，風物一川雲。", "小渡漁人占，中流縣界分。", "秋深山驛冷，蕭瑟夜深聞。"]'),
('573c56d3-0c5f-4f53-9ade-4ac4a5663d4e','東方寺','王十朋','宋','宋诗','song-poetry','','[]','大冶迢迢接武昌，西征踰月到東方。',32,'全唐诗/poet.song.119000.json','["大冶迢迢接武昌，西征踰月到東方。", "白蓮智印蟠桃朔，仙佛同歸一道場。"]'),
('d235ac26-1761-49bc-8f58-d92a7e31aa5d','宋武帝廟','王十朋','宋','宋诗','song-poetry','','[]','規模仍舊晉乾坤，遺恨于今失所尊。',32,'全唐诗/poet.song.119000.json','["規模仍舊晉乾坤，遺恨于今失所尊。", "廟食鐵山精爽在，鑄兵思欲定中原。"]'),
('044194c9-b4ea-4b57-b585-a4ae0f58523f','宿武昌縣','王十朋','宋','宋诗','song-poetry','','[]','行盡江西路，初乘湖北舟。',48,'全唐诗/poet.song.119000.json','["行盡江西路，初乘湖北舟。", "荒城嘆權皓，賢令惜韓歐。", "漫浪無元叟，崢嶸有故洲。", "神仙雪堂客，幾度絕江游。"]'),
('a3ebb3f7-0bac-4997-98cb-1bdb0c32ecf9','游西山寺','王十朋','宋','宋诗','song-poetry','','[]','好山遺恨恐他年，冒雨登臨興浩然。',64,'全唐诗/poet.song.119000.json','["好山遺恨恐他年，冒雨登臨興浩然。", "避暑離宮閔吳主，橫舟巨浪壯蘇仙。", "秋聲蕭瑟松風閣，巖乳清泠菩薩泉。", "山半有亭名可易，漫郎尤惡曲并圓。"]'),
('ebb21715-fb62-4b64-9734-c918c488ee91','遇雨兩宿縣驛','王十朋','宋','宋诗','song-poetry','','[]','絕巘笙簫斷，鄰州鼓角聞。',48,'全唐诗/poet.song.119000.json','["絕巘笙簫斷，鄰州鼓角聞。", "江淮兩岸雨，吳楚一天雲。", "有驛聊堪憇，無尊亦自欣。", "西山逢老宿，往事說三分。"]'),
('29f550f9-0c30-4242-b120-640c0c2006f4','吳大帝廟','王十朋','宋','宋诗','song-poetry','','[]','樊山八字形長在，漢鼎三分國盡墟。',32,'全唐诗/poet.song.119000.json','["樊山八字形長在，漢鼎三分國盡墟。", "安樂故宮猶廟食，遺民時薦武昌魚。"]'),
('bf2ab5ab-87fd-4f1f-8fc0-6f200c72e360','望黄州','王十朋','宋','宋诗','song-poetry','','[]','肩輿萬松嶺，鼓楫蘆花洲。',48,'全唐诗/poet.song.119000.json','["肩輿萬松嶺，鼓楫蘆花洲。", "忽見江上山，人言是黄州。", "懷人望雪堂，讀記思竹樓。", "二豪不復見，大江自東流。"]'),
('6b0b5294-4608-438b-9547-42ad69324cf3','過樊口','王十朋','宋','宋诗','song-poetry','','[]','短棹經樊口，高人憶漫郎。',48,'全唐诗/poet.song.119000.json','["短棹經樊口，高人憶漫郎。", "杯湖誰復泛，退谷自深藏。", "鄂渚風烟接，吳宮草樹荒。", "遺音聞八曲，大小兩回傍。"]'),
('c24aead1-04d6-4388-90b0-896cdf485603','宿華容寺','王十朋','宋','宋诗','song-poetry','','[]','古剎何年有，傳聞貞觀初。',48,'全唐诗/poet.song.119000.json','["古剎何年有，傳聞貞觀初。", "藥痊明主疾，鼠福梵王廬。", "帝賜褒嘉禮，神留吉利書。", "殘僧三四輩，朝莫自鍾魚。"]'),
('7581e236-43f5-4e37-a4dd-ab6aa1463fe4','朝離華容莫宿孟橋小店甚陋得莫漕子蒙書以八百料船見借遂可鼓楫而西矣','王十朋','宋','宋诗','song-poetry','','[]','曉發華容寺，雲開鄂渚天。',48,'全唐诗/poet.song.119000.json','["曉發華容寺，雲開鄂渚天。", "秋深餘晚稻，地曠闢管田。", "草市魚多骨，荒村店有烟。", "計臺書報我，已具濟川船。"]'),
('0f87eb13-b2eb-4906-9e97-3ce8443c752a','至鄂渚泊報恩寺','王十朋','宋','宋诗','song-poetry','','[]','跋涉經江夏，悲凉忽莫秋。',48,'全唐诗/poet.song.119000.json','["跋涉經江夏，悲凉忽莫秋。", "雨登羅漢閣，醉上庾公樓。", "風急將吹帽，江寒更泛舟。", "川塗元不隔，歸夢到東甌。"]'),
('108b0861-e910-40bc-998a-70e5037fa242','題一覽亭','王十朋','宋','宋诗','song-poetry','','[]','危亭頂鄂渚，欲上初不敢。',168,'全唐诗/poet.song.119000.json','["危亭頂鄂渚，欲上初不敢。", "肩輿躡崢嶸，眼界驚坎窗。", "青山繚江湖，烟雨抹濃淡。", "千帆破滄浪，萬室昭菡萏。", "大澤匈可吞，秀色手宜攬。", "形勢控上游，天險卦侔坎。", "登臨迫吹帽，秋聲在葭菼。", "銜杯情有欣，懷古意多感。", "兩雄孫與劉，壯志鯨鵬噉。", "赤壁走阿瞞，功業炳鉛槧。", "黄鶴去何之，靈竹色猶慘。", "樓餘庾公興，洲遺正平憾。", "北望舊中原，激裂壯士膽。", "何由登太山，一快天下覽。"]'),
('dfbe4a15-7338-4755-90d5-fb1db0f8a3b9','莫漕以蓴羹薦杯','王十朋','宋','宋诗','song-poetry','','[]','蕭瑟秋風送雁回，夢魂終夜遶簫臺。',32,'全唐诗/poet.song.119000.json','["蕭瑟秋風送雁回，夢魂終夜遶簫臺。", "年家知我鄉心切，斫鱠羹蓴薦酒杯。"]'),
('f4cf2c8e-5662-4a74-bb21-ac4aa0655471','九日懷故鄉','王十朋','宋','宋诗','song-poetry','','[]','天涯行客倍傷悲，鄂渚登高帽欲吹。',32,'全唐诗/poet.song.119000.json','["天涯行客倍傷悲，鄂渚登高帽欲吹。", "遥想弟兄行處樂，幾人同把菊花枝。"]'),
('181a5593-e16d-4e3a-b847-b3c0e40bbc29','登壓雲亭贈趙都統','王十朋','宋','宋诗','song-poetry','','[]','早將忠義立殊勳，鄂渚登臨氣壓雲。',32,'全唐诗/poet.song.119000.json','["早將忠義立殊勳，鄂渚登臨氣壓雲。", "異日雲臺觀畫像，要須壓盡漢將軍。"]'),
('22422af1-436e-4f37-a74c-49ae783544ff','九日陪諸公登高','王十朋','宋','宋诗','song-poetry','','[]','鄂渚逢重九，登高客魂黯。',48,'全唐诗/poet.song.119000.json','["鄂渚逢重九，登高客魂黯。", "白菊泛壺觴，青山滿欄檻。", "詩隨眼界添，酒逐年華減。", "回頭望楚東，半雨花思范。"]'),
('6b2dacf1-f5c4-4ec7-9878-187dd1954820','十日解舟晚泊江口望鄂渚漢陽','王十朋','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','繫纜長江口，斜陽照兩州。',48,'全唐诗/poet.song.119000.json','["繫纜長江口，斜陽照兩州。", "山遥瞻大別，渚遠認南樓。", "漁艇家烟浦，江神廟柳洲。", "文通送別處，春恨可如秋。"]'),
('75d758ab-a945-4dac-8519-ad87443f571d','解纜南浦初泝長江江流出鄂渚漢陽兩山之間雲靄橫之如一山然','王十朋','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','解纜長江口，回頭思黯然。',48,'全唐诗/poet.song.119000.json','["解纜長江口，回頭思黯然。", "封疆一川隔，烟靄兩州連。", "水鳥飛沿渚，江豚躍傍船。", "好風知幾葦，送我上青天。"]'),
('12f81351-21b7-40a5-9ca8-64a0f93d6d2b','過金口市江中有渚名鯉魚甲渚上有蘆花連日遇逆風舟以寸進挽舟者行蘆中成四絕  其一','王十朋','宋','宋诗','song-poetry','','[]','江山滿眼似相迎，一鬨人烟問地名。',32,'全唐诗/poet.song.119000.json','["江山滿眼似相迎，一鬨人烟問地名。", "舟過已經金口市，水流應到石頭城。"]'),
('12507564-372a-4d8e-bdc8-d55a5578d63f','過金口市江中有渚名鯉魚甲渚上有蘆花連日遇逆風舟以寸進挽舟者行蘆中成四絕  其二','王十朋','宋','宋诗','song-poetry','','[]','鯉魚甲露江中渚，蘆荻花浮渚上霜。',32,'全唐诗/poet.song.119000.json','["鯉魚甲露江中渚，蘆荻花浮渚上霜。", "檣影落江疑是釣，巨鱗驚躍鷺飛忙。"]'),
('a2d20ab4-7d50-47ce-a645-a52e82af9542','過金口市江中有渚名鯉魚甲渚上有蘆花連日遇逆風舟以寸進挽舟者行蘆中成四絕  其三','王十朋','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江十里渺連空，逆水那堪更逆風。',32,'全唐诗/poet.song.119000.json','["長江十里渺連空，逆水那堪更逆風。", "定是江神憐遠去，欲吹船轉浙江東。"]'),
('f847e056-b03d-4bf3-a307-8470ec946cf1','過金口市江中有渚名鯉魚甲渚上有蘆花連日遇逆風舟以寸進挽舟者行蘆中成四絕  其四','王十朋','宋','宋诗','song-poetry','','[]','江神不借一帆風，急水難收寸進功。',32,'全唐诗/poet.song.119000.json','["江神不借一帆風，急水難收寸進功。", "欹枕高眠真有媿，挽舟人在荻花中。"]'),
('ac5cd0fe-5b0d-4429-8d1d-34b3429cc7b8','食蝦','王十朋','宋','宋诗','song-poetry','','[]','江上秋風起，鱸蓴正憶家。',24,'全唐诗/poet.song.119000.json','["江上秋風起，鱸蓴正憶家。", "舟行良不惡，日啖小魚蝦。"]'),
('a3abcc42-c107-4ee9-9609-61c2bcaae6fc','宿通濟口','王十朋','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','千里長江險，舟行夢亦驚。',48,'全唐诗/poet.song.119000.json','["千里長江險，舟行夢亦驚。", "轉磯憂浪急，入沌喜波平。", "秋老天猶燠，宵長月自明。", "洋洋通濟水，何日得歸程。"]'),
('ab84851d-52cb-4800-b050-bcb2fafb8907','蘆花  其一','王十朋','宋','宋诗','song-poetry','','[]','悲秋已過黄花節，照眼渾疑白帝城。',32,'全唐诗/poet.song.119000.json','["悲秋已過黄花節，照眼渾疑白帝城。", "更類吾家子猷棹，飄然乘興雪中行。"]'),
('fe86c7de-4a06-460d-9fcc-28c75268a6da','蘆花  其二','王十朋','宋','宋诗','song-poetry','','[]','蘆花兩岸風蕭瑟，渺渺烟波浸秋日。',32,'全唐诗/poet.song.119000.json','["蘆花兩岸風蕭瑟，渺渺烟波浸秋日。", "鷗鷺家深不見人，小舟忽自花中出。"]'),
('4803c1a1-2ae2-4f20-aa9a-1c6c6355eb7d','夜宿思湖口繫纜蘆葦間夜半聞叢中有聲舟人驚起終夕爲之不寐','王十朋','宋','宋诗','song-poetry','','[]','老境殘秋路入荆，眼中何物不關情。',64,'全唐诗/poet.song.119000.json','["老境殘秋路入荆，眼中何物不關情。", "蘆花間蓼紅依白，江水歸湖濁带清。", "狐兔叢深應自賀，魚龍穴淺已相驚。", "扁舟夜宿無人境，展轉無眠到五更。"]'),
('047e9c44-583b-4981-b698-d24c5c879db1','舟中作','王十朋','宋','宋诗','song-poetry','','[]','竟日舟行無一家，無邊眼界只蘆花。',32,'全唐诗/poet.song.119000.json','["竟日舟行無一家，無邊眼界只蘆花。", "花中知有雁多少，爲我傳書到永嘉。"]'),
('1fa29a72-3443-4a49-b7da-e2641e00d96b','漢水','王十朋','宋','宋诗','song-poetry','','[]','方城以爲城，漢水以爲池。',96,'全唐诗/poet.song.119000.json','["方城以爲城，漢水以爲池。", "橫行江漢間，楚子滅諸姬。", "問鼎輕周室，爭盟會淮夷。", "子孫世有國，地大先王時。", "封疆六千里，俛首爲秦雌。", "虎狼不可親，前後幾見欺。", "始墮張儀計，卒至王翦師。", "西風吹黄蘆，疑是騷人悲。"]'),
('7f57e2a1-2bca-4cb2-994f-8508801e89d7','宿夏郡口','王十朋','宋','宋诗','song-poetry','','[]','夜宿古夏口，時維季秋半。',84,'全唐诗/poet.song.119000.json','["夜宿古夏口，時維季秋半。", "江湖猶未落，烟水渺無岸。", "左公昔屯兵，仲謀方斫案。", "助成赤壁勝，坐使老賊竄。", "壯志寧下人，借地聊取亂。", "蛟龍得雲雨，鼎足王蜀漢。", "英雄不復見，江水空汗漫。"]'),
('4b4e356f-b783-4abb-971e-6aec647a8bbd','九月十五夜','王十朋','宋','宋诗','song-poetry','','[]','九月十五夜，前年居故鄉。',60,'全唐诗/poet.song.119000.json','["九月十五夜，前年居故鄉。", "雞黍修故事，兄弟自范張。", "豈知今年秋，扁舟葭葦傍。", "三日無人烟，雨細風悲凉。", "澆愁一杯酒，苦語生悲腸。"]'),
('cc239352-9b78-4185-8723-1a37d28858c3','宿高牙','王十朋','宋','宋诗','song-poetry','','[]','牢落楚天涯，夔門路尚賒。',48,'全唐诗/poet.song.119000.json','["牢落楚天涯，夔門路尚賒。", "落帆驚宿鷺，弭榜傍栖鴉。", "風伯聲喧枕，漁人水浸家。", "江神阻行色，非是戀高牙。"]'),
('d7995912-5f49-4294-a55d-47e544dac9de','亡姊之葬在九月而不得其日十五日讀坡詩至英公燎須事不覺悲涕是日辛酉得非葬日邪詩以寓哀','王十朋','宋','宋诗','song-poetry','','[]','先人六兒女，姊長孝且慈。',132,'全唐诗/poet.song.119000.json','["先人六兒女，姊長孝且慈。", "德淑命不淑，哀哉止於斯。", "莫年失愛子，哭泣鬢成絲。", "年纔五十七，一病不可醫。", "姊死我在傍，姊葬吾不知。", "初聞卜九月，不得日與時。", "丐祠既不遂，臨穴竟無期。", "日月爲我昏，風雨爲我悲。", "宦游何所得，抱恨渺無涯。", "尚餘英公須，未作子厚碑。", "便當回雁蕩，那忍過秭歸。"]'),
('f4973fb4-2688-4371-b823-6702ec9ecddd','買魚行','王十朋','宋','宋诗','song-poetry','','[]','風伯一怒聲如雷，排空濁浪山崔嵬。',246,'全唐诗/poet.song.119000.json','["風伯一怒聲如雷，排空濁浪山崔嵬。", "江湖千里人影絕，一葉小舟何處來。", "蘆荻花中有漁者，蓑笠爲衣楫爲馬。", "止將烟水作生涯，紅麴鹽魚荷裹鮓。", "舟人爭買不論錢，我亦聊將薦杯斝。", "烹庖入坐氣微腥，飣餖登盤色如赭。", "但能得趣酒杯中，也勝彈鋏人門下。", "君不見仲尼魚餒則不食，陳蔡面猶含菜色。", "又不見退之欲飽東海鯨，焉知家有啼饑聲。", "我居江鄉厭海味，今日魚蝦八珍貴。", "朱門日興費萬錢，未必一生常適意。", "爾曹異日宦西東，一飯安得如今同。", "寄鮓不須勞孟宗，但願清白傳家風。", "我將歸結雞豚社，不用擊鮮如陸賈。", "但願年豐魚米賤，欣然醉飽同天下。"]'),
('8a986a57-9cb1-48e0-91af-2a05e0a8f9af','過八疊有小舟賣蝦是日風便但江岸縈迂疾徐相半','王十朋','宋','宋诗','song-poetry','','[]','舟經八疊疾還徐，帆便風高水自迂。',32,'全唐诗/poet.song.119000.json','["舟經八疊疾還徐，帆便風高水自迂。", "要與麴生談妙理，試呼漁父買長須。"]'),
('7aa69053-9089-4a69-a7d6-267b59ffaf20','過三叉','王十朋','宋','宋诗','song-poetry','','[]','派別從金口，江行過玉沙。',48,'全唐诗/poet.song.119000.json','["派別從金口，江行過玉沙。", "風灣迂八疊，烟渚會三叉。", "柳老餘春色，尊空負月華。", "端如退之語，江遠共蒹葭。"]'),
('5f6cd421-1b7a-482c-a923-398bb34c6a60','泛泛江漢水','王十朋','宋','宋诗','song-poetry','','[]','鄂渚上荆州，泛泛江漢水。',48,'全唐诗/poet.song.119000.json','["鄂渚上荆州，泛泛江漢水。", "縈迂知幾曲，蕭瑟非一葦。", "鄉心秋色中，旅思詩篇裏。", "雲安在何處，落日天邊是。"]'),
('37c0cf56-c63f-488e-9e6c-e027efc1e7d0','宿網步時已入夜猶行舟忽聞犬聲知有人家孤燈一點蓋漁舍也是夕有月不飲','王十朋','宋','宋诗','song-poetry','','[]','網步知何處，維舟日已昏。',48,'全唐诗/poet.song.119000.json','["網步知何處，維舟日已昏。", "孤燈耿漁舍，一犬吠江村。", "問境欣名復，歸心幾到溫。", "遥天有明月，惜不照金尊。"]'),
('9a3e2a46-1608-46f7-8d26-336c6947704a','過畢家池有姓陳者送香橙八顆云有子在太學名景初有佛舍額曰永固院臨水而門閉有神祠云江南吳王廟必孫氏也  其一','王十朋','宋','宋诗','song-poetry','','[]','甕間吏部姓名池，僧舍人家傍水涯。',32,'全唐诗/poet.song.119000.json','["甕間吏部姓名池，僧舍人家傍水涯。", "黍熟稻香俱可飯，橙黄橘綠最宜詩。"]'),
('5fef8cd9-16d2-48b6-951b-e7004d68f89c','過畢家池有姓陳者送香橙八顆云有子在太學名景初有佛舍額曰永固院臨水而門閉有神祠云江南吳王廟必孫氏也  其二','王十朋','宋','宋诗','song-poetry','','[]','江上人知我姓名，枝頭手自摘香橙。',32,'全唐诗/poet.song.119000.json','["江上人知我姓名，枝頭手自摘香橙。", "一盤來致殷勤意，儂有兒爲太學生。"]'),
('da6cd818-8e22-4f8d-8171-2e14cdd779d6','過畢家池有姓陳者送香橙八顆云有子在太學名景初有佛舍額曰永固院臨水而門閉有神祠云江南吳王廟必孫氏也  其三','王十朋','宋','宋诗','song-poetry','','[]','江東英傑舊孫郎，遺烈于今尚未忘。',32,'全唐诗/poet.song.119000.json','["江東英傑舊孫郎，遺烈于今尚未忘。", "猶有神祠枕流水，一間茅屋似昭王。"]'),
('888b4c48-1994-490e-b475-068b9c39838a','晚過沙灘有漁舉網得鯿魚二百餘頭橙橘正青黄以百錢買橘得十六顆比鄉里小差而味酸  其一','王十朋','宋','宋诗','song-poetry','','[]','漁人生計占沙洲，一網鯿魚二百頭。',32,'全唐诗/poet.song.119000.json','["漁人生計占沙洲，一網鯿魚二百頭。", "魚未到家人買盡，明朝一網更盈舟。"]'),
('1d0611f4-88b4-4722-9927-d5ba8f0ca5af','晚過沙灘有漁舉網得鯿魚二百餘頭橙橘正青黄以百錢買橘得十六顆比鄉里小差而味酸  其二','王十朋','宋','宋诗','song-poetry','','[]','地近荆州見木奴，青黄照眼兩三株。',32,'全唐诗/poet.song.119000.json','["地近荆州見木奴，青黄照眼兩三株。", "百錢買得霜前顆，味带儒酸似老夫。"]'),
('84412335-d561-4923-b1b8-5bd5890bdb81','晚過沙灘有漁舉網得鯿魚二百餘頭橙橘正青黄以百錢買橘得十六顆比鄉里小差而味酸  其三','王十朋','宋','宋诗','song-poetry','','[]','晚來諸卒競歡呼，糴得香粳一斗餘。',32,'全唐诗/poet.song.119000.json','["晚來諸卒競歡呼，糴得香粳一斗餘。", "拾荻爲薪煮江水，就船沽酒喫鯿魚。"]'),
('ad9da63a-be5f-45ce-b06f-10c6d635edcb','舟中懷鄱陽趙倅及諸同官用九日登高韵','王十朋','宋','宋诗','song-poetry','','[]','君如別駕寵，我媿淮陽黯。',48,'全唐诗/poet.song.119000.json','["君如別駕寵，我媿淮陽黯。", "鄱水偶同僚，江樓屢憑檻。", "感秋悲思多，惜別剛腸減。", "夔門嘯與諾，安得對岑范。"]'),
('1f817b34-c8f2-4d43-a280-dbf0f0ccd1fb','宿紫微','王十朋','宋','宋诗','song-poetry','','[]','高柳何人舍，孤燈此夜舟。',24,'全唐诗/poet.song.119000.json','["高柳何人舍，孤燈此夜舟。", "遥從白帝去，少爲紫微留。"]'),
('27ed090c-76ae-4d98-aa55-018f357ab963','二十一日至福田院留建聖節  其一','王十朋','宋','宋诗','song-poetry','','[]','魏闕回頭遠，夔門去路長。',24,'全唐诗/poet.song.119000.json','["魏闕回頭遠，夔門去路長。", "萬年天子壽，一瓣福田香。"]'),
('600e416f-dc06-4c19-9821-c3161ef85de7','二十一日至福田院留建聖節  其二','王十朋','宋','宋诗','song-poetry','','[]','小院藏脩竹，柴門傍曲江。',24,'全唐诗/poet.song.119000.json','["小院藏脩竹，柴門傍曲江。", "繫舟楊柳岸，詩句落僧窗。"]'),
('290c33cf-5eca-4699-99cf-3df7383bdf9a','宿金雞渡','王十朋','宋','宋诗','song-poetry','','[]','曉起雞未鳴，晚宿雞鳴渡。',48,'全唐诗/poet.song.119000.json','["曉起雞未鳴，晚宿雞鳴渡。", "雞鳴又還起，扁舟觸烟霧。", "不作田文奔，不效劉琨舞。", "孜孜慕舜徒，去去官夔府。"]'),
('b143f0cb-d857-411a-8bd8-a9489cd67329','宿王家村  其一','王十朋','宋','宋诗','song-poetry','','[]','舟行湖北路千里，家在浙東天一涯。',32,'全唐诗/poet.song.119000.json','["舟行湖北路千里，家在浙東天一涯。", "宿處問名同住處，梅花不見見蘆花。"]'),
('ca786e0b-e870-4769-bd57-3e2af21f0cb8','宿王家村  其二','王十朋','宋','宋诗','song-poetry','','[]','扁舟何日到夔州，已泛荆湖半月船。',32,'全唐诗/poet.song.119000.json','["扁舟何日到夔州，已泛荆湖半月船。", "誤喜地名同故里，欲尋鄰舍竟茫然。"]'),
('9a752cc7-5445-425a-8c35-9c6209ee7b40','宿王家村  其三','王十朋','宋','宋诗','song-poetry','','[]','王家又向此名村，只欠青山似左原。',32,'全唐诗/poet.song.119000.json','["王家又向此名村，只欠青山似左原。", "滿眼黄茅仍白葦，荒蕪疑是我田園。"]'),
('13239993-3765-4a55-bcd2-cc941d48bc14','讀楚東倡酬集寄洪景盧王嘉叟','王十朋','宋','宋诗','song-poetry','','[]','預恐吾儕有別離，急忙刊得倡酬詩。',32,'全唐诗/poet.song.119000.json','["預恐吾儕有別離，急忙刊得倡酬詩。", "江東渭北何曾隔，開卷無非見面時。"]'),
('99d15c16-68ac-4fdc-9eec-6079cb62bcb1','寄題鄱陽一江亭','王十朋','宋','宋诗','song-poetry','','[]','一江明月夜歸遲，蕭洒齋中小范詩。',32,'全唐诗/poet.song.119000.json','["一江明月夜歸遲，蕭洒齋中小范詩。", "亭自我名猶未賞，夢游江靜月明時。"]'),
('906829e5-67d4-4533-bfa8-ef48d56ea764','早至魯家洑復入大江見石首山','王十朋','宋','宋诗','song-poetry','','[]','入由通濟口，出自魯家洑。',48,'全唐诗/poet.song.119000.json','["入由通濟口，出自魯家洑。", "半月良已勞，大江離又復。", "濛濛烟雨中，兩岸漁人屋。", "遥山瞻石首，鄉味思海族。"]'),
('3dcc398b-7ac0-4c96-b894-0d2c3f5c04b2','舟中記所見','王十朋','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','不向三苗境上過，此身端怯洞庭波。',64,'全唐诗/poet.song.119000.json','["不向三苗境上過，此身端怯洞庭波。", "浪翁未免敖牙戲，漁父時爲欵乃歌。", "蟲喜年豐頻擣米，鳥憂沙漲自淘河。", "可無好處如鄉里，橘綠橙黄恨不多。"]'),
('2fc95601-8715-45ba-9da2-f4ccf5c03617','二十五日先妣遠忌祭于舟中','王十朋','宋','宋诗','song-poetry','','[]','有遺嗟無母，舟中遇忌辰。',48,'全唐诗/poet.song.119000.json','["有遺嗟無母，舟中遇忌辰。", "魚蔬當血食，橙橘薦時新。", "家比去年遠，囊如舊日貧。", "白巖山下冢，歸掃擬新春。"]'),
('cb1d54d7-20fe-4cf9-88eb-8ca45f73c924','夜宿下沙步有小浦藏舟于口懼有風也是夜浪忽作聲如潮舟爲之撼如是者三舟人驚懼初謂有風起視則天籟不號星月皎然篙工云江中畏炮炙鄰舟有煎油者岸圮而浪生曉視之果有圮處或云黿鼉之屬因記之','王十朋','宋','宋诗','song-poetry','','[]','疑向錢塘宿，潮頭夜半聲。',48,'全唐诗/poet.song.119000.json','["疑向錢塘宿，潮頭夜半聲。", "油煎江岸圮，舟撼夢魂驚。", "浪自黿鼉吐，風從蘆葦生。", "江神不遷怒，頃刻爲吾平。"]'),
('da288f21-b7f7-4816-a2a8-af1b9b579c48','天晴風順舟行過石首縣宿劉郎洑','王十朋','宋','宋诗','song-poetry','','[]','殘月照荆江，晨曦浴暘谷。',84,'全唐诗/poet.song.119000.json','["殘月照荆江，晨曦浴暘谷。", "雲收瘦山腰，風順飽帆腹。", "微茫見石首，俄頃過吾目。", "方茲驚洶湧，何敢求迅速。", "快意固可喜，遲鈍或爲福。", "風乎亦難矣，去順來者讟。", "江神豈世情，吾亦不私祝。"]'),
('066da7a6-64f2-4cca-99af-1d2fb953172b','予自鄂渚登舟近兩旬得順風纔二日耳高牙遇風雨留兩日既而得順風過八疊江流迂曲疾徐相半二十六日風駛甚方快之謂公安可一日到也明日如故江與風背浪洶涌停舟不行復用前韵','王十朋','宋','宋诗','song-poetry','','[]','我欲效元子，漫浪居退谷。',84,'全唐诗/poet.song.119000.json','["我欲效元子，漫浪居退谷。", "不效楚大夫，醒清葬魚腹。", "前非戀高牙，今豈嗜湖目。", "兩旬非不遲，一日靡容速。", "直爲退之規，寧覬塞翁福。", "未易論乘除，不須生怨讟。", "江水照吾心，宜將正辭祝。"]'),
('53039407-2869-4c70-b3e2-c02b0ebe9c1a','再讀楚東集用前韵寄景盧嘉叟','王十朋','宋','宋诗','song-poetry','','[]','二子聰明曠與離，一尊容我與論詩。',32,'全唐诗/poet.song.119000.json','["二子聰明曠與離，一尊容我與論詩。", "待將後集從前刻，直到鄱陽送別時。"]'),
('970c02c6-5658-4cad-915b-13ccdb9b10ce','寇萊公祠','王十朋','宋','宋诗','song-poetry','','[]','油水江頭寇相祠，凜然如坐廟堂時。',32,'全唐诗/poet.song.119000.json','["油水江頭寇相祠，凜然如坐廟堂時。", "精忠一點不負國，枯竹知公人不知。"]'),
('93def76d-3f1b-4339-a6f9-545d3eebe9ff','宿黄壇','王十朋','宋','宋诗','song-poetry','','[]','江口維舟問地名，黯然撩我故鄉情。',32,'全唐诗/poet.song.119000.json','["江口維舟問地名，黯然撩我故鄉情。", "平時尚怯黄壇嶺，誰遣遥臨白帝城。"]'),
('e9674bce-327c-4f30-b6c2-6c01e45df927','讀于公堂記寄孫錄聰伯','王十朋','宋','宋诗','song-poetry','','[]','于公治獄多陰德，溫靖居朝止肉刑。',32,'全唐诗/poet.song.119000.json','["于公治獄多陰德，溫靖居朝止肉刑。", "鄱水同僚溫靖後，于公堂記有芬馨。"]'),
('0aa8ac1c-365a-4c57-8946-2f97cd7aeecd','十月四日宿于沙市舟中捲簾忽見新月天色如水鄉思凄然得詩一聯云詩成天作紙簾捲月爲鈎連夕燭有花至六日家書來自臨安足成一篇寄二弟','王十朋','宋','宋诗','song-poetry','','[]','今夕果何夕，章華臺畔舟。',48,'全唐诗/poet.song.119000.json','["今夕果何夕，章華臺畔舟。", "詩成天作紙，簾捲月爲鈎。", "蠟炬知何喜，鄉心未免憂。", "家書隨雁足，兩月到荆州。"]'),
('ef2803eb-ac75-4881-b63f-0ab140cb4cc3','初九日離南用夔州船','王十朋','宋','宋诗','song-poetry','','[]','扁舟經月泝江流，又向江陵換蜀舟。',32,'全唐诗/poet.song.119000.json','["扁舟經月泝江流，又向江陵換蜀舟。", "腸斷一聲離岸櫓，不堪回首仲宣樓。"]'),
('2679f27d-3df8-4147-80a0-6282770f1048','過虎牙','王十朋','宋','宋诗','song-poetry','','[]','天遣西來亦大奇，眼中渾是少陵詩。',32,'全唐诗/poet.song.119000.json','["天遣西來亦大奇，眼中渾是少陵詩。", "虎牙銅柱爲我好，却勝先生出峽時。"]'),
('acefb474-b46c-4501-8f96-8fd560d7fec5','至峽州登至喜亭謁歐公祠','王十朋','宋','宋诗','song-poetry','','[]','曾於慶朔親祠范，又向夷陵敬拜歐。',32,'全唐诗/poet.song.119000.json','["曾於慶朔親祠范，又向夷陵敬拜歐。", "昔日四賢今見兩，慨然遐想舊風流。"]'),
('932b52b8-66b2-4dfd-8a65-f68daf6c838d','爾雅臺','王十朋','宋','宋诗','song-poetry','','[]','隠迹江山郭景純，學兼儒伎術通神。',32,'全唐诗/poet.song.119000.json','["隠迹江山郭景純，學兼儒伎術通神。", "蟲魚草木歸箋注，何害其爲磊落人。"]'),
('7d752d08-fbf3-484c-8b4d-65ce750168fc','楚塞樓','王十朋','宋','宋诗','song-poetry','','[]','楚國封疆六千里，荆門巖巒十二背。',96,'全唐诗/poet.song.119000.json','["楚國封疆六千里，荆門巖巒十二背。", "南標銅柱北虎牙，天險城邊古西塞。", "江山如故名尚存，形勢雖强國何在。", "水流三峽無古今，月照孤城幾興廢。", "吳蜀英雄空戰爭，屈宋風騷謾悲慨。", "但願時清塞不塵，樓上芳尊日相對。"]'),
('826fdcf9-7fe1-4ee8-977f-daf127b7200f','離夷陵移舟至水西將遵陸霧甚咫尺不辨舟人失津退數里遇渡船引而至岸有山在蒙籠中乃觀音臺也過姜詩村飯士門鋪晚宿油榨有山名四面頗佳','王十朋','宋','宋诗','song-poetry','','[]','至喜亭前曉霧迷，櫓聲離岸眩東西。',64,'全唐诗/poet.song.119000.json','["至喜亭前曉霧迷，櫓聲離岸眩東西。", "疑游神女行雲峽，忽到姜詩躍鯉溪。", "午飯驛亭同蓐食，夜眠村店類雞栖。", "眼中四面青山好，從此登天路不低。"]'),
('ac22d9c6-25d2-4f5b-a0be-1994c78d5c81','飯桃花鋪宿覆盆  其一','王十朋','宋','宋诗','song-poetry','','[]','路入桃花桃未花，碧溪流水兩三家。',32,'全唐诗/poet.song.119000.json','["路入桃花桃未花，碧溪流水兩三家。", "何年路接人間世，定是漁人歸去誇。"]'),
('369a96ad-f0a6-474e-b7c3-1d9c96b26d2e','飯桃花鋪宿覆盆  其二','王十朋','宋','宋诗','song-poetry','','[]','身在籃輿不自安，更勞牽挽上天門。',32,'全唐诗/poet.song.119000.json','["身在籃輿不自安，更勞牽挽上天門。", "山中亦有人間月，今夜應須照覆盆。"]'),
('613eb273-89ce-4dcb-b06a-90568e808d27','上大望州鑽天三里  其一','王十朋','宋','宋诗','song-poetry','','[]','身到猿啼百尺頭，更言前有鶻孫愁。',32,'全唐诗/poet.song.119000.json','["身到猿啼百尺頭，更言前有鶻孫愁。", "試於大望山頭望，望見人間是峽州。"]'),
('a436fb4d-fee9-4380-8b64-c2b6c05e55f1','上大望州鑽天三里  其二','王十朋','宋','宋诗','song-poetry','','[]','豆子山前火墨溪，迢迢一嶺與天齊。',32,'全唐诗/poet.song.119000.json','["豆子山前火墨溪，迢迢一嶺與天齊。", "肉身安得鑽天手，肝膽崔嵬自作梯。"]'),
('cd86167e-5e44-4f66-976c-36b5bc5bcf3e','宿千石聞誦書聲','王十朋','宋','宋诗','song-poetry','','[]','一嶺鑽天到此平，夜眠聽得誦書聲。',32,'全唐诗/poet.song.119000.json','["一嶺鑽天到此平，夜眠聽得誦書聲。", "莫言此地名千石，萬石它年或可名。"]'),
('a9ce6cff-498f-4b26-8e1e-7156d1f5b1e9','枕上聞鼓角','王十朋','宋','宋诗','song-poetry','','[]','五更枕上夢還醒，初聽夔州鼓角聲。',32,'全唐诗/poet.song.119000.json','["五更枕上夢還醒，初聽夔州鼓角聲。", "悲壯端如少陵語，它時送我更多情。"]'),
('585bdda4-66ac-4382-97ac-e3570f348780','過九盤嶺','王十朋','宋','宋诗','song-poetry','','[]','水不經三峽，山猶過九盤。',24,'全唐诗/poet.song.119000.json','["水不經三峽，山猶過九盤。", "數家修竹裏，堪入畫圖看。"]'),
('2d723bcc-58d0-4c3b-9ffd-52c385520fec','飯周平鋪南北山峰巒皆奇有佛頂峰鯉魚巖羅漢洞說者謂類巫山遇雨爲雲霧所蔽不盡見','王十朋','宋','宋诗','song-poetry','','[]','未見巫山十二峯，人言山與此山同。',32,'全唐诗/poet.song.119000.json','["未見巫山十二峯，人言山與此山同。", "定知神女藏深處，正在朝雲莫雨中。"]'),
('93ade336-6552-4b3f-a806-7698494348eb','至歸州宿報恩寺','王十朋','宋','宋诗','song-poetry','','[]','終夜江聲枕上喧，子規未叫已銷魂。',64,'全唐诗/poet.song.119000.json','["終夜江聲枕上喧，子規未叫已銷魂。", "身乘篳路思熊繹，詞誦離騷弔屈原。", "城邑舊爲夔子國，民人多是楚王孫。", "誤恩分閫方圖報，宿處那堪是報恩。"]'),
('cdcead3b-f26b-4934-a05f-bdbc66aa3b2d','題屈原廟','王十朋','宋','宋诗','song-poetry','','[]','自古皆有死，先生死忠清。',48,'全唐诗/poet.song.119000.json','["自古皆有死，先生死忠清。", "故宅秭歸江，前山熊繹城。", "眷言懷此都，不比異姓卿。", "六經變離騷，日月爭光明。"]'),
('1825bf68-6276-4ab7-99c5-692d20d96a7e','過秭歸','王十朋','宋','宋诗','song-poetry','','[]','晚日寒天過秭歸，江山點點上愁眉。',32,'全唐诗/poet.song.119000.json','["晚日寒天過秭歸，江山點點上愁眉。", "况經宋玉悲秋處，不獨秋悲冬亦悲。"]'),
('34d52691-50c2-4c81-9837-cb9cc7cc8715','二十四日視帥印于歸大拽鋪','王十朋','宋','宋诗','song-poetry','','[]','大拽名何壯，孤峯勢更巍。',48,'全唐诗/poet.song.119000.json','["大拽名何壯，孤峯勢更巍。", "拜恩羅吏卒，列炬照烟霏。", "分閫來魚復，懷鄉過秭歸。", "石門觀峽水，東注疾如飛。"]'),
('1b99ef73-9280-40ae-9ca6-ace022438bb7','宿巴東縣懷寇忠愍  其一','王十朋','宋','宋诗','song-poetry','','[]','製錦工夫早不同，至今人道寇巴東。',32,'全唐诗/poet.song.119000.json','["製錦工夫早不同，至今人道寇巴東。", "澶淵一段奇功業，可在孤舟野水中。"]'),
('27c95890-dd26-4f75-b3a0-30be21ea028e','宿巴東縣懷寇忠愍  其二','王十朋','宋','宋诗','song-poetry','','[]','堂前雙柏今何在，渡口孤舟依舊橫。',32,'全唐诗/poet.song.119000.json','["堂前雙柏今何在，渡口孤舟依舊橫。", "不似公安挿竹處，凜然容貌尚如生。"]'),
('f28b4169-e6a2-4f54-a7d0-aac1850bf8d1','初入巫山界登羅護關雲霧晦冥默禱之因成一絕','王十朋','宋','宋诗','song-poetry','','[]','西來水陸備艱辛，祇爲君恩不爲身。',32,'全唐诗/poet.song.119000.json','["西來水陸備艱辛，祇爲君恩不爲身。", "爲向巫山神女道，莫將雲霧惱行人。"]'),
('bebed94f-4d73-4b98-8230-b2e2d45d7329','霧開復成一絕','王十朋','宋','宋诗','song-poetry','','[]','關登羅護飯郵亭，雲霧迷人晝晦冥。',32,'全唐诗/poet.song.119000.json','["關登羅護飯郵亭，雲霧迷人晝晦冥。", "神女有靈呼即應，廓然山色爲吾青。"]'),
('9b1525a6-a876-4f93-82af-4dee678c307a','登得勝崗謁武安王關雲長廟有泉一泓俗傳謂兵至此無水拔刀刺地泉隨而湧廟西有磨刀溪北有曬甲崖','王十朋','宋','宋诗','song-poetry','','[]','得勝名崗蜀虎臣，氣吞吳魏失防身。',32,'全唐诗/poet.song.119000.json','["得勝名崗蜀虎臣，氣吞吳魏失防身。", "磨刀曬甲遺蹤在，英魄猶能敵萬人。"]'),
('5031f6ed-ab45-47f6-8c1f-bbb93829c8d8','過風口望巫峽巖嶂如雁山祥雲峯經行峽烟霞障','王十朋','宋','宋诗','song-poetry','','[]','十二巫山鎖白雲，巖如雁蕩列江濱。',32,'全唐诗/poet.song.119000.json','["十二巫山鎖白雲，巖如雁蕩列江濱。", "誰名雁蕩經行峽，定是經行峽裏人。"]'),
('af0cafe3-7ee3-4b73-bf9a-f8bbbddc16f4','登燕子坡前有一巖在江之旁如天台赤城名烏飛巖','王十朋','宋','宋诗','song-poetry','','[]','坡名燕子燕思歸，巖號烏飛烏倦飛。',32,'全唐诗/poet.song.119000.json','["坡名燕子燕思歸，巖號烏飛烏倦飛。", "雲本無心聊出岫，風緣有口故吹衣。"]'),
('dcc7410d-bb23-4593-a673-fd031badcc61','巴東之西近江有夫子洞亦曰聖洞巫山縣有孔子泉說者謂旱而祈則應泉旁之民雖童子皆能書夫子胡爲洞於此且有泉耶詩以辨之','王十朋','宋','宋诗','song-poetry','','[]','夫子道不行，嘗欲居九夷。',192,'全唐诗/poet.song.119000.json','["夫子道不行，嘗欲居九夷。", "乘桴浮於海，從者其爲誰。", "歷聘嘗之荆，豈亦游坤維。", "有洞巴峽間，人言幽更奇。", "雲深不可見，奧處那容窺。", "聖人肯巢仙，茲名良可疑。", "吾道其非耶，聊將友鹿麋。", "巫山亦有泉，可飲仍可祈。", "泉旁都幾家，聰慧多奇兒。", "父兄儻知教，聖門皆可歸。", "我來不及飲，清興隨泉飛。", "寧比盜與貪，聞名使人嗤。", "禹穴會稽陰，堯山番江湄。", "流傳雖失真，未敢以爲非。", "魯人輕東家，秦人燔書詩。", "茲俗聖夫子，吾何敢夷之。"]'),
('86f75447-032f-4386-90c5-77f151a118c1','自鄂渚至夔府途中記所見一百十韻','王十朋','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','流火郡離饒，悠悠驛路迢。',288,'全唐诗/poet.song.119000.json','["流火郡離饒，悠悠驛路迢。", "黄華舟解鄂，渺渺大江遥。", "肩弛鄱人檐，身隨楚客橈。", "東甌鄉夢遠，南浦別魂銷。", "不過漢陽壘，猶勞郡守軺。", "遠山看八字，古國避三苗。", "別水由通濟，羈帆渡泬漻。", "方隨鷗浩蕩，俄值雨飄颻。", "夾岸華疑雪，舂天浪似潮。", "枝栖並烏鵲，苕宿伴鷦鷯。", "旅思憑詩遣，愁腸頼酒澆。", "無魚不彈鋏，忘味若聞韶。", "孺子滄浪曲，漁人欵乃謠。", "逃虛音可喜，得雋語同囂。", "秋老江經夏，湖平境過宵。", "夜鳴疑有虎，昏吠喜聞獢。", "遺俗懷吳主，荒祠類楚昭。", "巨鱗烹縮項，白粲糴長腰。", "茅舍橘初熟，江村楓未凋。", "柳枝猶楚楚，竹淚尚思姚。", "雨後禾收晚，霜前麥見蕎。", "風清玉沙界，月吐紫微霄。", "一瓣香聞佛，千齡壽祝堯。", "沱潛終共道，江漢訖同朝。"]'),
('37807c9c-a4c5-47d5-bea6-747fd8524484','初到夔州','王十朋','宋','宋诗','song-poetry','','[]','分甘易守不勞麾，夢已先予到古夔。',32,'全唐诗/poet.song.119000.json','["分甘易守不勞麾，夢已先予到古夔。", "讖語端符楚東韵，忠懷雅合杜陵詩。"]'),
('715a8f3f-aeb6-4290-b4ee-d795df940f50','查漕元章生日','王十朋','宋','宋诗','song-poetry','','[]','氣壓群陰首占陽，生賢時節自非常。',64,'全唐诗/poet.song.119000.json','["氣壓群陰首占陽，生賢時節自非常。", "十分天上月輪滿，一線人間日影長。", "攬轡威名崖雪凜，和羹消息嶺梅香。", "要知三峽無窮水，便是詞源與壽觴。"]'),
('3e48b087-7b4c-425a-aa65-f2a14b10efd5','周漕行可和詩復用前韵并簡元章','王十朋','宋','宋诗','song-poetry','','[]','重聞鳴鳳瑞岐陽，不比清齋老太常。',64,'全唐诗/poet.song.119000.json','["重聞鳴鳳瑞岐陽，不比清齋老太常。", "帝里別離頭併白，夔門邂逅日初長。", "詩篇照眼騰光艷，蘭友傾心藹國香。", "天遣西來端有意，要令我輩共壺觴。"]'),
('738c776a-1b33-4c4d-9352-b3bd49cd76a0','又用行可韵','王十朋','宋','宋诗','song-poetry','','[]','二公海內姓名聞，我亦追隨到蜀門。',64,'全唐诗/poet.song.119000.json','["二公海內姓名聞，我亦追隨到蜀門。", "龍卧廬中嘆諸葛，蛙居坎底陋公孫。", "雨聽巫峽夢時滴，花看杜鵑啼處痕。", "酬唱又成夔府集，論文欣對少陵尊。"]'),
('a49282c0-1117-4239-b714-120b0a9697c3','行可再和用其韵以酬','王十朋','宋','宋诗','song-poetry','','[]','孤陋書生寬見聞，西來端欲掃儒門。',64,'全唐诗/poet.song.119000.json','["孤陋書生寬見聞，西來端欲掃儒門。", "懷人久作周公夢，訪道欣聞孔子孫。", "書爲愛民成再奏，淚因憂國有雙痕。", "休論身世無窮事，但願常陪北海尊。"]'),
('8318aed2-1ace-40df-89c4-2ed492011392','又酬元章','王十朋','宋','宋诗','song-poetry','','[]','叱馭西來媿子陽，舊交重見白眉常。',64,'全唐诗/poet.song.119000.json','["叱馭西來媿子陽，舊交重見白眉常。", "傷心鬼錄人何短，回首蓬山話更長。", "夔府並游容倚玉，計臺高選輟含香。", "我非逸少君如謝，聊繼蘭亭曲水觴。"]'),
('a17180a1-e66d-4f94-8285-58fdd4947479','行可元章再賦二詩依韵以酬前篇寓二後篇寓三  其一','王十朋','宋','宋诗','song-poetry','','[]','不學金仙李伯陽，來從雄愈論天常。',64,'全唐诗/poet.song.119000.json','["不學金仙李伯陽，來從雄愈論天常。", "毫鋒落紙一臺妙，詩艷驚人萬丈長。", "會見鵾鵬俱變化，稔聞蘭菊各芬香。", "盍簪聯席論文酒，却笑淵明獨引觴。"]'),
('3207c195-f296-473b-b104-5335afaaeb89','行可元章再賦二詩依韵以酬前篇寓二後篇寓三  其二','王十朋','宋','宋诗','song-poetry','','[]','朋得西南直諒聞，同行宜入仲尼門。',64,'全唐诗/poet.song.119000.json','["朋得西南直諒聞，同行宜入仲尼門。", "交成一體慕龍友，政在諸家嗤魯孫。", "雪唱紛紜臘天瑞，詞源洶涌峽江痕。", "二公如月如太白，我亦影隨同一尊。"]'),
('f029e10e-0c62-4961-a1fd-b11cab8b8daa','元章贈餘甘子用前韵','王十朋','宋','宋诗','song-poetry','','[]','草稟南方地近陽，不隨凡果當家常。',64,'全唐诗/poet.song.119000.json','["草稟南方地近陽，不隨凡果當家常。", "端因坡句聲名重，正類梅詩氣韵長。", "回頰已輸崖蜜味，返魂終共雪芽香。", "故人知我詩腸苦，更贈蒲萄爲薦觴。"]'),
('d50c51c7-6796-4e7d-8fdd-a2db7826c028','行可骨肉自西州來用門字韵贊喜','王十朋','宋','宋诗','song-poetry','','[]','連夕西臺笑語聞，綵衣人戲綉衣門。',64,'全唐诗/poet.song.119000.json','["連夕西臺笑語聞，綵衣人戲綉衣門。", "定知情話同元亮，不用詩篇寄抱孫。", "果見燈花將喜事，寧愁江竹染啼痕。", "登堂濫作韓公客，白首相逢十載尊。"]'),
('a4d52f3d-cd38-49e9-a3f7-06635ea7282b','吳參議和詩用前韵以酬','王十朋','宋','宋诗','song-poetry','','[]','萬頃波瀾瑩岳陽，氣鍾人物亦非常。',64,'全唐诗/poet.song.119000.json','["萬頃波瀾瑩岳陽，氣鍾人物亦非常。", "爲郎堪嘆馮唐老，治郡未施黄霸長。", "詩吐錦腸多麗句，品高蓮幕有清香。", "穆生醴酒周璆榻，不是區區爲奉腸。"]'),
('39619f04-8617-4fd2-bb73-63448df3e353','聞馬綱復行舊路聖主之恩諸公奏議之力也元章用前韵喜而和之','王十朋','宋','宋诗','song-poetry','','[]','利博仁言亟奏聞，恩光萬里燭夔門。',64,'全唐诗/poet.song.119000.json','["利博仁言亟奏聞，恩光萬里燭夔門。", "綱船已免□□□，棧道不應愁鶻孫。", "村落烟餘烟火□，□□□息斧斤痕。", "坐看巴蜀回生意，放我歡呼到酒尊。"]'),
('8a747ffd-46e0-419c-a6c8-e28dd3d36950','州縣有戒石飭官吏某至夔之初□□□□□詩以自警云','王十朋','宋','宋诗','song-poetry','','[]','爾俸爾祿民膏脂，下民易虐天難欺。',144,'全唐诗/poet.song.119000.json','["爾俸爾祿民膏脂，下民易虐天難欺。", "聖訓昭昭日月垂，刻石于庭勵官師。", "臣庭堅字尤瓌奇，光堯宸翰增光輝。", "坤維門戶州名夔，庭前戒石□□□。", "筆畫微茫觀者疑，太歲在酉嘉平時。", "吉日丁亥刑□□，命工舉石少高之。", "一新欄檻嚴謢持，銀鈎照眼光陸離。", "天威咫尺顔不違，虐民之事焉可爲。", "勿謂蒼蒼不吾知，與爾同僚共孜孜。"]'),
('7fc17def-2188-46b8-b6b8-07660280a7cf','出郊送虞參政因游竹亭小飲與者九人','王十朋','宋','宋诗','song-poetry','','[]','送客出西郊，天氣爲我佳。',48,'全唐诗/poet.song.119000.json','["送客出西郊，天氣爲我佳。", "穿林看修竹，偶與群賢偕。", "邂逅適我願，三杯寫幽懷。", "向來濤與戎，此樂何繇諧。"]'),
('0a2ad3ea-37d2-46c3-9e61-7105ae9729a6','立春','王十朋','宋','宋诗','song-poetry','','[]','巫峽逢生日，夔州見立春。',24,'全唐诗/poet.song.119000.json','["巫峽逢生日，夔州見立春。", "行年五十五，羞作戴花人。"]'),
('25354fd3-82e9-4559-ad3f-1712164d7935','寄劉侍郎韶美','王十朋','宋','宋诗','song-poetry','','[]','流落天涯老病身，歸心一點逐新春。',32,'全唐诗/poet.song.119000.json','["流落天涯老病身，歸心一點逐新春。", "故人少借論思口，放我山林作散人。"]'),
('38ff852b-77e8-431b-82ad-38c5bb9edec8','正月六日游磧呈行可元章','王十朋','宋','宋诗','song-poetry','','[]','踏磧逢爲馬，臨流想卧龍。',48,'全唐诗/poet.song.119000.json','["踏磧逢爲馬，臨流想卧龍。", "江山供指顧，尊俎奉從容。", "峽水淺還漲，巫雲淡復濃。", "天教我輩合，莫惜罄金鍾。"]'),
('57fd46ac-6195-4c98-a839-8fab5db39440','呈同官','王十朋','宋','宋诗','song-poetry','','[]','樽前記得少陵詩，好向江頭盡醉歸。',64,'全唐诗/poet.song.119000.json','["樽前記得少陵詩，好向江頭盡醉歸。", "此日風光真可惜，古來樂事巧相違。", "細看八陣圖猶在，欲問三分迹已非。", "惟有年年古夔國，竹枝聲裏日暉暉。"]'),
('bb949012-b005-4db2-a052-e920671febf9','買山','王十朋','宋','宋诗','song-poetry','','[]','書生爲郡亦迂哉，剩買童山買木栽。',32,'全唐诗/poet.song.119000.json','["書生爲郡亦迂哉，剩買童山買木栽。", "但遣牛羊勿踐履，它年定出棟梁材。"]'),
('cfc3f062-827a-4a1d-9c45-6f399b850282','給水','王十朋','宋','宋诗','song-poetry','','[]','接筒引水下山陬，端爲夔民解百憂。',32,'全唐诗/poet.song.119000.json','["接筒引水下山陬，端爲夔民解百憂。", "長使義泉名不斷，莫教人費一錢求。"]'),
('0ada8407-3e95-474b-a45e-78cd2ec1e663','修壘','王十朋','宋','宋诗','song-poetry','','[]','莫將逆旅視居官，宜作吾家活計看。',32,'全唐诗/poet.song.119000.json','["莫將逆旅視居官，宜作吾家活計看。", "牆壁時時爲修葺，安知勞苦是平安。"]'),
('a6a57d94-d101-447e-928d-077953bab9e2','種柳','王十朋','宋','宋诗','song-poetry','','[]','瀼水東西十里餘，新栽楊柳二千株。',32,'全唐诗/poet.song.119000.json','["瀼水東西十里餘，新栽楊柳二千株。", "會看聳幹參天去，能似甘棠勿翦無。"]'),
('15540f7f-0960-4516-b123-0076f29a8b0d','江月亭二絕  其一','王十朋','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江何處水，明月幾州天。',24,'全唐诗/poet.song.119000.json','["長江何處水，明月幾州天。", "月與江無約，相逢是偶然。"]'),
('6db77c9b-906e-4955-880b-83ee2c71c8f1','江月亭二絕  其二','王十朋','宋','宋诗','song-poetry','','[]','江山今古幾英雄，割據并吞總是空。',32,'全唐诗/poet.song.119000.json','["江山今古幾英雄，割據并吞總是空。", "惟有江流不轉石，千秋長在月明中。"]'),
('9d6eb5db-a33d-4bee-9f29-185fb6d617c9','登真武山','王十朋','宋','宋诗','song-poetry','','[]','籃輿曉上小琳宮，夔子江山指顧中。',32,'全唐诗/poet.song.119000.json','["籃輿曉上小琳宮，夔子江山指顧中。", "道士手栽山上柏，身猶未老幹凌空。"]'),
('76cb3c9f-64fb-4183-a0a6-9c5b7a651a22','上元山中百姓出游作三章諭之  其一','王十朋','宋','宋诗','song-poetry','','[]','鄰里相呼入郡城，巴歌楚舞沸歡聲。',32,'全唐诗/poet.song.119000.json','["鄰里相呼入郡城，巴歌楚舞沸歡聲。", "三宵游罷同歸去，勉力耕桑事父兄。"]'),
('df6e2ed5-912d-4280-93b9-0e48a460331c','上元山中百姓出游作三章諭之  其二','王十朋','宋','宋诗','song-poetry','','[]','三日嬉游喜遇晴，還家又見麥青青。',32,'全唐诗/poet.song.119000.json','["三日嬉游喜遇晴，還家又見麥青青。", "但須及早輸租稅，莫要勾呼到訟庭。"]'),
('f6917be5-25f7-4699-912b-4dd94a526c5d','上元山中百姓出游作三章諭之  其三','王十朋','宋','宋诗','song-poetry','','[]','好去耕耘隴上田，但能勤苦有豐年。',32,'全唐诗/poet.song.119000.json','["好去耕耘隴上田，但能勤苦有豐年。", "家家飽暖身康健，更向明年看月圓。"]'),
('bb2f121e-6fa4-4d81-b2bb-7421d5c83cd1','題諸葛武侯祠','王十朋','宋','宋诗','song-poetry','','[]','八陣圖旁丞相祠，風雲慘淡會當時。',64,'全唐诗/poet.song.119000.json','["八陣圖旁丞相祠，風雲慘淡會當時。", "功成豈止三分漢，才大非惟十倍丕。", "渭上忽傳司馬走，蜀中長起卧龍思。", "我來再拜瞻遺像，淚滿襟如老杜詩。"]'),
('4d5bb284-1fc9-4416-bfe1-46ff69a39e5e','登詩史堂觀少陵畫像','王十朋','宋','宋诗','song-poetry','','[]','萬丈光芒筆有神，兩眉猶带舊酸辛。',64,'全唐诗/poet.song.119000.json','["萬丈光芒筆有神，兩眉猶带舊酸辛。", "殘杯不復隨肥馬，賸馥端能丐後人。", "夔子江頭吟處景，杜鵑聲裏拜時身。", "敬瞻遺像觀詩史，一酹雲安麴米春。"]'),
('9a8a6a73-6205-468d-b515-6bc5038bbcf1','送參議吳郎中','王十朋','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','扁舟西泝蜀江長，邂逅論交得老蒼。',64,'全唐诗/poet.song.119000.json','["扁舟西泝蜀江長，邂逅論交得老蒼。", "幕客可能淹杜甫，郎官誰復識馮唐。", "梅花開日方聯事，柳絮飛時遽趣裝。", "我過洞庭應有日，定須來掃蓋公堂。"]'),
('4c5186e5-0713-4398-a098-436811e1dad6','夔州祀社稷于州之西五里地不盈畝壇宇庳陋垣牆頹圮非所以崇明祀也買地易路築屋增壇命同僚董其事不踰月告成二月戊子祀事既畢詩以記之','王十朋','宋','宋诗','song-poetry','','[]','天下通祀惟社稷，次則曰雨曰雷風。',128,'全唐诗/poet.song.119000.json','["天下通祀惟社稷，次則曰雨曰雷風。", "勾龍與棄配土穀，是皆於民有大功。", "古夔子國今會府，其於明祀可不崇。", "西郊壇宇何太陋，我忝守土責在躬。", "廣而新之繄誰力，蓮幕花縣謀僉同。", "築垣旁近丹荔圃，闢路下壓黄冠宮。", "地有松柏兼可植，時和黍稌行將豐。", "夔門社稷宋社稷，願與天地同無窮。"]'),
('035b6008-b8d6-49b6-b0cb-57ca1d77e2f7','游卧龍山呈行可元章','王十朋','宋','宋诗','song-poetry','','[]','我輩逢山眼即青，卧龍頂上喜同登。',64,'全唐诗/poet.song.119000.json','["我輩逢山眼即青，卧龍頂上喜同登。", "圖留沙磧懷諸葛，詩誦江濆憶少陵。", "巫峽雲飛天一握，瞿唐魚化浪三層。", "藍輿又向人間去，回首林泉媿老僧。"]'),
('cdffbd48-a84b-4bf0-94dc-3866bc2db6ba','聞詩得男名之曰夔','王十朋','宋','宋诗','song-poetry','','[]','巫邑初傳鯉，吾家遂得夔。',48,'全唐诗/poet.song.119000.json','["巫邑初傳鯉，吾家遂得夔。", "遥來如馬地，却應夢熊詩。", "官忝二千石，孫看第一枝。", "欣同君子抱，祝汝似吾兒。"]'),
('deb94ea8-bcde-4071-8e41-f3a0793d0f74','甘露降于宅堂竹間凡半月三經雨乃止州宅有甘露堂昔周□□侍郎爲郡露降焉易見山堂以名之予無善政懼其爲災記以二絕  其一','王十朋','宋','宋诗','song-poetry','','[]','湛湛下脩竹，味如飴蜜甘。',24,'全唐诗/poet.song.119000.json','["湛湛下脩竹，味如飴蜜甘。", "人言此爲瑞，無德可能堪。"]'),
('b9858fc5-1da0-48d5-9058-c8e88adece19','甘露降于宅堂竹間凡半月三經雨乃止州宅有甘露堂昔周□□侍郎爲郡露降焉易見山堂以名之予無善政懼其爲災記以二絕  其二','王十朋','宋','宋诗','song-poetry','','[]','竹間甘露日瀼瀼，飴蜜珠璣带細香。',32,'全唐诗/poet.song.119000.json','["竹間甘露日瀼瀼，飴蜜珠璣带細香。", "天閔夔民歲饑饉，雨暘時若乃嘉祥。"]'),
('dc777d3a-c3c2-4837-a977-a224afa5b251','元章贈蘭','王十朋','宋','宋诗','song-poetry','','[]','英英道山友，贈我深林芳。',48,'全唐诗/poet.song.119000.json','["英英道山友，贈我深林芳。", "入室與俱化，同心如此香。", "紉之可爲佩，不采庸何傷。", "三復韓子操，援琴鼓揚揚。"]'),
('2b9439a2-cf28-4b68-a7f1-f2afc872ff02','卧龍山有武侯新祠再用前韵','王十朋','宋','宋诗','song-poetry','','[]','山藏古寺柏青青，地重端因蜀相登。',64,'全唐诗/poet.song.119000.json','["山藏古寺柏青青，地重端因蜀相登。", "沙上不聞江轉石，人間幾見谷爲陵。", "龍蛇樹影摇千尺，玉雪花枝吐萬層。", "堪嘆草廬誰復顧，凄然香火却依僧。"]'),
('06147215-6002-458c-a69a-ce8219740f32','寄書與二叔二弟  其一','王十朋','宋','宋诗','song-poetry','','[]','八十高年林下老，四千餘里夢中家。',32,'全唐诗/poet.song.119000.json','["八十高年林下老，四千餘里夢中家。", "雲安雙鯉隨春水，爲我傳書到永嘉。"]'),
('e9ddb1ae-df8f-4701-87c1-05b337e09667','寄書與二叔二弟  其二','王十朋','宋','宋诗','song-poetry','','[]','左原端是脊令原，誰遣分飛到蜀門。',32,'全唐诗/poet.song.119000.json','["左原端是脊令原，誰遣分飛到蜀門。", "况是清明寒食候，杜鵑聲裏斷離魂。"]'),
('3b8f111d-97bf-49ef-94b7-6090fa265411','題卧龍山觀音泉呈行可元章','王十朋','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','去歲游廬山，社中觀白蓮。',240,'全唐诗/poet.song.119000.json','["去歲游廬山，社中觀白蓮。", "不飲遠公酒，聊酌聰明泉。", "肩輿過武昌，乘興西山巔。", "巖乳飲菩薩，詩篇誦蘇仙。", "夔州苦無井，癭俗殊可憐。", "竹筩喉不乾，可浣不可煎。", "日汲卧龍水，屢頼擔夫肩。", "所取都幾斛，深慚未投錢。", "前日招提游，入耳聲涓涓。", "泓澄可照膽，草木皆光妍。", "却疑南陽人，蟠蟄清泠淵。", "慘淡會風雲，滂沱霖普天。", "源如少陵詞，清入光芒篇。", "餘波漲瞿唐，洶湧吞百川。", "何人著水經，漏此不及編。", "道人出新茗，林間手新研。", "共以夷齊心，來結觀音緣。", "至今清夜夢，猶到幽亭邊。", "交游况離索，回首成悽然。", "何時鹿呦呦，重訪山中禪。"]'),
('b25f00e2-fca5-4698-8b64-1ab0f3ded167','元章贈筆戲成一絕','王十朋','宋','宋诗','song-poetry','','[]','東臺使者妙詩文，贈我中書四十君。',32,'全唐诗/poet.song.119000.json','["東臺使者妙詩文，贈我中書四十君。", "我不善書慚拜賜，中書今日遇將軍。"]'),
('e2eae2da-0d14-446f-8b88-81a5914ec79f','再酬元章','王十朋','宋','宋诗','song-poetry','','[]','一尊方喜細論文，春草題詩又送君。',32,'全唐诗/poet.song.119000.json','["一尊方喜細論文，春草題詩又送君。", "手握管城言不盡，詩壇誰復將中軍。"]'),
('5de29b66-e310-4393-a9f7-579ac9b45da9','又答行可','王十朋','宋','宋诗','song-poetry','','[]','道造精微更有文，絳侯應媿不如君。',32,'全唐诗/poet.song.119000.json','["道造精微更有文，絳侯應媿不如君。", "試將武事論詩筆，句法嚴於細柳軍。"]'),
('c4d79cc7-2a9e-4887-89be-75d0adf08cfb','酬行可惠白酒','王十朋','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','渴懷思欲吸長江，聞說西臺釀滿缸。',32,'全唐诗/poet.song.119000.json','["渴懷思欲吸長江，聞說西臺釀滿缸。", "一斗青州白從事，忽隨詩句到蓬窗。"]'),
('c4e7c36c-3609-4b96-b1f7-71d3ed31fa03','同行可元章報恩寺行香登佛牙樓望勝己山','王十朋','宋','宋诗','song-poetry','','[]','籃輿拂曉出東關，鍾磬聲聞杳靄間。',64,'全唐诗/poet.song.119000.json','["籃輿拂曉出東關，鍾磬聲聞杳靄間。", "心欲報恩頻入院，人逢勝己更觀山。", "竹香細細禪房靜，江水渾渾野渡閑。", "欲問漁人國興廢，黄鸝隔葉語緜蠻。"]'),
('03cd59de-5402-4b83-845f-a7fc2953de7e','五月四日與同僚南樓觀競渡因成小詩四首明日同行可元章登樓又成五首  其一','王十朋','宋','宋诗','song-poetry','','[]','蜀江險處是夔州，灧澦堆邊看競舟。',32,'全唐诗/poet.song.119000.json','["蜀江險處是夔州，灧澦堆邊看競舟。", "爲報鄱陽相識道，去年人在此登樓。"]'),
('d6fb03e5-0414-4c22-8fd5-3fb11504d888','五月四日與同僚南樓觀競渡因成小詩四首明日同行可元章登樓又成五首  其二','王十朋','宋','宋诗','song-poetry','','[]','臺前八陣己陳迹，水底三閭何處招。',32,'全唐诗/poet.song.119000.json','["臺前八陣己陳迹，水底三閭何處招。", "手把菖蒲對佳節，興來呼酒勸同僚。"]'),
('039be3c5-cc44-49f6-b12b-da5e9bcf79e4','五月四日與同僚南樓觀競渡因成小詩四首明日同行可元章登樓又成五首  其三','王十朋','宋','宋诗','song-poetry','','[]','鄱陽夔子兩端午，去歲人如今歲人。',32,'全唐诗/poet.song.119000.json','["鄱陽夔子兩端午，去歲人如今歲人。", "直是吳頭來蜀尾，子規聲裏弔靈均。"]'),
('ff1a4f37-58fa-4e59-b0e6-f71317c63350','五月四日與同僚南樓觀競渡因成小詩四首明日同行可元章登樓又成五首  其四','王十朋','宋','宋诗','song-poetry','','[]','榴花照眼對佳客，荷葉傳杯懷故鄉。',32,'全唐诗/poet.song.119000.json','["榴花照眼對佳客，荷葉傳杯懷故鄉。", "想見明年話夔子，又如今歲念鄱陽。"]'),
('7f40cb72-81f3-43d6-b3f8-5673f3cb99f9','五月四日與同僚南樓觀競渡因成小詩四首明日同行可元章登樓又成五首  其五','王十朋','宋','宋诗','song-poetry','','[]','黍遇今朝盡生角，艾從何處忽爲神。',32,'全唐诗/poet.song.119000.json','["黍遇今朝盡生角，艾從何處忽爲神。", "荷香十里一鈎月，定有扁舟歸去人。"]'),
('fcab636f-65cb-42c4-aa32-99f9180e068f','五月四日與同僚南樓觀競渡因成小詩四首明日同行可元章登樓又成五首  其六','王十朋','宋','宋诗','song-poetry','','[]','舟人鼓楫呼何在，聲似湘沅江上聲。',32,'全唐诗/poet.song.119000.json','["舟人鼓楫呼何在，聲似湘沅江上聲。", "更聽劉郎竹枝曲，不論南北總傷情。"]'),
('5b0db367-c833-4287-bb80-5ccdbf05530a','五月四日與同僚南樓觀競渡因成小詩四首明日同行可元章登樓又成五首  其七','王十朋','宋','宋诗','song-poetry','','[]','細葛含風羅疊雪，近臣初拜賜衣時。',32,'全唐诗/poet.song.119000.json','["細葛含風羅疊雪，近臣初拜賜衣時。", "願因角黍詢遺俗，學士寧無六一詞。"]'),
('38051f97-35de-48b2-ba11-8947b570971c','五月四日與同僚南樓觀競渡因成小詩四首明日同行可元章登樓又成五首  其八','王十朋','宋','宋诗','song-poetry','','[]','競渡本來緣救溺，凌波初不爲爭標。',32,'全唐诗/poet.song.119000.json','["競渡本來緣救溺，凌波初不爲爭標。", "今人不解古人意，得勝歸來笑語囂。"]'),
('7ee6b538-c0f9-498a-a4de-84b87ddebabd','五月四日與同僚南樓觀競渡因成小詩四首明日同行可元章登樓又成五首  其九','王十朋','宋','宋诗','song-poetry','','[]','綵舟兩兩鼓鼕鼕，勝己山陰瀼水東。',32,'全唐诗/poet.song.119000.json','["綵舟兩兩鼓鼕鼕，勝己山陰瀼水東。", "父老相逢話良苦，兒郎多在馬船中。"]'),
('fda28222-27ed-4142-af62-05830c9925cb','劉韶美至巫山寄詩因次其韵','王十朋','宋','宋诗','song-poetry','','[]','終日思歸未有涯，夢魂無夜不還家。',64,'全唐诗/poet.song.119000.json','["終日思歸未有涯，夢魂無夜不還家。", "莫雲春樹憶太白，流水高山逢伯牙。", "卷軸隨身雖有厄，風流得罪可無譁。", "相逢莫便匆匆去，弭棹夔門過食瓜。"]'),
('300730f6-3b94-44ed-abaa-0dc207ce0875','送元章改漕成都','王十朋','宋','宋诗','song-poetry','','[]','取友四十載，普天半交游。',288,'全唐诗/poet.song.119000.json','["取友四十載，普天半交游。", "蒹葭群玉間，莫盛登瀛洲。", "元章真國士，未見心已投。", "雅抱畎畆志，共懷天下憂。", "舘閣育人材，孰云專校讎。", "慷慨論世事，不見范尹歐。", "疆埸况如許，寧不憂宗周。", "精忠屹肝膽，苦語驚冕旒。", "君去最勇决，我行尚遲留。", "初別擬十載，相逢忽三秋。", "龍飛起元老，江淮握貔貅。", "禮羅得奇才，戎幕資良籌。", "人事苦好違，壯懷莫能酬。", "去持夔州節，遥泛瞿唐舟。", "我亦來自鄱，茲行豈人謀。", "八陣觀壯圖，三峽窺倒流。", "訪君義勝堂，顧我制勝樓。", "如馬謁白帝，卧龍尋武侯。", "江亭覽月色，園花賞春柔。", "果分餘味甘，蘭贈深林幽。", "詩篇浩卷軸，墨妙輝山丘。", "氣薄文艷杜，詞卑竹枝劉。", "吏事容拙踈，交情荷綢繆。", "綸言下北闕，綉衣使西州。"]'),
('fef47a75-e86a-44de-ae57-2fc86cab25cc','次韵元章留別','王十朋','宋','宋诗','song-poetry','','[]','送客成都去，回舟白帝邊。',48,'全唐诗/poet.song.119000.json','["送客成都去，回舟白帝邊。", "月應遥共對，夔復有誰憐。", "我只懷歸計，君宜了世緣。", "相期翼吾道，餘事讀楞圓。"]'),
('c7ca2782-2fad-4423-9e35-b6116f06487c','夜與韶美飲酒瑞白堂秉燭觀跳珠，分韵得跳字','王十朋','宋','宋诗','song-poetry','','[]','五月峽中天氣歊，竹筩引水那能澆。',128,'全唐诗/poet.song.119000.json','["五月峽中天氣歊，竹筩引水那能澆。", "江濆龍老卧未起，崖石不枯珠自跳。", "草草杯盤對君酌，燈前疑是簷花落。", "毫端寫出萬斛珠，共向炎天作氷雹。", "妃子名園荔子丹，絳囊初摘堆金盤。", "細擘輕紅唱君曲，咀嚼水晶牙頰寒。", "老翁真箇如年少，激水成珠堪一笑。", "劉侯自有胸中珠，不止照人兼自照。"]'),
('ee842678-f726-42e9-943b-2b276ab57d0a','儀鳳得珠字','王十朋','宋','宋诗','song-poetry','','[]','別來世故朝昏殊，相與言之汗模糊。',160,'全唐诗/poet.song.119000.json','["別來世故朝昏殊，相與言之汗模糊。", "兩翁得酒促坐席，感深念極氣欲蘇。", "籜龍亦解作水供，紬繹尋丈如渴烏。", "衣巾生秋背毛豎，金石相應環佩趨。", "江山豪壯旁尊俎，醉中頻貫纍纍珠。", "此時一事復掛口，爲樂未竟成喑嗚。", "夔州憂民困湯火，潤澤有志無坦途。", "眼前焦熬十萬戶，欠伸戲笑皆霑濡。", "自操量槩入官廩，不輸一錢分水符。", "讀書功力無表畔，久矣俗吏輕吾儒。"]'),
('4096be68-1a60-4209-a2fd-47f3f3e1854b','次韵韶美失舟閔書','王十朋','宋','宋诗','song-poetry','','[]','醫師籠參朮，良將枕戈矢。',168,'全唐诗/poet.song.119000.json','["醫師籠參朮，良將枕戈矢。", "儒生嗜底物，書卷掛口齒。", "劉侯西南來，歲月十首尾。", "閉門閲古今，過眼分亥豕。", "異書照神藜，奇字哭妖鬼。", "許身如蠹魚，文字共生死。", "風流反得罪，去國果誰耻。", "仙舟載祕閣，便腹貯名理。", "江神亦世情，逐客多不喜。", "厄同焚書秦，惡類滅邢燬。", "沾濡徧箱篋，痛惜到骨髓。", "我初聞爲驚，終夜成坐起。", "得君詩細讀，罪己不罪水。", "願言坐嘯餘，書著子劉子。"]'),
('1fc37405-6af6-450d-b8ec-4fdcaa95d52f','韶美歸舟過夔留半月語離作惡詩二章以送  其一','王十朋','宋','宋诗','song-poetry','','[]','五載三詩送我歸，古夔今作送君詩。',64,'全唐诗/poet.song.119000.json','["五載三詩送我歸，古夔今作送君詩。", "相如游處符分竹，諸葛陣旁舟解維。", "秉燭莫辭頻把酒，揮毫未免各憂時。", "可憐灧澦雙蓬鬢，會合無多又別離。"]'),
('ee972538-ee45-4d5b-b4e8-197231dd8858','韶美歸舟過夔留半月語離作惡詩二章以送  其二','王十朋','宋','宋诗','song-poetry','','[]','弱羽年來正倦飛，夔門邂逅故人歸。',64,'全唐诗/poet.song.119000.json','["弱羽年來正倦飛，夔門邂逅故人歸。", "人生一笑難開口，世事多端合掩扉。", "况是桑榆俱晚景，何曾富貴已危機。", "明朝悵望仙舟遠，百尺高樓上靜暉。"]'),
('d70def91-8e7c-4e21-9de4-f91ba90278c6','元章至雲安用送韶美韵見寄次韵以酬','王十朋','宋','宋诗','song-poetry','','[]','社燕秋鴻不共飛，却因送別更懷歸。',64,'全唐诗/poet.song.119000.json','["社燕秋鴻不共飛，却因送別更懷歸。", "一壺獨酌人何處，千里相思月滿扉。", "烟雨已催予把釣，功名行看子投機。", "雲安雙鯉傳書至，詩句清含山水暉。"]'),
('3e33c34c-cb8d-4339-9b4f-5a1898956eb6','靜暉樓前有荔子一株木老矣猶未生予去其枯枝今歲遂生一二百顆至六月方熟','王十朋','宋','宋诗','song-poetry','','[]','木老生遲六月丹，明珠百顆照朱顔。',64,'全唐诗/poet.song.119000.json','["木老生遲六月丹，明珠百顆照朱顔。", "因渠風味思瑶柱，撩我鄉心念玉環。", "路遠應難三日寄，樓高更上一層攀。", "君謨譜內丁香種，宜在江陳品第間。"]'),
('b3338052-5e00-4bbe-8efe-f751ef1c6c15','行可和詩再用前韵','王十朋','宋','宋诗','song-poetry','','[]','肌膚冰雪鶴頭丹，三峽相逢一破顔。',64,'全唐诗/poet.song.119000.json','["肌膚冰雪鶴頭丹，三峽相逢一破顔。", "人折高枝如折桂，鳥銜餘顆似銜環。", "香傳樂譜名尤重，紅入詩家句莫攀。", "來歲熟時先寄我，夢魂應到白雲間。"]'),
('080a387c-4c21-475e-a851-5a10280845df','行可再和因思前日與韶美同飲計臺臨池摘實復用前韵','王十朋','宋','宋诗','song-poetry','','[]','星火燒空一夜丹，來禽青李覺無顔。',64,'全唐诗/poet.song.119000.json','["星火燒空一夜丹，來禽青李覺無顔。", "少陵池舘三人賞，白帝江山四面環。", "生晚免教妃子汙，食餘應許黑衣攀。", "閩娘十八誰標榜，未必風流似此間。"]'),
('13430137-d900-4a20-94c5-8454e4e9568a','又用韵呈行可','王十朋','宋','宋诗','song-poetry','','[]','神仙乞與返魂丹，枯木能成處子顔。',64,'全唐诗/poet.song.119000.json','["神仙乞與返魂丹，枯木能成處子顔。", "雅樂聲中逢魏絳，重圍解後見齊環。", "九齡賦妙那能繼，三峽詩高未易攀。", "兒輩莫言酬倡晚，吾鄉食實在秋間。"]'),
('41527eb6-47ac-4709-86a2-caccbca8bc55','元章至萬州湖灘寄六言一絕云滿目莫山平遠一池雲錦清酣忽有鍾聲林際直疑夢到江南某六月朔日登靜暉樓觀江漲望西南碧遠數峰乃前日送別處也爲之黯然樓前荔子初丹次韵寄元章','王十朋','宋','宋诗','song-poetry','','[]','遥碧峯尖如削，輕紅荔臉初酣。',28,'全唐诗/poet.song.119000.json','["遥碧峯尖如削，輕紅荔臉初酣。", "水漲江天渺渺，故人一葉西南。"]'),
('5b2fb696-f7be-42cc-8708-73529a0364b0','韶美至雲安寄詩二首再用詩字韻以寄','王十朋','宋','宋诗','song-poetry','','[]','劉郎初自日邊歸，入峽殷勤寄我詩。',64,'全唐诗/poet.song.119000.json','["劉郎初自日邊歸，入峽殷勤寄我詩。", "大小承天思越絕，後先去國會坤維。", "分題應記跳珠夜，送別還思入竹時。", "千里遥遥共明月，此心無合亦無離。"]'),
('244645f3-26a2-4ade-a821-4145590ff582','伏日與同官小飲瑞白堂觀跳珠分韵賦詩','王十朋','宋','宋诗','song-poetry','','[]','瑞白堂虛氷雪凝，散爲珠玉洗炎蒸。',32,'全唐诗/poet.song.119000.json','["瑞白堂虛氷雪凝，散爲珠玉洗炎蒸。", "詼諧未效東方朔，賦詠聊追杜少陵。"]'),
('fb6efda0-e9a0-48bf-85f6-8227c12f702b','伏日懷鄱陽同僚','王十朋','宋','宋诗','song-poetry','','[]','去歲鄱陽四望亭，題分十二志同登。',32,'全唐诗/poet.song.119000.json','["去歲鄱陽四望亭，題分十二志同登。", "眼中忽見天邊月，不謂天邊是固陵。"]'),
('1522f952-0a01-4818-8218-5d6f6e5cd075','餘干翁簿以予去饒之日郡人斷橋見留畫圖賦詩見寄因次其韵','王十朋','宋','宋诗','song-poetry','','[]','我慕鄭子真，躬耕老巖谷。',240,'全唐诗/poet.song.119000.json','["我慕鄭子真，躬耕老巖谷。", "不慕蘇季子，腰金詫宗族。", "失脚落塵網，回頭念幽獨。", "向來鴛鷺行，進退慚碌碌。", "把麾鄱君國，飲水清灣曲。", "緬懷九賢人，痛閔千里俗。", "奉揚乏仁風，黎庶因炎燠。", "疇能政有成，敢望諾無宿。", "厚顔叨祿廩，汗背擁旌纛。", "命下忽夔門，諸公孰推轂。", "水陸三千里，湖重嶺仍複。", "至喜謁文忠，秭歸懷李矗。", "鄱人憐老守，去類楚臣逐。", "出門橋已斷，擁道頞爭蹙。", "初無龔黄政，濫繼秦侯躅。", "仇香舊同僚，別寄兩竿牘。", "賦詩仍畫圖，開卷宛在目。", "清音滿干越，餘韵到巴蜀。", "我有二頃田，荒蕪雁山腹。", "願畫歸去來，芒鞋事耕育。"]'),
('c270b142-6d8c-420e-ba65-176f9bfe52ec','贈裴童子','王十朋','宋','宋诗','song-poetry','','[]','文公有序規童子，將聖猶言畏後生。',32,'全唐诗/poet.song.119000.json','["文公有序規童子，將聖猶言畏後生。", "好把五車書盡讀，五車讀了要須行。"]'),
('8915367a-3d3d-4422-a42b-4e6dc6480227','行可生日','王十朋','宋','宋诗','song-poetry','','[]','千載岐周鸑鷲聞，果生英傑嗣姬文。',64,'全唐诗/poet.song.119000.json','["千載岐周鸑鷲聞，果生英傑嗣姬文。", "鯤鵬變化正六月，蟾兔光輝將十分。", "肯把威名爭烈日，只將道眼視浮雲。", "祝公壽共詩書久，一瓣心香已敬焚。"]'),
('63b70f5f-a9d8-466b-93ab-5a2741f4c7ae','王嘉叟和讀楚東詩復用前韵以寄','王十朋','宋','宋诗','song-poetry','','[]','照眼驪珠光陸離，莆田太守寄新詩。',32,'全唐诗/poet.song.119000.json','["照眼驪珠光陸離，莆田太守寄新詩。", "死生貴賤交情見，惟有吾宗不徇時。"]'),
('12377b58-29e2-4f3f-9043-4dbe5054a664','嘉叟和黯字詩再用前韵以寄','王十朋','宋','宋诗','song-poetry','','[]','金谷富季倫，丑坐貴思黯。',48,'全唐诗/poet.song.119000.json','["金谷富季倫，丑坐貴思黯。", "人間幾泉石，豪奪在軒檻。", "燕賀厦初成，花飛春忽減。", "破甑任生塵，只有萊蕪范。"]'),
('0a394e4e-a1db-40cd-b3b8-0f593716ddf0','和喻叔奇宿大木寺','王十朋','宋','宋诗','song-poetry','','[]','木記餘干大，風觀楚國雄。',48,'全唐诗/poet.song.119000.json','["木記餘干大，風觀楚國雄。", "吾詩留大木，君句壓雄風。", "鄱水連天碧，潘花滿縣紅。", "論文一尊酒，何日故人同。"]'),
('81d1c28b-c499-40eb-9d29-3bef208d0dda','用讀楚東集韵寄元章','王十朋','宋','宋诗','song-poetry','','[]','誰遣吾儕合又離，江山深憶共題詩。',32,'全唐诗/poet.song.119000.json','["誰遣吾儕合又離，江山深憶共題詩。", "君舟西上吾東矣，尊酒論文更幾時。"]'),
('9690b8ed-f9ba-4c61-9351-cd46bba01cdf','納凉','王十朋','宋','宋诗','song-poetry','','[]','簾捲見山近，窗開竹香香。',24,'全唐诗/poet.song.119000.json','["簾捲見山近，窗開竹香香。", "訟庭公事少，靜坐納微凉。"]'),
('ddaf3fdb-281e-49ce-805f-593d5e17c016','立秋','王十朋','宋','宋诗','song-poetry','','[]','節物催吾老，天涯見立秋。',48,'全唐诗/poet.song.119000.json','["節物催吾老，天涯見立秋。", "凉微金尚伏，暑熾火初流。", "家遠思嘗稻，年衰怯戴楸。", "歸耕期已近，河漢望牽牛。"]'),
('cde4fab2-8282-487f-b68d-9f3bb44abd10','七夕','王十朋','宋','宋诗','song-poetry','','[]','去年佳節吳頭見，今久秋聲峽內聞。',64,'全唐诗/poet.song.119000.json','["去年佳節吳頭見，今久秋聲峽內聞。", "桂魄漸看成半璧，銀河猶自掩微雲。", "曬書空有便便腹，乞巧初無怪怪文。", "爲向天邊牛女道，夫耕婦織莫辭勤。"]'),
('65fe5cdc-c01c-4876-8457-5abc5713656f','懷鄱陽','王十朋','宋','宋诗','song-poetry','','[]','一別鄱陽歲及朞，夔門又見食瓜時。',32,'全唐诗/poet.song.119000.json','["一別鄱陽歲及朞，夔門又見食瓜時。", "自慚政拙無遺愛，安得民心有去思。"]'),
('8ae4a87d-f53f-462b-b824-c559b082144c','齒落用昌黎韻','王十朋','宋','宋诗','song-poetry','','[]','我來饒與夔，三載墮兩齒。',216,'全唐诗/poet.song.119000.json','["我來饒與夔，三載墮兩齒。", "懸知年非永，早悟仕當已。", "要須未落時，猛效二疏止。", "胡爲一再落，不已良可耻。", "慨然懷古人，未有長不死。", "因思年方少，輩行多勝己。", "顔紅齒牢潔，徃徃同逝水。", "吾衰况如許，寧復老彭比。", "覽鏡視顔色，今昨不相似。", "行年五十五，萬事可休矣。", "功名與富貴，磨滅何足紀。", "但願早還鄉，俯育三百指。", "婚嫁畢兒女，松楸依怙恃。", "弟兄飲真率，故舊忘汝爾。", "齒牙任摇脫，肉食吾不視。", "有身久爲患，無齒實堪喜。", "始憂笑韓公，可惜陋子美。", "未必傷我心，茲言聞柳子。"]'),
('a8b4b486-daec-43a6-aaa8-8521ab2e01a5','十八坊詩 宣化','王十朋','宋','宋诗','song-poetry','','[]','聖主有美化，丁寧戒守臣。',24,'全唐诗/poet.song.119000.json','["聖主有美化，丁寧戒守臣。", "毋令挂牆壁，宣以及吾民。"]'),
('a7df46af-99e4-43ba-9309-711e4e5944ea','十八坊詩 刑清','王十朋','宋','宋诗','song-poetry','','[]','昔日循良吏，獄空無怨聲。',24,'全唐诗/poet.song.119000.json','["昔日循良吏，獄空無怨聲。", "刑清本無術，心地要先清。"]'),
('9c24599e-6041-441f-8277-df58430d73b9','十八坊詩 介福','王十朋','宋','宋诗','song-poetry','','[]','茲地有神宇，人人來薦羞。',24,'全唐诗/poet.song.119000.json','["茲地有神宇，人人來薦羞。", "神雖能介福，福亦自須求。"]'),
('5b8060e0-7ce0-4cb4-b7de-319d52547b35','十八坊詩 弭節','王十朋','宋','宋诗','song-poetry','','[]','川峽天下險，幾人持節過。',24,'全唐诗/poet.song.119000.json','["川峽天下險，幾人持節過。", "好來平處弭，莫起險中波。"]'),
('d9998583-811d-4bc4-a5a6-13a80c6e7271','十八坊詩 皇華','王十朋','宋','宋诗','song-poetry','','[]','夔府皇華地，乘軺都幾人。',24,'全唐诗/poet.song.119000.json','["夔府皇華地，乘軺都幾人。", "誰如二使者，實惠活斯民。"]'),
('83fd91c1-0470-4a38-b4c8-fb62d8a006a6','十八坊詩 興儒','王十朋','宋','宋诗','song-poetry','','[]','刀笠燒畬俗，舟航撇旋鄉。',24,'全唐诗/poet.song.119000.json','["刀笠燒畬俗，舟航撇旋鄉。", "五經誰教子，儒術破天荒。"]'),
('1ebacdba-3ef5-4705-ad3b-eea21ca1c5ac','十八坊詩 崇化','王十朋','宋','宋诗','song-poetry','','[]','西接卿雲里，東連屈宋鄉。',24,'全唐诗/poet.song.119000.json','["西接卿雲里，東連屈宋鄉。", "好風吹峽水，盡作魯芹香。"]'),
('d4fd04e8-7a9d-4900-8a4d-90888fb025b6','十八坊詩 𢡟遷','王十朋','宋','宋诗','song-poetry','','[]','相與勿言利，要令通有無。',24,'全唐诗/poet.song.119000.json','["相與勿言利，要令通有無。", "家家香一瓣，心慕舜之徒。"]'),
('e34daff8-b784-4da8-a602-47d721991c83','十八坊詩 興龍','王十朋','宋','宋诗','song-poetry','','[]','世仰欽宗聖，人知太母賢。',24,'全唐诗/poet.song.119000.json','["世仰欽宗聖，人知太母賢。", "千秋龍已化，香火蜀江邊。"]'),
('5a56bdbd-ba91-4205-ba62-0a64cf2680c4','十八坊詩 卧龍','王十朋','宋','宋诗','song-poetry','','[]','非長陳壽賛贊，無首杜陵詩。',25,'全唐诗/poet.song.119000.json','["非長陳壽賛贊，無首杜陵詩。", "廟貌并公論，如今勝昔時。"]'),
('a681f42a-5433-4420-9547-a20ac56bd432','十八坊詩 慶豐','王十朋','宋','宋诗','song-poetry','','[]','誰道夔門陋，茲坊號慶豐。',24,'全唐诗/poet.song.119000.json','["誰道夔門陋，茲坊號慶豐。", "守臣憂國願，端似杜陵翁。"]'),
('1699f6c1-2514-4064-bdfd-992d4f377f5e','十八坊詩 禮賓','王十朋','宋','宋诗','song-poetry','','[]','前山名勝己，夔子有嘉賓。',24,'全唐诗/poet.song.119000.json','["前山名勝己，夔子有嘉賓。", "舘闢自予始，媿非賢主人。"]'),
('82babe9c-1931-432a-9bd4-4da9168ef4e9','十八坊詩 通津','王十朋','宋','宋诗','song-poetry','','[]','大江來自蜀，衆水共朝東。',24,'全唐诗/poet.song.119000.json','["大江來自蜀，衆水共朝東。", "我欲扁舟去，問津從此通。"]'),
('a9b00ca2-0a33-4305-ae92-3c812e77bbf4','十八坊詩 義泉','王十朋','宋','宋诗','song-poetry','','[]','官費接筒竹，民蠲沽水錢。',24,'全唐诗/poet.song.119000.json','["官費接筒竹，民蠲沽水錢。", "丁寧後來者，莫負義名泉。"]'),
('95844f16-b074-412e-a93d-7e538d2fb6fd','十八坊詩 永安','王十朋','宋','宋诗','song-poetry','','[]','分鼎江山在，受遺宮闕荒。',24,'全唐诗/poet.song.119000.json','["分鼎江山在，受遺宮闕荒。", "風雲時慘淡，疑會舊明良。"]'),
('4a0895a4-5edf-42fa-b5b9-065ebc0d307c','十八坊詩 折桂','王十朋','宋','宋诗','song-poetry','','[]','月窟何人到，向來標榜新。',24,'全唐诗/poet.song.119000.json','["月窟何人到，向來標榜新。", "如今折桂者，不止一坊人。"]'),
('94a2f72e-3fa6-44c0-b96c-a4cac1a73958','十八坊詩 知足','王十朋','宋','宋诗','song-poetry','','[]','二疏歸去後，林下少休官。',24,'全唐诗/poet.song.119000.json','["二疏歸去後，林下少休官。", "聖代夔門裏，一枝栖故鸞。"]'),
('6ae70b72-1be0-4c50-a5e9-9b58390e462d','十八坊詩 和風','王十朋','宋','宋诗','song-poetry','','[]','郡城深僻處，車馬罕經過。',24,'全唐诗/poet.song.119000.json','["郡城深僻處，車馬罕經過。", "中有人多少，人和風自和。"]'),
('bbb8b563-ef8d-4848-82e7-1bc53b5a4ca1','制勝樓','王十朋','宋','宋诗','song-poetry','','[]','絕塞依天險，高城瞰陣圖。',48,'全唐诗/poet.song.119000.json','["絕塞依天險，高城瞰陣圖。", "公孫曾帝蜀，諸葛欲吞吳。", "尊俎衝千里，關山敵萬夫。", "人謀兼地利，端坐靜邊隅。"]'),
('f848df3a-4526-4323-b384-d3e519be4480','中元日得雨','王十朋','宋','宋诗','song-poetry','','[]','秋陽亢流火，時雨洗中元。',48,'全唐诗/poet.song.119000.json','["秋陽亢流火，時雨洗中元。", "既賀苗蘇槁，還欣暑滌煩。", "德知天地大，功任鬼神言。", "願作老農圃，一犁耕故園。"]'),
('11a68866-7699-4c57-8151-15aa67ff1012','夢覺偶成','王十朋','宋','宋诗','song-poetry','','[]','早秋良夜月朦朧，夢覺凉生枕簟中。',32,'全唐诗/poet.song.119000.json','["早秋良夜月朦朧，夢覺凉生枕簟中。", "數點過雲簷外雨，一聲落木隴頭風。"]'),
('67153c1e-d638-485e-8d17-59770a60fa54','題無隠齋寄交代張真父舍人','王十朋','宋','宋诗','song-poetry','','[]','遥自不欺室，來居無隠齋。',48,'全唐诗/poet.song.119000.json','["遥自不欺室，來居無隠齋。", "事君均有犯，得郡兩俱佳。", "西蜀去何猛，東甌歸未諧。", "清風數竿竹，時見故人懷。"]'),
('ce04e2fd-df0b-40a4-99f6-9e5c95e6e98e','漕臺賞荷花因誦昌黎太華峯頭玉井蓮句遂用其韵呈行可','王十朋','宋','宋诗','song-poetry','','[]','天池水落華開蓮，綉衣呼賓傾玉船。',64,'全唐诗/poet.song.119000.json','["天池水落華開蓮，綉衣呼賓傾玉船。", "賞花對酒誦佳句，香徹鼻觀頭風痊。", "韓公思摘太華實，陶令不結東林緣。", "何如君有第一朶，池上許我清芬連。"]'),
('c30c973f-1e5d-46c0-9499-d0d5d7b4f069','再用前韵','王十朋','宋','宋诗','song-poetry','','[]','夢草池塘千頃蓮，紅雲樓閣游人船。',64,'全唐诗/poet.song.119000.json','["夢草池塘千頃蓮，紅雲樓閣游人船。", "薰薰風日作夏供，病不須藥花能痊。", "朅來夔門念鄉國，浄友喜結西臺緣。", "明年華開各南北，今日有酒宜留連。"]'),
('62f9436c-f4c2-4095-8f25-d7102ca5d077','張主管攝郡秭歸贈以三絕  其一','王十朋','宋','宋诗','song-poetry','','[]','魏公名德最芬馨，猶子傳家有典刑。',32,'全唐诗/poet.song.119000.json','["魏公名德最芬馨，猶子傳家有典刑。", "勉力施行誠與善，民謠待向峽中聽。"]'),
('69affc29-5d1b-47fa-b661-3e7f4fc19c5c','張主管攝郡秭歸贈以三絕  其二','王十朋','宋','宋诗','song-poetry','','[]','女須歸處郡如何，地狹民貧事不多。',32,'全唐诗/poet.song.119000.json','["女須歸處郡如何，地狹民貧事不多。", "把酒送行無別語，要先撫字後催科。"]'),
('a1ca9370-ebee-4f4b-85df-479a49b13a28','張主管攝郡秭歸贈以三絕  其三','王十朋','宋','宋诗','song-poetry','','[]','政術遥傳京兆張，笑談爲治定循良。',32,'全唐诗/poet.song.119000.json','["政術遥傳京兆張，笑談爲治定循良。", "諸生相見宜相勉，正是風騷屈宋鄉。"]'),
('44337674-4efa-4894-9d2d-c8f1e077b01c','蒲萄','王十朋','宋','宋诗','song-poetry','','[]','水晶馬乳薦新秋，青紫酸甜孰味優。',32,'全唐诗/poet.song.119000.json','["水晶馬乳薦新秋，青紫酸甜孰味優。", "只可堆鹽餉韓子，不宜釀酒博凉州。"]'),
('6cf00341-78b5-4adf-aa1e-1ed3f8d2a7a3','寄趙果州','王十朋','宋','宋诗','song-poetry','','[]','九江話別已經年，三峽相逢豈偶然。',32,'全唐诗/poet.song.119000.json','["九江話別已經年，三峽相逢豈偶然。", "預掃江頭禮賓舘，論文尊酒菊花天。"]'),
('d8fbc088-7c25-4347-9b73-0273ca5af007','寄閻普州','王十朋','宋','宋诗','song-poetry','','[]','對策天庭老布衣，直言中已有危機。',32,'全唐诗/poet.song.119000.json','["對策天庭老布衣，直言中已有危機。", "須知東普勝西掖，好買扁舟及早歸。"]'),
('522733b7-d206-4701-9b41-36bc6e964b6b','八月十二日雨','王十朋','宋','宋诗','song-poetry','','[]','七月之間旱如燬，禱而得之偶然耳。',80,'全唐诗/poet.song.119000.json','["七月之間旱如燬，禱而得之偶然耳。", "八月又旱農無秋，同僚勸效前日求。", "我方省愆未及禱，沛然一雨蘇群槁。", "古人重請應上公，何敢頻煩瀆蒼穹。", "但願時暘及時雨，不獨一州天下普。"]'),
('58ffadcc-5498-4980-814b-6799c98fb034','中秋對月用昌黎贈張功曹韵呈同官','王十朋','宋','宋诗','song-poetry','','[]','水精爲鑑金爲波，挂空影寫山與河。',235,'全唐诗/poet.song.119000.json','["水精爲鑑金爲波，挂空影寫山與河。", "清光此夜十分好，有酒有客宜高歌。", "去年今日行役苦，浪叟谿邊宿逢雨。", "傳聞蜀道如天高，崖懸壁絕哀猿號。", "波橫劍戟不易上，陸有虎豹何由逃。", "江山舊恃白帝險，風俗猶带烏蠻臊。", "驅馳兩月到西塞，夢寐萬里還東皐。", "嗅梅踏雪巴子里，路入鬼門欣不死。", "飛飛倦鳥惟思還，玉筍豈是粗官班。", "餘生但願閑及酒，虛名寧顧觸與蠻。", "良宵佳客十有五，雲放月入尊罍間。", "頹然老子興不淺，韓詩坡句聊追攀。", "君不見天寶雲霓羽衣歌，人間樂舞難同科，遺音猶在悲凉多。", "有酒且飲遑卹他，不飲如此良夜何。"]'),
('dcbf3acd-8a5b-44af-a822-eeb84bad6af3','盤古廟','王十朋','宋','宋诗','song-poetry','','[]','盤古千千古，江頭遺像存。',48,'全唐诗/poet.song.119000.json','["盤古千千古，江頭遺像存。", "伏羲猶後輩，禮殿盡諸孫。", "不屋昔非陋，有祠今未尊。", "東鄰二郎廟，巫覡醉朝昏。"]'),
('2743ef4e-c3bc-484d-86c9-f2b3c84ff540','趙果州之子年十四能作大字果州自荆南以詩寄予命書之字畫老成異日必名家因贈以詩','王十朋','宋','宋诗','song-poetry','','[]','子政平生宜諒聞，故應有子嗣清芬。',64,'全唐诗/poet.song.119000.json','["子政平生宜諒聞，故應有子嗣清芬。", "讀書行見破萬卷，識字豈惟能八分。", "年少便宜觀上國，詩成真可張吾軍。", "校讎異日居天祿，玉葉金枝有子雲。"]'),
('3861109a-2096-49b5-bd7b-6611eb23138f','送如上人  其一','王十朋','宋','宋诗','song-poetry','','[]','蜀道青天不易登，飄然雲水遇鄉僧。',32,'全唐诗/poet.song.119000.json','["蜀道青天不易登，飄然雲水遇鄉僧。", "芒鞋便欲相隨去，身縛粗官愧未能。"]'),
('a9e558a4-740a-44df-b476-7859bcc5479c','送如上人  其二','王十朋','宋','宋诗','song-poetry','','[]','十年作別稽山下，萬里相逢峽水西。',32,'全唐诗/poet.song.119000.json','["十年作別稽山下，萬里相逢峽水西。", "天下名山游已遍，好尋潛澗一枝栖。"]'),
('7c3636cf-f87b-4034-9c1a-b2c7d6d612ea','州宅雜詠 甘露堂','王十朋','宋','宋诗','song-poetry','','[]','昔日賢太守，堂前零露甘。',24,'全唐诗/poet.song.119000.json','["昔日賢太守，堂前零露甘。", "我來無善政，露下亦何堪。"]'),
('fc49e12c-8d1f-4de1-96c3-a6f514f81de4','州宅雜詠 萬卷堂','王十朋','宋','宋诗','song-poetry','','[]','書讀萬卷破，少陵觀國初。',24,'全唐诗/poet.song.119000.json','["書讀萬卷破，少陵觀國初。", "登堂吾有媿，頭白腹空虛。"]'),
('a9b06170-4343-4528-8d89-bde615d53cf1','州宅雜詠 瑞白堂','王十朋','宋','宋诗','song-poetry','','[]','昔日曾夔州，茲堂見三白。',24,'全唐诗/poet.song.119000.json','["昔日曾夔州，茲堂見三白。", "爲瑞不嫌多，年豐最宜麥。"]'),
('78f56e6a-13ac-4af9-8a16-3be22d62c95a','州宅雜詠 詩史堂','王十朋','宋','宋诗','song-poetry','','[]','誰鎸堂上石，光艷少陵章。',24,'全唐诗/poet.song.119000.json','["誰鎸堂上石，光艷少陵章。", "莫作詩人看，斯文似子長。"]'),
