('ca98851e-763b-4410-8857-1b098dde274d','送喻令','王十朋','宋','宋诗','song-poetry','','[]','捫膝先生有鳳毛，三年魚邑試牛刀。',64,'全唐诗/poet.song.119000.json','["捫膝先生有鳳毛，三年魚邑試牛刀。", "要令人被絃歌化，詎肯身辭州縣勞。", "賢令首祠唐質肅，詩篇時出楚風騷。", "西歸更勉家傳學，雲翼行看九萬高。"]'),
('6f753800-1684-4238-9701-6c34e350c5f3','十月九日雪','王十朋','宋','宋诗','song-poetry','','[]','夔子今年雪，初冬已在山。',48,'全唐诗/poet.song.119000.json','["夔子今年雪，初冬已在山。", "峯非是鹽白，鬢不爲詩班。", "寒律三朝後，雷聲八日間。", "潛催子猷棹，乘興早知還。"]'),
('09cd3f9b-392e-428b-b1c0-ab773830b092','食柑','王十朋','宋','宋诗','song-poetry','','[]','蕭山陸橘東坡傳，夔子黄柑老杜詩。',32,'全唐诗/poet.song.119000.json','["蕭山陸橘東坡傳，夔子黄柑老杜詩。", "楚越相望五千里，西州滋味獨濃知。"]'),
('1bb326f8-abe1-49c4-8d61-47f9091effd0','十日買黄菊二株','王十朋','宋','宋诗','song-poetry','','[]','十月更十日，黄花開滿枝。',72,'全唐诗/poet.song.119000.json','["十月更十日，黄花開滿枝。", "鮮鮮如可餐，采采還自疑。", "重陽不堪摘，况後一月期。", "既晚何用好，茲言聞退之。", "天然傲霜性，寧問早與遲。", "不以日月斷，深杯爲花持。"]'),
('75db2252-dee9-4f2a-994e-b03889252c85','采菊圖','王十朋','宋','宋诗','song-poetry','','[]','淵明耻折腰，慨然詠式微。',48,'全唐诗/poet.song.119000.json','["淵明耻折腰，慨然詠式微。", "閑居愛重九，采菊來白衣。", "南山忽在眼，倦鳥亦知歸。", "至今東籬花，清如首陽薇。"]'),
('4322e58d-dc42-4b25-9b01-829a410fe79c','梁彭州歸自道山泝流入峽以二詩見寄因次其韵  其一','王十朋','宋','宋诗','song-poetry','','[]','首遇重華闢四門，郡符帥閫誤蒙恩。',64,'全唐诗/poet.song.119000.json','["首遇重華闢四門，郡符帥閫誤蒙恩。", "路經灧澦少陵鬢，草夢池塘靈運魂。", "馬運敢辭論水陸，兵儲未暇議營屯。", "故人相見談時事，耿耿胸中直氣存。"]'),
('d7e615ea-05c8-46fc-b832-367fb72b87e4','梁彭州歸自道山泝流入峽以二詩見寄因次其韵  其二','王十朋','宋','宋诗','song-poetry','','[]','壯夫白首兩同年，又繼錢塘唱和篇。',64,'全唐诗/poet.song.119000.json','["壯夫白首兩同年，又繼錢塘唱和篇。", "十載音書天上雁，一江風雪峽中船。", "西州賢守得高適，東觀人才推孟堅。", "紫陌曾陪探花馬，姓名深愧在盧前。"]'),
('394e835d-fe36-4798-8081-66941c1576bb','梁彭州與客登卧龍山送酒二尊  其一','王十朋','宋','宋诗','song-poetry','','[]','五馬携壺上卧龍，四夔連騎與游從。',32,'全唐诗/poet.song.119000.json','["五馬携壺上卧龍，四夔連騎與游從。", "山中古柏歲寒色，應爲清流作意濃。"]'),
('10e01245-e6cf-4f72-afd1-51247139e64c','梁彭州與客登卧龍山送酒二尊  其二','王十朋','宋','宋诗','song-poetry','','[]','天祿歸來楊子雲，酒隨後乘爲論文。',32,'全唐诗/poet.song.119000.json','["天祿歸來楊子雲，酒隨後乘爲論文。", "雲安麴米瓶雙玉，聊助詩人作小醺。"]'),
('7d7d9e64-0e6b-4dee-ae93-02cc5cd0a132','閻普州趙果州舟中唱和以巨軸見寄酬以二首  其一','王十朋','宋','宋诗','song-poetry','','[]','聯舟西上沸歡聲，趙璧隋珠照坐明。',64,'全唐诗/poet.song.119000.json','["聯舟西上沸歡聲，趙璧隋珠照坐明。", "一客詞流三峽水，百篇詩壓五言城。", "廣文舊舍欣重掃，阿買奇兒况侍行。", "我以禮賓名客舘，雲安麴米待君傾。"]'),
('71fc2ba5-08a1-46e4-852e-2839a3c1b18c','閻普州趙果州舟中唱和以巨軸見寄酬以二首  其二','王十朋','宋','宋诗','song-poetry','','[]','燈結寒花鵲有聲，書傳雙鯉眼增明。',64,'全唐诗/poet.song.119000.json','["燈結寒花鵲有聲，書傳雙鯉眼增明。", "人言盡是青雲士，天遣相逢白帝城。", "富貴有機端可畏，山川非險莫辭行。", "定知蜀道從今易，東普南充蓋已傾。"]'),
('aff9c6dd-c872-475a-97d3-7f4861cb823f','丙戌冬十月閻惠夫梁子紹得郡還蜀聯舟過夔訪予於郡齋修同年之好也因觀太上皇帝親擢御札及館閣題名感嘆良久輒成惡詩一章以紀陳迹且志吾儕會合之異','王十朋','宋','宋诗','song-poetry','','[]','光堯親擢賜巍科，穅秕居前有媿多。',64,'全唐诗/poet.song.119000.json','["光堯親擢賜巍科，穅秕居前有媿多。", "書向蓬山俱點勘，詩從天竺共吟哦。", "十年尊酒喜身健，五馬人生驚鬢皤。", "握手夔門話疇昔，君恩未報欲如何。"]'),
('9563384d-e6cb-41e4-bf6c-18c75fece9e3','與二同年觀雪於八陣臺果州會焉酌酒論文煮惠山泉瀹建溪茶誦少陵江流石不轉之句復用前韵','王十朋','宋','宋诗','song-poetry','','[]','吾儕風味雅同科，領略江山逸興多。',64,'全唐诗/poet.song.119000.json','["吾儕風味雅同科，領略江山逸興多。", "諸葛陣圖臺上看，少陵詩句酒中哦。", "惠山活水煎茶白，勝己高峯带雪皤。", "絕境况逢三五馬，定將好句壓陰何。"]'),
('bafc4b84-e1f6-40c3-8cfc-fd0147dcaedd','惠夫子紹二同年懷章過夔宗英趙若拙聯舟西上賦詩二首記吾三人會合之異次韵仍簡二同年  其一','王十朋','宋','宋诗','song-poetry','','[]','端似唐人會合年，句追籍徹孟韓聯。',64,'全唐诗/poet.song.119000.json','["端似唐人會合年，句追籍徹孟韓聯。", "朱幡俱任專城寄，白首叨持帥閫權。", "鼎甲豈如天聖榜，宗盟不減德麟賢。", "客真不惡主人惡，勝己山名自古傳。"]'),
('fdd27864-6d74-432e-ad9f-83599f316dc7','惠夫子紹二同年懷章過夔宗英趙若拙聯舟西上賦詩二首記吾三人會合之異次韵仍簡二同年  其二','王十朋','宋','宋诗','song-poetry','','[]','晚菊鮮鮮梅蘂新，天涯對酒忽三人。',64,'全唐诗/poet.song.119000.json','["晚菊鮮鮮梅蘂新，天涯對酒忽三人。", "才高不比丹青相，志大聊爲州縣臣。", "麾把普彭夔子國，榜同詹愈季元賓。", "二公行矣居廊廟，放我江湖作逸民。"]'),
('e061ba57-b209-47a0-acd4-eb208189fe13','與惠夫若拙小酌郡齋再用聯字韵并寄子紹','王十朋','宋','宋诗','song-poetry','','[]','杯盤草草酌同年，更與英英玉葉聯。',64,'全唐诗/poet.song.119000.json','["杯盤草草酌同年，更與英英玉葉聯。", "我輩論交真有道，異時當國願無權。", "策蒙親擢言尤直，召不留中已足賢。", "天遣西來結詩社，郵筒毋惜徃來傳。"]'),
('fa97f4fa-fd7d-44eb-a736-0ca93ca58da2','三友堂','王十朋','宋','宋诗','song-poetry','','[]','丁丑同年友，三人忽此逢。',48,'全唐诗/poet.song.119000.json','["丁丑同年友，三人忽此逢。", "符分俱握虎，簪盍偶成龍。", "撫卷神山遠，銜杯瑞雪濃。", "一壺勝太白，形影月游從。"]'),
('3e335b03-5c3e-47d4-ba82-263efb0da678','生日','王十朋','宋','宋诗','song-poetry','','[]','老遇懸弧旦，天涯把一麾。',48,'全唐诗/poet.song.119000.json','["老遇懸弧旦，天涯把一麾。", "誤蒙崧嶽句，忍誦蓼莪詩。", "節物梅經眼，年華雪上眉。", "兒曾觴壽酒，盡是祝歸期。"]'),
('8ae90566-c0df-40f6-b9ce-d55205aed547','觀畫像','王十朋','宋','宋诗','song-poetry','','[]','似我豈真我，相看還自疑。',48,'全唐诗/poet.song.119000.json','["似我豈真我，相看還自疑。", "陋非臺閣像，高失布韋時。", "吟苦眉常皺，憂多鬢早衰。", "惓惓畎畝志，無復畫師知。"]'),
('80605a07-8cc6-4a9e-a46f-21eef9929f15','杜殿院挽詞  其一','王十朋','宋','宋诗','song-poetry','','[]','流落杜陵老，平生一飯忠。',48,'全唐诗/poet.song.119000.json','["流落杜陵老，平生一飯忠。", "大賢宜有後，異代果生公。", "文艷神藜燭，霜蹄御史驄。", "九原呼不起，蕭瑟柏臺空。"]'),
('db1c3ec7-654f-4e1f-9b85-26532c21da90','杜殿院挽詞  其二','王十朋','宋','宋诗','song-poetry','','[]','親擢逢明主，臺綱振一時。',48,'全唐诗/poet.song.119000.json','["親擢逢明主，臺綱振一時。", "觸真同獬薦，問不到狐狸。", "姦佞已落膽，江湖甘把麾。", "賢哉郭有道，無媿蔡邑碑。"]'),
('9c2a9090-b623-4e89-97ed-c4d4533614b4','杜殿院挽詞  其三','王十朋','宋','宋诗','song-poetry','','[]','我昔游三舘，聞公論立朝。',48,'全唐诗/poet.song.119000.json','["我昔游三舘，聞公論立朝。", "端如平日語，果不小人饒。", "節義真齊固，年齡不逮喬。", "英魂已上天，楚些詎容招。"]'),
('cb6f02bc-ee7b-4605-b503-32301c72c662','會同僚于郡齋煮惠山泉烹建谿茶酌瞿唐春','王十朋','宋','宋诗','song-poetry','','[]','錫泉龍焙忽飛來，春著瞿唐初潑醅。',64,'全唐诗/poet.song.119000.json','["錫泉龍焙忽飛來，春著瞿唐初潑醅。", "腸似玉川堪七碗，興如太白謾三杯。", "月團不許無詩得，霜蘂端因有分開。", "石銚瓦盆吾已具，竹林它日定相陪。"]'),
('8939cc6e-fd94-40b2-901d-d2e41adcd158','同僚和詩復用前韵','王十朋','宋','宋诗','song-poetry','','[]','掃地焚香待客來，煎泉瀹茗漉官醅。',64,'全唐诗/poet.song.119000.json','["掃地焚香待客來，煎泉瀹茗漉官醅。", "相公溪近何曾汲，白帝城寒正可杯。", "江上詩成風葉落，閣中興動雪梅開。", "嘉賓飲散鈴齋靜，月照虛窗有影陪。"]'),
('58429320-b18f-4722-98da-558f1f0d8253','蠟梅','王十朋','宋','宋诗','song-poetry','','[]','天工著意點酡酥，不與江梅鬭雪膚。',64,'全唐诗/poet.song.119000.json','["天工著意點酡酥，不與江梅鬭雪膚。", "露滴蜂房釀崖蜜，日烘龍腦噴金爐。", "萬松張蓋黄尤好，三峽藏春綠不枯。", "題品倘非坡與谷，世人應作小蟲呼。"]'),
('2fdb2cae-4b6e-4ba5-a1b7-d0e638e27c2c','子紹至雲安復和前韵見寄酬以二首  其一','王十朋','宋','宋诗','song-poetry','','[]','細閲皇朝進士科，第三人最得賢多。',64,'全唐诗/poet.song.119000.json','["細閲皇朝進士科，第三人最得賢多。", "不勞則餓天將任，或起而僵帝欲哦。", "舘閣早推仁者勇，廟堂終作國之皤。", "也知有意東山卧，其奈蒼生望子何。"]'),
('781af38a-812e-470c-84af-4fdab43e57da','子紹至雲安復和前韵見寄酬以二首  其二','王十朋','宋','宋诗','song-poetry','','[]','不比求游占一科，無施不可患才多。',64,'全唐诗/poet.song.119000.json','["不比求游占一科，無施不可患才多。", "手持江海一麾去，夢與神仙七字哦。", "客裏有書情愈重，別來多病鬢添皤。", "郡齋獨坐歲華莫，眼見官梅深憶何。"]'),
('d66436ab-c5d9-466c-9b17-9183ae4b169d','趙若拙卓爾不群佳公子也痛親不見名堂曰思諸公爭賦之不鄙予亦以詩命予謂若拙不止乎思也且能顯之作思堂詩','王十朋','宋','宋诗','song-poetry','','[]','天下人子皆思親，思而顯之能幾人。',160,'全唐诗/poet.song.119000.json','["天下人子皆思親，思而顯之能幾人。", "入堂省親親不見，長向羹牆見親面。", "身苟不立名不揚，九原何由發幽光。", "金枝挺挺賢公子，風樹興悲思不已。", "口誦孝經第一篇，立身行道期心傳。", "直諒多聞古三益，標準宗支名籍籍。", "前日召還胡不留，一麾出守西南州。", "官職人心所同欲，孝子思親恐親辱。", "不獨思親能顯親，孔門曾子君前身。", "我愧思親未能顯，詩作思堂涕徒泫。"]'),
('a086ecfd-bfe8-42e3-885d-52ad10f4abca','題朱鈐幹灝無喧室','王十朋','宋','宋诗','song-poetry','','[]','雅抱淵明尚，處喧思避喧。',48,'全唐诗/poet.song.119000.json','["雅抱淵明尚，處喧思避喧。", "門雖有車馬，趣不異丘園。", "仁者本來靜，時然應亦言。", "端能重吾幕，無復擾爲煩。"]'),
('1384ceaf-4891-40d0-b38e-3f674ccce287','糟蟹薦杯','王十朋','宋','宋诗','song-poetry','','[]','麴生有理何曾濁，公子無腸却最佳。',32,'全唐诗/poet.song.119000.json','["麴生有理何曾濁，公子無腸却最佳。", "羅饌寧同富兒飲，带糟聊慰老饕懷。"]'),
('88aa7e08-aa03-487d-9e8b-e65300403754','至日寄二弟','王十朋','宋','宋诗','song-poetry','','[]','雲物書何處，山城白帝旁。',48,'全唐诗/poet.song.119000.json','["雲物書何處，山城白帝旁。", "鬢絲驚漸短，日線喜初長。", "江冷魚思復，陽回雁戀行。", "小舟吾已具，命下即還鄉。"]'),
('01834920-6ab8-470e-89ba-4453a0561a94','懷二叔','王十朋','宋','宋诗','song-poetry','','[]','二叔年高甚，天涯姪未歸。',48,'全唐诗/poet.song.119000.json','["二叔年高甚，天涯姪未歸。", "一陽雲物動，三峽夢魂飛。", "丈室懷明慶，巍樓上靜暉。", "皇恩許歸去，行矣叩林扉。"]'),
('e09014f7-677f-4147-89dc-fddeeb0d4607','連日鵲喜東歸之祥也詩寄二弟','王十朋','宋','宋诗','song-poetry','','[]','烏鵲枝頭竟日喧，皇恩應許返丘園。',64,'全唐诗/poet.song.119000.json','["烏鵲枝頭竟日喧，皇恩應許返丘園。", "荒蕪賦就同元亮，歡喜詩成異審言。", "定有好音來象闕，媿無遺愛在夔門。", "寄書預報梅溪弟，灑掃吾廬辦酒尊。"]'),
('757f0e62-2f88-459e-a043-3f7abe11c75c','白雲樓赴周漕飯追念行可','王十朋','宋','宋诗','song-poetry','','[]','不到西臺久，傷心憶舊游。',48,'全唐诗/poet.song.119000.json','["不到西臺久，傷心憶舊游。", "水流猶故沼，雲散只空樓。", "丹荔誰祠柳，清齋不對周。", "徘徊賦詩處，淚下莫能收。"]'),
('f1383845-2bde-470b-8850-805f5a90005d','哭陳阜卿  其一','王十朋','宋','宋诗','song-poetry','','[]','槐市聲名早，儒林行藝尊。',48,'全唐诗/poet.song.119000.json','["槐市聲名早，儒林行藝尊。", "麟經無絕學，烏府有危言。", "半歲甘泉橐，頻年刺史幡。", "凄凉道山舊，今日幾人存。"]'),
('82b89796-ce75-4d7a-a09c-e16fe51976d9','哭陳阜卿  其二','王十朋','宋','宋诗','song-poetry','','[]','識面登瀛日，論心去國時。',48,'全唐诗/poet.song.119000.json','["識面登瀛日，論心去國時。", "孟軻非好辯，羊祜有先知。", "手筆今文伯，神明古吏師。", "老成嗟不見，流淚讀招詞。"]'),
('2d9904f1-9b5f-43af-bc42-79c626641d18','哭陳阜卿  其三','王十朋','宋','宋诗','song-poetry','','[]','我守鄱君國，公時帥豫章。',48,'全唐诗/poet.song.119000.json','["我守鄱君國，公時帥豫章。", "詩筒續元白，治境接龔黄。", "流落來夔子，傳聞侍玉皇。", "北門方卧護，帝忽遣巫陽。"]'),
('bac0c160-4937-4b61-8cff-2b666efe9e5c','哭陳阜卿  其四','王十朋','宋','宋诗','song-poetry','','[]','邸報知凶訃，傷心不忍言。',48,'全唐诗/poet.song.119000.json','["邸報知凶訃，傷心不忍言。", "圖猶對徐孺，人已喪陳蕃。", "杖屨欲三徑，衣冠俄九原。", "數行嬴博淚，瞑目有餘痕。"]'),
('42d435df-f593-428b-a126-16972911f7e6','夢人贈范文正公集','王十朋','宋','宋诗','song-poetry','','[]','平生敬慕范文正，遺像向來祠楚東。',32,'全唐诗/poet.song.119000.json','["平生敬慕范文正，遺像向來祠楚東。", "夢裏何人贈文集，見公端似見周公。"]'),
('8fc83903-6eff-4798-bc62-05f1a21395af','食筍  其一','王十朋','宋','宋诗','song-poetry','','[]','篔簹又復長纖纖，頭角猶藏味已甜。',32,'全唐诗/poet.song.119000.json','["篔簹又復長纖纖，頭角猶藏味已甜。", "吾友子脩三載別，不知稚子幾根添。"]'),
('0c16a455-5ca3-4aa5-a940-2a43c524ad1c','食筍  其二','王十朋','宋','宋诗','song-poetry','','[]','著庭食筍記當年，屈指交游半鬼仙。',32,'全唐诗/poet.song.119000.json','["著庭食筍記當年，屈指交游半鬼仙。", "謹護籜龍無恙否，得時張主想參天。"]'),
('b0521d67-4615-484e-97e3-1ca754d62f99','食筍  其三','王十朋','宋','宋诗','song-poetry','','[]','夔門雪裏竹萌抽，味占盤餐第一流。',32,'全唐诗/poet.song.119000.json','["夔門雪裏竹萌抽，味占盤餐第一流。", "深憶江西陳仲舉，如今無復寄貓頭。"]'),
('18a985c9-3053-47c9-9e81-a8e291d8666a','寇萊公取韋蘇州野渡無人舟自橫之句增爲十字見于曾南豐所作公傳則知前輩作詩一言一句皆有來歷予用其說爲巴東詞記有新進士作詩云語當人意爲佳句何與韋郎野渡舟用其以解嘲','王十朋','宋','宋诗','song-poetry','','[]','野水再經吟咏手，一般景象兩般舟。',32,'全唐诗/poet.song.119000.json','["野水再經吟咏手，一般景象兩般舟。", "萊公相業韋郎句，付與詩人子細搜。"]'),
('fd54df6b-939c-4e8f-bc26-53a6602b162e','夔硯','王十朋','宋','宋诗','song-poetry','','[]','一片夔州硯，千年禹鑿痕。',48,'全唐诗/poet.song.119000.json','["一片夔州硯，千年禹鑿痕。", "平公見爾祖，王子得其孫。", "銅雀今安有，羅文世所尊。", "聊同玄穎輩，文字與吾論。"]'),
('190ba546-035c-44fe-aa4f-e4111cef799a','聞韶美侍郎易任廣漢  其一','王十朋','宋','宋诗','song-poetry','','["\u897f\u6e56"]','帝眷甘泉舊，綸恩換虎符。',48,'全唐诗/poet.song.119000.json','["帝眷甘泉舊，綸恩換虎符。", "神應馳北闕，眼已見西湖。", "霖雨思賢甚，仙槎到漢無。", "書梁形夢寐，大厦待公扶。"]'),
('b1b6ad7d-2b64-4aa0-841d-507760e0ed82','聞韶美侍郎易任廣漢  其二','王十朋','宋','宋诗','song-poetry','','[]','書欲臨邛去，公俄廣漢行。',48,'全唐诗/poet.song.119000.json','["書欲臨邛去，公俄廣漢行。", "湖欣遇房相，詩擬和劉兄。", "爲郡人生貴，還鄉晝錦榮。", "無從陪杖屨，老我欲歸耕。"]'),
('dc597f53-a7b8-44f0-8731-3ce908a476d7','臘日與同官小集八陣臺觀武侯新祠','王十朋','宋','宋诗','song-poetry','','[]','伏幾何時臘又逢，天涯尊酒記游從。',64,'全唐诗/poet.song.119000.json','["伏幾何時臘又逢，天涯尊酒記游從。", "未於山下祠黄石，且向江濆謁卧龍。", "青眼共看官舍柳，白頭相對雪天峯虎。", "符願逐桃符換，萬里歸心一片濃。"]'),
('8645c6aa-9b79-4714-97ec-f03f8974ab92','梅雪','王十朋','宋','宋诗','song-poetry','','[]','同僚文字三杯酒，臘日江山八陣臺。',32,'全唐诗/poet.song.119000.json','["同僚文字三杯酒，臘日江山八陣臺。", "冷有人嫌吾似雪，清無塵染客如梅。"]'),
('749eb5c8-8e62-40e8-9917-061ef4b4ba3a','十八日迓虞參政于西城竹亭去歲亦以此日送之','王十朋','宋','宋诗','song-poetry','','[]','兩年此日此江濱，又迓向來歸去賓。',32,'全唐诗/poet.song.119000.json','["兩年此日此江濱，又迓向來歸去賓。", "兀坐茅亭竹應笑，林間不著送迎人。"]'),
('8315c8d0-db35-40ee-bb1f-6ca892f78aad','讀東坡詩','王十朋','宋','宋诗','song-poetry','','[]','東坡文章冠天下，日月爭光薄風雅。',336,'全唐诗/poet.song.119000.json','["東坡文章冠天下，日月爭光薄風雅。", "誰分宗派故謗傷，蚍蜉撼樹不自量。", "堂堂天人歐陽子，引鞭遜避門下士。", "天昌斯文大才出，先生弟子俱第一。", "天人詩如李謫仙，此論最公誰不然。", "詞無艱深非淺近，章成韵盡意不盡。", "味長何止飛鳥驚，臆說紛紛幾元稹。", "渾然天成無斧鑿，二百年來無此作。", "誰與爭先惟大蘇，謫仙退之非過呼。", "胸中萬卷古今有，筆下一點塵埃無。", "武庫森然富摛掞，利鈍一從人點檢。", "莫年海上詩更高，和陶之詩又過陶。", "地闢天開含萬彙，少陵相逢亦應避。", "北斗以南能幾人，大江之西有異議。", "日光玉潔一退之，亦言能文不能詩。", "碑淮頌聖十琴操，生民清廟離騷詞。", "舂容大篇騁豪怪，韵到窘束尤瑰奇。", "韓子於詩蓋餘事，詩至韓子將何譏。", "文章定價如金玉，口爲輕重專門學。", "向來學者尊西昆，詩無老杜文無韓。", "凈掃書齋拂塵几，瓣香敬爲三夫子。"]'),
('c7d826ca-f3d2-4a3b-b702-5f8927e0ea96','除日','王十朋','宋','宋诗','song-poetry','','[]','蝸舍三年別，夔門兩歲除。',48,'全唐诗/poet.song.119000.json','["蝸舍三年別，夔門兩歲除。", "盆雖具肴簌，儺不是鄉閭。", "櫪馬喧新集，桃符換舊書。", "何如杜陵老，守歲阿咸居。"]'),
('8da87b76-e209-4f1d-8643-5d0214569c45','元日','王十朋','宋','宋诗','song-poetry','','[]','元日年年見，天涯意故長。',48,'全唐诗/poet.song.119000.json','["元日年年見，天涯意故長。", "詩篇示宗武，春色酌瞿唐。", "白髮又新歲，黄甘非故鄉。", "弟兄團拜處，歸去願成行。"]'),
('498789f9-24fd-4ac2-8ded-ec9d544b3740','趙果州送黄柑金泉酒','王十朋','宋','宋诗','song-poetry','','[]','元日書來自果州，柑三百顆酒新蒭。',64,'全唐诗/poet.song.119000.json','["元日書來自果州，柑三百顆酒新蒭。", "賢於齊下六從事，好似平陽千戶侯。", "老矣惟思醉鄉去，歸歟且種木奴休。", "使君厚意吾先辱，媿乏瓊瑶報所投。"]'),
('2d22022a-cce9-4f19-b7b1-4dde35206154','四日雪坐間有江梅水仙花因目曰三白 梅花','王十朋','宋','宋诗','song-poetry','','[]','孤標相對楚天涯，寒不能威意自佳。',32,'全唐诗/poet.song.119000.json','["孤標相對楚天涯，寒不能威意自佳。", "消得廣平公援筆，此花真是鐵心花。"]'),
('eccfeeb4-4d0f-4d26-b837-e4b7d8a9cf23','四日雪坐間有江梅水仙花因目曰三白 水仙花','王十朋','宋','宋诗','song-poetry','','[]','葉抽書带秀文房，玉表黄中耐雪霜。',32,'全唐诗/poet.song.119000.json','["葉抽書带秀文房，玉表黄中耐雪霜。", "得水成仙最風味，與梅爲弟各芬香。"]'),
('04e1e96c-dee0-481c-9072-747ebf09dbf7','四日雪坐間有江梅水仙花因目曰三白 雪','王十朋','宋','宋诗','song-poetry','','[]','不來平地只山巔，端爲民貧故見憐。',32,'全唐诗/poet.song.119000.json','["不來平地只山巔，端爲民貧故見憐。", "未到立春猶臘月，忽成三白定豐年。"]'),
('5dc9224e-c5f8-4cf9-b4b3-b9533fa6c02b','人日游磧','王十朋','宋','宋诗','song-poetry','','[]','好遨蜀風俗，夔人貧亦遨。',48,'全唐诗/poet.song.119000.json','["好遨蜀風俗，夔人貧亦遨。", "今日日爲人，傾城出江皐。", "遨頭老病守，呼賓酌春醪。", "歸來及初鼓，繁燈照霜毛。"]'),
('6e88d58e-9449-4869-9149-a72b771fa136','穀日立春','王十朋','宋','宋诗','song-poetry','','[]','穀日逢春日，江天弄佳氣。',48,'全唐诗/poet.song.119000.json','["穀日逢春日，江天弄佳氣。", "蔬盆雜蒿韭，一箸異鄉味。", "西疇農事動，問我歸何未。", "豈無二頃田，奚用五馬貴。"]'),
('342a4ba2-5c98-41cd-bbe4-1ceb38e2251d','雙鵲','王十朋','宋','宋诗','song-poetry','','[]','雙鵲喳喳首向東，似將喜報主人公。',32,'全唐诗/poet.song.119000.json','["雙鵲喳喳首向東，似將喜報主人公。", "主人只欲東歸去，歸作左原田舍翁。"]'),
('fa58c4eb-c63a-47e7-a2cf-0692d297eef8','王撫幹贈蘇黄真蹟酬以建茶','王十朋','宋','宋诗','song-poetry','','[]','蘇黄文章外，翰墨亦莫加。',120,'全唐诗/poet.song.119000.json','["蘇黄文章外，翰墨亦莫加。", "蘇得魯公法，黄自成一家。", "肥無塵俗點，瘦或風雨斜。", "可愛如其人，敬之無邇遐。", "真蹟落人間，蔀屋生光華。", "我無一字藏，天遣來三巴。", "吾宗東州秀，文翰俱可嘉。", "袖中出至寶，雙眸洗昏花。", "歸橐今不貧，持往東南誇。", "何以報嘉貺，龍團建溪芽。"]'),
('14eaf05a-c6a2-4dad-9c60-2780e5409128','予雪詩云不來平地只山巔朱鈐幹和云不能下乞俗人憐志在潔己陳知錄云只可在山如去年志在卹民王撫幹云散作人間大有年志在潤物三子之志雖不同皆可嘉也各用其句作三絕以贈之又以一絕自貺 贈鈐幹','王十朋','宋','宋诗','song-poetry','','[]','無喧室對山頭雪，雪照無喧室湛然。',32,'全唐诗/poet.song.119000.json','["無喧室對山頭雪，雪照無喧室湛然。", "高潔似人人亦似，不能下乞俗人憐。"]'),
('bf980e2a-f5e4-435f-b572-faf46e52b195','予雪詩云不來平地只山巔朱鈐幹和云不能下乞俗人憐志在潔己陳知錄云只可在山如去年志在卹民王撫幹云散作人間大有年志在潤物三子之志雖不同皆可嘉也各用其句作三絕以贈之又以一絕自貺 贈知錄','王十朋','宋','宋诗','song-poetry','','[]','不道世人貧可憐，亂飄宇宙濕厨烟。',32,'全唐诗/poet.song.119000.json','["不道世人貧可憐，亂飄宇宙濕厨烟。", "居高潤下澤自普，只可在山如去年。"]'),
('2819ab60-4450-4585-9cfa-d2c89d240be5','予雪詩云不來平地只山巔朱鈐幹和云不能下乞俗人憐志在潔己陳知錄云只可在山如去年志在卹民王撫幹云散作人間大有年志在潤物三子之志雖不同皆可嘉也各用其句作三絕以贈之又以一絕自貺 贈撫幹','王十朋','宋','宋诗','song-poetry','','[]','時哉臘後立春前，散作人間大有年。',32,'全唐诗/poet.song.119000.json','["時哉臘後立春前，散作人間大有年。", "會合風雲灑天外，不須只在蜀山川。"]'),
('9e2c246e-cb83-4e0d-be47-739114f0f5b2','予雪詩云不來平地只山巔朱鈐幹和云不能下乞俗人憐志在潔己陳知錄云只可在山如去年志在卹民王撫幹云散作人間大有年志在潤物三子之志雖不同皆可嘉也各用其句作三絕以贈之又以一絕自貺 自况','王十朋','宋','宋诗','song-poetry','','[]','在地在山無不可，去年今年同不同。',32,'全唐诗/poet.song.119000.json','["在地在山無不可，去年今年同不同。", "銀杯縞带逐車馬，何似蓑笠隨漁翁。"]'),
('e554816f-9ea1-45ca-a683-18e77c0656dc','春雪','王十朋','宋','宋诗','song-poetry','','[]','立春三日餘，霏霏下人間。',120,'全唐诗/poet.song.119000.json','["立春三日餘，霏霏下人間。", "胡不瑞嘉平，天於此偏慳。", "忽從何處來，頃刻堆塵寰。", "投隙妙能入，遇圓巧成環。", "侵凌到肌骨，點綴生容顔。", "凝積遽如許，掃除良亦艱。", "牧羊念大窖，擁馬愁藍關。", "我時巴峽觀，眩晃迷江山。", "認峯失白鹽，問俗非烏蠻。", "豈無興可乘，扁舟正宜還。"]'),
('21abfcab-de05-4347-8e66-740720853aaa','十四日登真武山  其一','王十朋','宋','宋诗','song-poetry','','[]','山中松柏幾經春，壁上龜蛇妙入神。',32,'全唐诗/poet.song.119000.json','["山中松柏幾經春，壁上龜蛇妙入神。", "羽士相看笑相語，使君老似去年人。"]'),
('56ce1baa-8911-4695-9e83-1495e2d7182b','十四日登真武山  其二','王十朋','宋','宋诗','song-poetry','','[]','白鹽卓立群峯外，真武山頭平視之。',32,'全唐诗/poet.song.119000.json','["白鹽卓立群峯外，真武山頭平視之。", "試上白鹽峯頂望，未知真武孰高卑。"]'),
('9a12a7d8-2055-42a4-9323-e8732d3551b3','十四日登真武山  其三','王十朋','宋','宋诗','song-poetry','','[]','瑩煌燈火如星斗，夜夜人間望此山。',32,'全唐诗/poet.song.119000.json','["瑩煌燈火如星斗，夜夜人間望此山。", "來向元宵試燈火，却移星斗下人間。"]'),
('a445edec-1854-4939-83fa-8d9d737d776b','禿筆','王十朋','宋','宋诗','song-poetry','','[]','管城人已老，後輩頗相侵。',24,'全唐诗/poet.song.119000.json','["管城人已老，後輩頗相侵。", "問汝中書否，猶言欲盡心。"]'),
('6e686f60-dd8d-4b25-86e5-a6cf6c98a185','二月朔日詣學講堂前杏花正開呈教授','王十朋','宋','宋诗','song-poetry','','[]','孔壇昔栽杏，魯人呼東家。',120,'全唐诗/poet.song.119000.json','["孔壇昔栽杏，魯人呼東家。", "當時三千株，化工無等差。", "雩風長其實，教雨濯其葩。", "木與聖化俱，芬芳無邇遐。", "數株能白紅，開向天之涯。", "况於芹藻間，相看意殊嘉。", "對之懷哲人，甘棠何以加。", "不比曲江春，祇名及第花。", "又異仙家桃，徒爾蒸紅霞。", "願言廣對殖，夔魯同光華。"]'),
('8b56e5d1-e109-4464-867d-585a1fee1cf0','泮宮杏花乃閻紫微爲教官時所殖復用前韵','王十朋','宋','宋诗','song-poetry','','[]','同年紫微公，昔游帝王家。',120,'全唐诗/poet.song.119000.json','["同年紫微公，昔游帝王家。", "穿楊百步間，妙不毫釐差。", "桂窟擢高枝，杏園賞仙葩。", "手移曲江根，不憚川塗遐。", "翺翔夫子壇，栽植泮水涯。", "花好實亦成，諸公欣拜嘉。", "我來節中和，數樹紅交加。", "不見紫微郎，如對紫微花。", "滿堂爛銀袍，賦詩麗綺霞。", "大勝瓜李桃，欲報無瓊華。"]'),
('d63b8ed6-55fb-4147-b879-618f36c5133a','甘露堂前有杏花一株在脩竹之外殊有風味用昌黎韵','王十朋','宋','宋诗','song-poetry','','[]','桃李未吐梅英空，杏花嫣然作小紅。',160,'全唐诗/poet.song.119000.json','["桃李未吐梅英空，杏花嫣然作小紅。", "孤城絕塞也不惡，一株綽有仙家風。", "高枝半出脩竹外，醉臉略與江梅同。", "夔州花木不多有，封殖嘉樹知誰功。", "春光忽到刺史宅，天氣正在中和中。", "不同浪蘂落瘴霧，自有甘露滋芳叢。", "我來歲律驚兩換，歸興遥指吳江楓。", "曲江往事何足夢，願爲老圃安吾窮。", "明年花開我何處，小園數畆簫臺東。", "蒼蒼烟雨記巫峽，酣酣詩句吟梅翁。"]'),
('ec0861d5-83a8-4fcb-9f82-5531478a2e34','送王撫幹行甫','王十朋','宋','宋诗','song-poetry','','[]','之子來夔子，春江又綠波。',48,'全唐诗/poet.song.119000.json','["之子來夔子，春江又綠波。", "分符慚政拙，贊畫頼才多。", "翰墨妙揮染，詞章工琢磨。", "扁舟先吾去，送別奈愁何。"]'),
('cf9b1001-0957-44a2-98bb-a7557ba1f15e','郡圃無海棠買數根殖之','王十朋','宋','宋诗','song-poetry','','[]','少陵詩史有遺闕，海棠名花輒湮沒。',240,'全唐诗/poet.song.119000.json','["少陵詩史有遺闕，海棠名花輒湮沒。", "孤芳千載逢蘇仙，竹籬一笑嫣然發。", "我從蜀錦亭邊來，遥入蒼蒼烟雨窟。", "綺霞曉抹神女肌，香醪春醉明妃骨。", "鮮鮮絲蘂垂更嫋，點點燕脂勻未歇。", "半含欲吐不勝情，沐露梳風睡明月。", "爲開酒尊苦多病，欲挿一枝羞白髮。", "照眼千株未觀蜀，回首十年深憶越。", "何人好事呼名友，姚魏不容矜閥閲。", "凝香有地胡不植，負郭無園何處謁。", "不煩飛鵠銜子來，自買芳根带花掘。", "明年高堂來燕子，想見繁紅映林樾。", "栽花老守在何許，雁蕩山中采薇蕨。", "憑誰爲問花消息，有夢遥驚山突兀。", "自慙不是召伯棠，那得詩人歌勿伐。"]'),
('251522be-ca29-47e8-9a7a-ede3ecb9525a','哭純老','王十朋','宋','宋诗','song-poetry','','[]','忽得潛澗書，驚聞壽山死。',120,'全唐诗/poet.song.119000.json','["忽得潛澗書，驚聞壽山死。", "開書未終讀，老淚灑盈紙。", "壽山僧中傑，蕭灑如晉人。", "識高行孤潔，匈無一點塵。", "少年走江湖，叢林參大士。", "莫年住甌閩，道價高遠邇。", "桑下不留戀，急流猛抽身。", "我欲掛衣冠，歸歟遠公親。", "遽聞新塔成，已葬堅固子。", "無由訪圓澤，空對瞿唐水。"]'),
('f711b327-fd0e-4f75-812c-be90d2df3a3d','次韵喻叔奇松竹圖','王十朋','宋','宋诗','song-poetry','','[]','只應王子猷相愛，未許秦皇帝可親。',32,'全唐诗/poet.song.119000.json','["只應王子猷相愛，未許秦皇帝可親。", "畫我同年作三友，歲寒節操宰官身。"]'),
('685a7014-2654-413c-bfe4-197eb8d7a40a','寄巫山圖與林致一喻叔奇  其一','王十朋','宋','宋诗','song-poetry','','[]','圖畫巫山十二峯，緘題遥寄舊游從。',32,'全唐诗/poet.song.119000.json','["圖畫巫山十二峯，緘題遥寄舊游從。", "煩君子細看山色，不似老夫歸意濃。"]'),
('4b7fb984-b588-4ec9-8c18-3d5748d3ad1e','寄巫山圖與林致一喻叔奇  其二','王十朋','宋','宋诗','song-poetry','','[]','數千里外共明月，十二峯頭望故鄉。',32,'全唐诗/poet.song.119000.json','["數千里外共明月，十二峯頭望故鄉。", "我對此山無夢寐，夢魂只在雁山傍。"]'),
('a67934e0-7c85-4dd3-bf19-caef58271645','夔路十賢 屈大夫','王十朋','宋','宋诗','song-poetry','','[]','大夫楚忠臣，哀哉以讒逐。',24,'全唐诗/poet.song.119000.json','["大夫楚忠臣，哀哉以讒逐。", "遺廟大江濆，醒清今古獨。"]'),
('318cd963-5bec-4c98-8918-c6e0c9a7b083','夔路十賢 嚴刺史','王十朋','宋','宋诗','song-poetry','','[]','將軍頭可斷，詎肯以城降。',24,'全唐诗/poet.song.119000.json','["將軍頭可斷，詎肯以城降。", "斯可爲忠矣，至今名此邦。"]'),
('3e377bd7-8e24-4e06-8e9f-118d3b1e2a25','夔路十賢 諸葛武侯','王十朋','宋','宋诗','song-poetry','','[]','卧龍起南陽，不爲鼎一足。',24,'全唐诗/poet.song.119000.json','["卧龍起南陽，不爲鼎一足。", "託名蜀丞相，相漢非相蜀。"]'),
('ce7d11e6-186e-4268-a6df-f0afd97b4c64','夔路十賢 少陵先生','王十朋','宋','宋诗','song-poetry','','[]','子美稷禼志，空抱竟無用。',24,'全唐诗/poet.song.119000.json','["子美稷禼志，空抱竟無用。", "夔州三百篇，高配風雅頌。"]'),
('054e1a05-7d7d-4241-acbe-c06222095a0d','夔路十賢 陸宣公','王十朋','宋','宋诗','song-poetry','','[]','敬輿避讒謗，閉門不著書。',24,'全唐诗/poet.song.119000.json','["敬輿避讒謗，閉門不著書。", "活人集名方，炳然仁誼餘。"]'),
('90dd0d94-bd7c-4026-9497-2674e77d6fa3','夔路十賢 韋丞相','王十朋','宋','宋诗','song-poetry','','[]','韋侯守盛山，賦詩十二首。',24,'全唐诗/poet.song.119000.json','["韋侯守盛山，賦詩十二首。", "能以堯事君，遂令詩不朽。"]'),
('1472bfb3-342a-4d6c-9fa8-fb8590734084','夔路十賢 白文公','王十朋','宋','宋诗','song-poetry','','[]','賦詠窮三峽，樂天在忠州。',24,'全唐诗/poet.song.119000.json','["賦詠窮三峽，樂天在忠州。", "苟不以直道，亦如元與劉。"]'),
('02881235-06cf-43fa-883e-83463d02346c','夔路十賢 柳文公','王十朋','宋','宋诗','song-poetry','','[]','柳公本書生，忠勇著岳鄂。',24,'全唐诗/poet.song.119000.json','["柳公本書生，忠勇著岳鄂。", "盛山戮姦吏，餘威震夷落。"]'),
('8f550922-9474-4442-801b-93ebc0f7b189','夔路十賢 寇萊公','王十朋','宋','宋诗','song-poetry','','[]','萊公經濟業，志在巴東詩。',24,'全唐诗/poet.song.119000.json','["萊公經濟業，志在巴東詩。", "斯人不復見，亭上秋風悲。"]'),
('c0dcb314-d922-4838-a785-37222c85df6d','夔路十賢 唐質肅公','王十朋','宋','宋诗','song-poetry','','[]','子方筮仕初，牛刀割魚復。',24,'全唐诗/poet.song.119000.json','["子方筮仕初，牛刀割魚復。", "一朝峩廌冠，風采百僚肅。"]'),
('747704d3-6491-4ccf-8f63-2906660b0915','續訪得七人 宋大夫','王十朋','宋','宋诗','song-poetry','','[]','述志哀正則，陳詞諷靈脩。',24,'全唐诗/poet.song.119000.json','["述志哀正則，陳詞諷靈脩。", "讀君九辨章，悲楚非悲秋。"]'),
('b3ae9458-04f9-4eb6-aec2-82bc610c284c','續訪得七人 源丞相','王十朋','宋','宋诗','song-poetry','','[]','傑人掾夔子，相業光開元。',24,'全唐诗/poet.song.119000.json','["傑人掾夔子，相業光開元。", "故宅半赤甲，荒凉今不存。"]'),
('f192a08c-1181-46c2-a383-30a7de623c57','續訪得七人 李左相','王十朋','宋','宋诗','song-poetry','','[]','罷相避同列，銜杯樂聖人。',24,'全唐诗/poet.song.119000.json','["罷相避同列，銜杯樂聖人。", "那知偃月堂，中有丞相瞋。"]'),
('2c0e29e1-f004-4988-9c67-f62b6084c243','續訪得七人 李丞相','王十朋','宋','宋诗','song-poetry','','[]','公在忠州日，人高長者風。',24,'全唐诗/poet.song.119000.json','["公在忠州日，人高長者風。", "忮心無後段，寧媿賛皇公。"]'),
('c1b93d2b-9f8e-4ba9-973e-05ca00e6a535','續訪得七人 溫御史','王十朋','宋','宋诗','song-poetry','','[]','誰坐綉衣石，曾落金吾膽。',24,'全唐诗/poet.song.119000.json','["誰坐綉衣石，曾落金吾膽。", "不戮擁靴人，至今有餘憾。"]'),
('104cfdec-900d-46d9-990f-c8f640674847','續訪得七人 程伊川','王十朋','宋','宋诗','song-poetry','','[]','軻伋誠明學，弟兄傳以心。',24,'全唐诗/poet.song.119000.json','["軻伋誠明學，弟兄傳以心。", "易微於九師，閉門自鈎深。"]'),
('2691ec97-dbf8-4419-b070-09177a313571','續訪得七人 黄太史','王十朋','宋','宋诗','song-poetry','','[]','豫章官逸遠，直筆非謗史。',24,'全唐诗/poet.song.119000.json','["豫章官逸遠，直筆非謗史。", "天遣來黔涪，詩鳴配子美。"]'),
('32438f81-0014-41fb-8455-ebd71ccb02df','柏架','王十朋','宋','宋诗','song-poetry','','[]','青銅柯葉勝杉松，带得清風下卧龍。',32,'全唐诗/poet.song.119000.json','["青銅柯葉勝杉松，带得清風下卧龍。", "日莫微凉起高架，移牀却扇坐從容。"]'),
('5db5a8e1-d9d9-44fb-93a9-bf6f2d18029a','次韵林江州題高遠亭','王十朋','宋','宋诗','song-poetry','','[]','眼明廬阜翠橫空，疑是雲頭屹夏峯。',64,'全唐诗/poet.song.119000.json','["眼明廬阜翠橫空，疑是雲頭屹夏峯。", "遺迹君應懷聖治，故家我亦念歸宗。", "遥瞻瀑水三千尺，猶隔巫山十二重。", "亭上主人高更遠，天然丘壑在心匈。"]'),
('06499cf5-3f81-40c7-a417-092bbf9a39c3','登制勝樓','王十朋','宋','宋诗','song-poetry','','[]','梁棟翬飛百尺樓，江山滿目壯夔州。',64,'全唐诗/poet.song.119000.json','["梁棟翬飛百尺樓，江山滿目壯夔州。", "鳥穿雲過白鹽去，魚透浪來清瀼游。", "控扼地臨三峽險，朝宗水會百川流。", "古今制勝人何勝，天下奇才忠武侯。"]'),
('caeae750-7fa8-424d-8c61-d082dd618f79','再用前韵','王十朋','宋','宋诗','song-poetry','','[]','下視瞿唐縹渺樓，規模雄壓十三州。',64,'全唐诗/poet.song.119000.json','["下視瞿唐縹渺樓，規模雄壓十三州。", "良籌合向暇時運，緩带宜來高處游。", "列障四時環坐好，大江千古抱城流。", "後山植木成陰日，誰識十年前故侯。"]'),
('d9e48b5c-05b9-4eb0-8ef9-6c7fc8253ae1','送宋山甫知縣','王十朋','宋','宋诗','song-poetry','','[]','君住眉山我永嘉，老來邂逅楚天涯。',64,'全唐诗/poet.song.119000.json','["君住眉山我永嘉，老來邂逅楚天涯。", "無詩不和已成杜，有酒相呼如在家。", "官職未高名滿蜀，人才如許邑爲巴。", "且將異日作霖手，潤澤河陽一縣花。"]'),
('2e3d2df5-224f-48e6-ac78-9289b22dedaa','六月一日','王十朋','宋','宋诗','song-poetry','','[]','天涯逢六月，深憶別家時。',48,'全唐诗/poet.song.119000.json','["天涯逢六月，深憶別家時。", "行也亦云遠，歸歟何太遲。", "殊方最炎熱，多病想扶持。", "天遣西來意，端令啖荔枝。"]'),
('9ead1524-ea3a-4447-b2c3-fb1949d86a79','食荔枝  其一','王十朋','宋','宋诗','song-poetry','','[]','荔枝初熟飣金盆，手擘輕紅子細看。',32,'全唐诗/poet.song.119000.json','["荔枝初熟飣金盆，手擘輕紅子細看。", "風味由來太奇絕，不教容易到長安。"]'),
('cebc2bb8-8a6a-421b-a8f8-1e8b02b0edab','食荔枝  其二','王十朋','宋','宋诗','song-poetry','','[]','妃子園中荔子奇，莫因名號起猜疑。',32,'全唐诗/poet.song.119000.json','["妃子園中荔子奇，莫因名號起猜疑。", "清時入坐非尤物，一洗烟塵頼好詩。"]'),
('3f453aaa-3c4d-44d3-b3da-c030ba4e6160','食荔枝  其三','王十朋','宋','宋诗','song-poetry','','[]','詩史堂前種幾時，輕紅曾入少陵詩。',32,'全唐诗/poet.song.119000.json','["詩史堂前種幾時，輕紅曾入少陵詩。", "殊方競續櫻桃獻，萬樹爭先爾獨遲。"]'),
('fa700ba2-ad99-490a-ac4d-5b186677ca58','拾荔枝核欲種之戲成一首','王十朋','宋','宋诗','song-poetry','','[]','海味正思瑶柱美，夔門又見荔枝紅。',64,'全唐诗/poet.song.119000.json','["海味正思瑶柱美，夔門又見荔枝紅。", "炎方入貢自妃子，郡圃欲栽如白公。", "官滿猶爲十年計，實成須待二星終。", "不須更論何時喫，前種後收人我同。"]'),
('3e0ca070-fde6-4d26-a876-8e2d04a65176','幼女生日','王十朋','宋','宋诗','song-poetry','','[]','林鍾蓂四莢，吾女此時生。',48,'全唐诗/poet.song.119000.json','["林鍾蓂四莢，吾女此時生。", "日向炎天永，月從前夜明。", "提携仰慈母，教誨頼諸兄。", "願汝康而壽，人如少藴清。"]'),
('6bdb731f-2b9a-46a9-bccf-46f2637162b6','詩史堂荔枝歌','王十朋','宋','宋诗','song-poetry','','[]','君不見詩人以來一子美，莫年流落來夔子。',317,'全唐诗/poet.song.119000.json','["君不見詩人以來一子美，莫年流落來夔子。", "賦詩三百六十篇，西瀼東屯客愁裏。", "何人作堂畫遺像，收拾光芒榜詩史。", "堂前何有有荔枝，樹猶未老熟獨遲。", "世人貴早不貴晚，倘非我輩誰賞之。", "涪陵昔遭妃子污，萬顆包羞莫能訴。", "瀘戎一經少陵擘，至今傳誦輕紅句。", "少陵傷時淚成血，一點丹心不磨滅。", "散成朱實滿炎方，風味如詩兩奇絕。", "樂天曾畫忠州圖，自言香味人間無。", "君謨亦作閩中譜，陳紫聲名重南土。", "何如詩史堂前株，正是一飯孤忠餘。", "人爲世重物亦重，端如丈人屋上烏。", "巴圖閩譜合避路，奚用品第分錙銖。", "攙先熟者如楊盧，但可與之作前驅。", "閩娘十八婢妾爾，將軍大樹真傭奴。", "我生四百餘年後，來作先生游處守。", "登堂三嘆荔正丹，聊效柳人祠子厚。", "安得先生今復生，添賦夔州歌一首，要使荔枝之名長不朽。"]'),
('f768a51e-0609-441f-acfb-75153e4bfd97','周行可挽詩  其一','王十朋','宋','宋诗','song-poetry','','[]','我始來夔子，公先在計臺。',48,'全唐诗/poet.song.119000.json','["我始來夔子，公先在計臺。", "江山同吊古，文字共銜杯。", "馬運言尤力，天高聽未回。", "懷人夢不見，西望肺肝摧。"]'),
('0a7f0348-51ff-4145-af64-bcb08d81a687','周行可挽詩  其二','王十朋','宋','宋诗','song-poetry','','[]','大事同生日，佳城近故丘。',48,'全唐诗/poet.song.119000.json','["大事同生日，佳城近故丘。", "空留丹竈藥，忍望白雲樓。", "偃折恩誰繼，澄清志未酬。", "傷哉葬元伯，執紼竟無由。"]'),
('90e20356-0011-4f86-82c0-3fda7d020361','過客談梁彭州之政不容口聞爲虛額所困欲引去予願其少留以福千里輒寄惡詩','王十朋','宋','宋诗','song-poetry','','[]','籍甚吾年友，彭州譽正馳。',48,'全唐诗/poet.song.119000.json','["籍甚吾年友，彭州譽正馳。", "那因困虛額，遽欲丐真祠。", "勿謂徒勞耳，終須日教之。", "家傳治稱最，自有九重知。"]'),
('401987de-fd5a-4966-b15f-5ad23e7112fd','食薏苡粥','王十朋','宋','宋诗','song-poetry','','[]','夔州再見夏，炎瘴侵我肌。',48,'全唐诗/poet.song.119000.json','["夔州再見夏，炎瘴侵我肌。", "兩股忽浮腫，百藥竟未治。", "或言薏苡良，可以作粥糜。", "恐坐伏波謗，腹中有珠璣。"]'),
('6bc65c48-72e7-4ce5-8e85-c437385b9f5f','十賢堂栽竹','王十朋','宋','宋诗','song-poetry','','[]','六月修篁带雨移，丁寧護取歲寒枝。',32,'全唐诗/poet.song.119000.json','["六月修篁带雨移，丁寧護取歲寒枝。", "十賢清節高千古，不是此君誰與宜。"]'),
('96aee57b-d9c8-41a5-85d9-0139c6576ed3','詩史堂荔枝晚熟而佳預約同官共賞偶成參差摘實分餉因誦廬陵先生詩云人生此事尚難必况欲功名書鼎彝復用前韻以歌之','王十朋','宋','宋诗','song-poetry','','[]','詩史堂前荔支晚尤美，高壓瀘戎與妃子。',330,'全唐诗/poet.song.119000.json','["詩史堂前荔支晚尤美，高壓瀘戎與妃子。", "姓名猶未聞峽中，風味惟應自皮裏。", "試將遠况江瑶柱，正似騷人擬良史。", "我來嘆息頤屢支，殊方爭獻惟恐遲。", "汝今已晚何用好，不是少陵誰眼之。", "貴妃游魂遭血污，玉坐悲懷何以訴。", "惟有雲安再拜人，悶解夔州兩絕句。", "遺像空存食不血，滿目烟霞明自滅。", "何人種此星幾終，一樹團團味奇絕。", "君不見南賓木蓮有華何足圖，樂夫過慮重看無。", "又不見洛陽牡丹妖艷何必譜，六一區區記風土。", "天生此果更此株，夏日之時見子餘。", "晝疑炎方張火傘，夕訝庭樹栖赤烏。", "雙頭瑩若玉一瑴，細骨輕於錢五銖。", "陳江閥閲如崔盧，茲産於閩必爭驅。", "甜無中邊大勝蜜，醖釀不假蜂爲奴。", "永安宮西郡堂後，折簡呼賓老太守。", "時方炎熱會苦稀，事好乖違意徒厚。", "手摘高枝贈丹實，歌和前篇搔白首。", "嗟一餉之樂兮，天亦慳於老朽。"]'),
('d6bd4553-6d43-4bed-8b64-0d472efba312','伏日與同僚游三友亭','王十朋','宋','宋诗','song-poetry','','[]','炎天過小雨，伏日生微凉。',48,'全唐诗/poet.song.119000.json','["炎天過小雨，伏日生微凉。", "新亭會僚友，故事開壺觴。", "泉汲卧龍乳，茶烹團鳳香。", "緬懷去年友，跳珠出詩章。"]'),
('13c7a411-da8b-4bda-b0f9-c020e9d5e0d9','分韻得炎字','王十朋','宋','宋诗','song-poetry','','[]','兩載夔子國，尤苦夏日炎。',48,'全唐诗/poet.song.119000.json','["兩載夔子國，尤苦夏日炎。", "穉金又云伏，老火猶未潛。", "呼賓江上亭，風雄雨纖纖。", "仰知九重心，勃鬰念閭閻。"]'),
('add9f249-34c1-4006-a53a-d9ede5781bde','制勝樓有元豐間太守王延禧及計臺郡僚過客唱和詩大書於版歲久字漫命筆吏再書之記以數語','王十朋','宋','宋诗','song-poetry','','[]','周室禾黍過者傷，漢宮威儀見之喜。',128,'全唐诗/poet.song.119000.json','["周室禾黍過者傷，漢宮威儀見之喜。", "神州久沒餘楚蜀，太平聲詩存有幾。", "制勝樓頭詩數版，仍是元豐舊臣子。", "體格猶存前輩風，氣象如樓頗奇偉。", "人雖不見典刑在，事尚能言文獻是。", "歲月侵尋自漫滅，愛禮存羊那忍毀。", "百年陳迹一旦新，不問升沉與工鄙。", "一洗向來官職眼，獨刊無盡張居士。"]'),
('085c66b6-eccb-4680-9189-c530635b493f','雷聲','王十朋','宋','宋诗','song-poetry','','[]','雷已先聲雷隠隠，雨宜灑道即紛紛。',32,'全唐诗/poet.song.119000.json','["雷已先聲雷隠隠，雨宜灑道即紛紛。", "爲言風伯不須怒，天下蒼生正望雲。"]'),
('0040d119-3dd9-4182-8b86-a8dd1b218587','某二年于夔竊食而已無德於民尤無功於學校泮宮諸生相與肖其象而祠之意固厚矣然非所宜得呈蘇校授','王十朋','宋','宋诗','song-poetry','','[]','一麾出守喜來夔，日與諸生泳聖涯。',64,'全唐诗/poet.song.119000.json','["一麾出守喜來夔，日與諸生泳聖涯。", "竊取於城勉忠孝，來能如衮進文詞。", "從公于邁誤成頌，爾貌不揚何足祠。", "爲語廣文休作記，粗沙大石定磨碑。"]'),
('1ca06d29-4c83-4b17-b49f-af214ec1db6f','聞得吳興','王十朋','宋','宋诗','song-poetry','','[]','莫年身似杜陵翁，流落烏蠻白帝中。',32,'全唐诗/poet.song.119000.json','["莫年身似杜陵翁，流落烏蠻白帝中。", "聖主哀憐不終棄，乞祠却得水晶宮。"]'),
('7301d36d-f8e6-4012-9e62-0a5bbdd495fe','七夕呈同官','王十朋','宋','宋诗','song-poetry','','[]','今夕何夕夕云七，天孫有巧不願乞。',96,'全唐诗/poet.song.119000.json','["今夕何夕夕云七，天孫有巧不願乞。", "舉盃遥指河漢頭，但願歸耕學牽牛。", "我無腹中書可晒，亦不曬衣隨俗輩。", "緱山未訪仙祖游，夔門聊與嘉賓會。", "星河動摇三峽流，人間天上同新秋。", "鵲已成橋動歸翮，我亦一枝栖可得。"]'),
('41aebc50-5ba4-47f1-a600-6cee3a3d056c','別夔州三絕  其一','王十朋','宋','宋诗','song-poetry','','[]','朅來夔子兩經年，恰是忠州白樂天。',32,'全唐诗/poet.song.119000.json','["朅來夔子兩經年，恰是忠州白樂天。", "種柳栽花一般意，愧無名德比前賢。"]'),
('4df6b2c0-8ed0-4775-a35d-7d776aa19955','別夔州三絕  其二','王十朋','宋','宋诗','song-poetry','','[]','夔峽民淳獄訟稀，使君無事只吟詩。',32,'全唐诗/poet.song.119000.json','["夔峽民淳獄訟稀，使君無事只吟詩。", "才疏政拙形容陋，深愧邦人爲立祠。"]'),
('934a64dd-7ece-4b4c-b442-950f3ffb0489','別夔州三絕  其三','王十朋','宋','宋诗','song-poetry','','[]','陣圖入眼渾如夢，回首江山又夢間。',32,'全唐诗/poet.song.119000.json','["陣圖入眼渾如夢，回首江山又夢間。", "萬里白雲遮望眼，□□□□□□□。"]'),
('2c27ead0-7b5a-4372-acfc-a6d98d193332','贈牟童子','王十朋','宋','宋诗','song-poetry','','[]','牟家六歲好男兒，誦得夔州太守詩。',32,'全唐诗/poet.song.119000.json','["牟家六歲好男兒，誦得夔州太守詩。", "好把五車書盡讀，早成頭角上天池。"]'),
('ffa2a2b2-443d-4c2d-a707-ff01f2ac9217','別同官','王十朋','宋','宋诗','song-poetry','','[]','兩年竊祿古夔州，邂逅諸君亦宦遊。',64,'全唐诗/poet.song.119000.json','["兩年竊祿古夔州，邂逅諸君亦宦遊。", "爲郡不才真下下，同僚多助却優優。", "及瓜便合扁舟去，行李聊爲一飯留。", "摻別相期可無語，君親恩重各宜酬。"]'),
('91b785d3-6b45-44fd-b0f0-6567f29b7568','七月十七日離夔州是夜宿瞿唐','王十朋','宋','宋诗','song-poetry','','[]','邦人送別亦傷情，楊柳陰中涕泣聲。',32,'全唐诗/poet.song.119000.json','["邦人送別亦傷情，楊柳陰中涕泣聲。", "我亦憐夔不忍去，一宵留宿舊江城。"]'),
('d81be57f-60a6-4645-950d-adae11aa4705','至東屯謁少陵祠  其一','王十朋','宋','宋诗','song-poetry','','[]','宦游夔子兩經年，未到東屯意慊然。',32,'全唐诗/poet.song.119000.json','["宦游夔子兩經年，未到東屯意慊然。", "端爲先生舊吟處，不應容易上詩篇。"]'),
('d0150d71-ec99-4e26-b0e3-b93435771926','至東屯謁少陵祠  其二','王十朋','宋','宋诗','song-poetry','','[]','忠不忘君句有神，當時無地可容身。',32,'全唐诗/poet.song.119000.json','["忠不忘君句有神，當時無地可容身。", "草堂遺像英靈在，又見匙翻雪稻新。"]'),
('c3380abd-9439-4f85-97ed-f7690bbb6194','東屯溪山之勝似吾家左原','王十朋','宋','宋诗','song-poetry','','[]','東屯別是一山川，水秀山青似左原。',32,'全唐诗/poet.song.119000.json','["東屯別是一山川，水秀山青似左原。", "我待還家築茅屋，作詩招取少陵魂。"]'),
('6e087b54-9fb2-4cff-8b9c-b70559e04fec','登古峯嶺望夔州','王十朋','宋','宋诗','song-poetry','','[]','巍登古峯嶺，回首望夔州。',72,'全唐诗/poet.song.119000.json','["巍登古峯嶺，回首望夔州。", "隠約瞻卧龍，微茫見江流。", "明朝望眼遮，江山見無由。", "翻令還鄉夢，飛過白鹽頭。", "不知此邦人，亦念使君不。", "使君無可念，空有詩篇留。"]'),
('6d659922-7254-481b-871e-514c1a2ca68e','古峯驛小飲','王十朋','宋','宋诗','song-poetry','','[]','老去最惜別，同僚情更鍾。',24,'全唐诗/poet.song.119000.json','["老去最惜別，同僚情更鍾。", "三杯古峯驛，添我別情濃。"]'),
('9d8bbbcf-111e-4dda-8e67-3340d165ca65','燕子坡','王十朋','宋','宋诗','song-poetry','','[]','燕子歸期近，吾今亦得歸。',24,'全唐诗/poet.song.119000.json','["燕子歸期近，吾今亦得歸。", "烏栖一枝穩，何必更高飛。"]'),
('787bfd3c-62e7-4477-a785-ad9b58694144','悼巫山趙宰','王十朋','宋','宋诗','song-poetry','','[]','使者追求急，君方歸意濃。',48,'全唐诗/poet.song.119000.json','["使者追求急，君方歸意濃。", "讒言端可畏，鬼物不相容。", "浮世誰無死，良醫未易逢。", "我來經舊舘，流涕覺無從。"]'),
('7acb2758-fbaf-416a-b3f6-cbe961bce510','巫峽  其一','王十朋','宋','宋诗','song-poetry','','[]','三峽江流七月平，全家東下葉舟輕。',32,'全唐诗/poet.song.119000.json','["三峽江流七月平，全家東下葉舟輕。", "陽臺得得收雲雨，放盡峯巒照眼明。"]'),
('0359bf39-b24d-43c7-8a46-4883c344ba55','巫峽  其二','王十朋','宋','宋诗','song-poetry','','[]','峽中七月行舟斷，我仗孤忠盡室行。',32,'全唐诗/poet.song.119000.json','["峽中七月行舟斷，我仗孤忠盡室行。", "寄語後人宜自戒，莫因幸免遂輕生。"]'),
('5d451eea-0500-4f84-8cc9-aa716e936b17','巫峽  其三','王十朋','宋','宋诗','song-poetry','','[]','正是瞿唐莫下時，却將行止問舟師。',32,'全唐诗/poet.song.119000.json','["正是瞿唐莫下時，却將行止問舟師。", "老夫也是歸心急，不記前吟灧澦詩。"]'),
('591a352e-5107-482e-ae7f-6f4dc33f4d43','神女廟','王十朋','宋','宋诗','song-poetry','','[]','功開神禹言何妄，夢惱襄王事亦非。',32,'全唐诗/poet.song.119000.json','["功開神禹言何妄，夢惱襄王事亦非。", "峯下祠荒少人到，峽中舟過有烏飛。"]'),
('a7c309ae-062f-4b5b-997b-19abe6567c96','昭君村','王十朋','宋','宋诗','song-poetry','','[]','十二巫峯下，明妃生處村。',24,'全唐诗/poet.song.119000.json','["十二巫峯下，明妃生處村。", "至今粗醜女，灼面亦成痕。"]'),
('8436e2b1-d070-4381-808c-a34eba67b39b','過大拽','王十朋','宋','宋诗','song-poetry','','[]','大拽今重過，江山記我無。',48,'全唐诗/poet.song.119000.json','["大拽今重過，江山記我無。", "雲開列嶂秀，石峙一峯孤。", "吏卒送迎異，舟車來徃殊。", "鴻留泥上迹，飛去到江湖。"]'),
('c8ec4c29-8d2d-451b-8b3d-80541b2c9f4d','石門','王十朋','宋','宋诗','song-poetry','','[]','兵忿雖云敗，君臣義有餘。',24,'全唐诗/poet.song.119000.json','["兵忿雖云敗，君臣義有餘。", "石門能脫急，風義亦堪書。"]'),
('3c3937ed-9d05-4e22-89be-62ed23234dfc','謁清烈廟登獨醒亭','王十朋','宋','宋诗','song-poetry','','[]','我醉亦如衆，亭慙登獨醒。',24,'全唐诗/poet.song.119000.json','["我醉亦如衆，亭慙登獨醒。", "惟知慕清節，首爲繪儀形。"]'),
('1e941b6b-3ed8-45b0-b3ab-30552f1ce993','黄牛峽','王十朋','宋','宋诗','song-poetry','','[]','白狗黄牛竹節灘，奇奇怪怪幾峯巒。',32,'全唐诗/poet.song.119000.json','["白狗黄牛竹節灘，奇奇怪怪幾峯巒。", "山川好處造化惜，不許人間平地看。"]'),
('e1909c45-1edc-43c5-b4c9-5310e1a9f458','黄牛廟','王十朋','宋','宋诗','song-poetry','','[]','我從白帝城，舟次黄牛峽。',204,'全唐诗/poet.song.119000.json','["我從白帝城，舟次黄牛峽。", "黄牛遺廟存，石馬隻耳缺。", "宛如歐公夢，地靈亦奇絕。", "固宜鎮大川，千載食常血。", "何人讚巨力，曾不紀功烈。", "神乎豈求食，挽石駭舟楫。", "或云土勝水，茲亦强牽合。", "白帝將何云，吾爲究其詋。", "神禹昔治水，疏鑿九州別。", "百神各效職，僚佐力俱竭。", "功成禹化熊，塗山亦爲石。", "譬如穆南征，化者想非一。", "有化爲牛者，斷崖留遺跡。", "豈亦黄帝餘，與牛同一色。", "至今名此峽，援溺有陰力。", "淫祠自其俗，神手本正直。", "爵以保安侯，足以章神德。"]'),
('0a4ffbab-abca-4ba0-8fa7-5b74438ad2c1','蝦蟆碚水','王十朋','宋','宋诗','song-poetry','','[]','蝦蟆好居水，背水以自濡。',108,'全唐诗/poet.song.119000.json','["蝦蟆好居水，背水以自濡。", "不知背上味，乃與衆水殊。", "品第高水經，煎茶必來須。", "爭汲以致遠，不憚險且迂。", "我亦走瓶罌，一甌瀹雲腴。", "所恨太遐僻，親朋莫能呼。", "巨蛙如有靈，曷不上天衢。", "以水爲雨露，助天澤寰區。", "坎視峽中小，笑渠子陽愚。"]'),
('1dfa6aa7-3d37-4567-9876-71b7eef59762','石漁翁','王十朋','宋','宋诗','song-poetry','','[]','釣利釣名者，紛紛三峽中。',24,'全唐诗/poet.song.119000.json','["釣利釣名者，紛紛三峽中。", "何人化爲石，又作釣魚翁。"]'),
('c9cf5308-257e-494b-83c7-a0c3ce17b763','至喜亭','王十朋','宋','宋诗','song-poetry','','[]','前年泊舟至喜亭，舍舟觸霧登山行。',96,'全唐诗/poet.song.119000.json','["前年泊舟至喜亭，舍舟觸霧登山行。", "身到猿啼虎嘯處，至今魂夢中宵驚。", "兩年寒暑深山裏，瘴癘侵凌身不死。", "七月歸舟浮漲江，重見茲亭實堪喜。", "世間憂喜無定形，此喜本從憂得名。", "須知既濟有未濟，勿謂江流今已平。"]'),
('3d1e1fe6-7f9c-4777-8334-57c59b11f04b','又一絕','王十朋','宋','宋诗','song-poetry','','[]','歸客來登至喜亭，喜歸兼喜峽江平。',32,'全唐诗/poet.song.119000.json','["歸客來登至喜亭，喜歸兼喜峽江平。", "當時作記文章伯，不止文章得美名。"]'),
('bbf5ab8b-341b-4fb9-841a-5ad4625b2ddb','郭道山','王十朋','宋','宋诗','song-poetry','','[]','學道無成藝有成，青山猶以道爲名。',32,'全唐诗/poet.song.119000.json','["學道無成藝有成，青山猶以道爲名。", "匆匆不及登山看，歸看家山白鹿城。"]'),
('6d67473f-c527-4865-98d8-f3f154cc4d90','宿灌口','王十朋','宋','宋诗','song-poetry','','[]','拂曉出楚塞，中流望荆門。',48,'全唐诗/poet.song.119000.json','["拂曉出楚塞，中流望荆門。", "江隨銅柱轉，舟遇虎牙奔。", "鳥度南天闊，魚翻秋水渾。", "宜都轉盼過，夜宿舊江村。"]'),
('2247bfbc-25a4-4cca-bb50-acac255e98ba','江陵舟中作','王十朋','宋','宋诗','song-poetry','','[]','夢裏身曾到永安，孤城絕塞俯驚湍。',64,'全唐诗/poet.song.119000.json','["夢裏身曾到永安，孤城絕塞俯驚湍。", "東歸初喜楚天闊，西望堪嗟蜀道難。", "灧澦堆邊已陳迹，水晶宮裏又粗官。", "帝鄉咫尺家鄉近，臣子憂心亦小心。"]'),
('9227b691-f147-4206-873f-b4f88c6f0ffb','查元章自成都走書至江陵并貺蜀牋附子','王十朋','宋','宋诗','song-poetry','','[]','芝蘭道山舊，邂逅夔江邊。',240,'全唐诗/poet.song.119000.json','["芝蘭道山舊，邂逅夔江邊。", "會合止半載，別離又經年。", "君猶滯使軺，我忽移霅川。", "東歸不及見，西望心悠然。", "尺書走健卒，追上江陵船。", "慇懃贈遠意，藥百紙以千。", "我老苦多病，得藥年可延。", "靜思苦口味，奚止沉疴痊。", "但非造樓手，誤辱文房牋。", "待將君詩文，傳寫千萬篇。", "書言作二記，付與夔人鎸。", "捍波記修壘，濟渴記義泉。", "深慚郡政謬，濫託雄文傳。", "君才高輩流，君譽藹民編。", "雅志在活人，何心肯流錢。", "當宁正念賈，諸公咸薦賢。", "定歸玉筍班，慷慨旒扆前。", "所陳必堯舜，那肯談武宣。", "早趣舍人裝，行著祖生鞭。", "我冠儻未掛，苕溪遲言旋。"]'),
('d4946c82-3716-4e9f-abeb-159923207ce5','離沙市天色變舟人懼風作少憩公安而行默禱有應','王十朋','宋','宋诗','song-poetry','','[]','解任古夔國，移官白蘋洲。',96,'全唐诗/poet.song.119000.json','["解任古夔國，移官白蘋洲。", "三峽雖幸免，大江尚堪憂。", "黎明霧四塞，篙師請停舟。", "爾禱於公安，吾禱學孔丘。", "愷悌以爲治，潔廉以自修。", "神乎苟聽之，庶不爲神羞。", "須臾日光漏，江凈烟靄收。", "願如吾祖言，千里俱安流。"]'),
('5c700767-a268-4552-baaf-b11ed79ff844','望石首山  其一','王十朋','宋','宋诗','song-poetry','','[]','江山遥望疑若無，隠隠漸露山規摹。',64,'全唐诗/poet.song.119000.json','["江山遥望疑若無，隠隠漸露山規摹。", "化工作山首安石，不著草木爲肌膚。", "吾鄉石首黄金色，五年不見深思憶。", "山頭有石名偶同，長鋏空彈不堪食。"]'),
('6bdfeb2d-89e9-41d1-a423-575e89148f04','望石首山  其二','王十朋','宋','宋诗','song-poetry','','[]','巴夔之山厭太多，荆江其奈無山何。',64,'全唐诗/poet.song.119000.json','["巴夔之山厭太多，荆江其奈無山何。", "舟中遥遥望石首，一點亦足供吟哦。", "艤舟亦向劉郎洑，應是劉郎招我宿。", "劉郎如問舊江山，永安宮草年年綠。"]'),
('f49e7232-e247-4e66-bacf-d6a7a3b30a6b','過三沱','王十朋','宋','宋诗','song-poetry','','[]','舟從三峽過三沱，柳岸人家轉盼過。',32,'全唐诗/poet.song.119000.json','["舟從三峽過三沱，柳岸人家轉盼過。", "莫惜慇懃問舟子，江邊好處亦無多。"]'),
('b52fddff-4ddb-4855-b2f7-9a6dd246e90b','塔子山','王十朋','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','已過魯家洑，猶瞻石首山。',48,'全唐诗/poet.song.119000.json','["已過魯家洑，猶瞻石首山。", "水隨江繚繞，山逐岸回環。", "雨泊蘆洲畔，舟行晚照間。", "貪看洞庭好，不作沌中還。"]'),
('b98390b6-017f-4778-84ba-18675f1e3d6a','魯家洑','王十朋','宋','宋诗','song-poetry','','[]','江頭烟樹色如故，記得向來舟出時。',32,'全唐诗/poet.song.119000.json','["江頭烟樹色如故，記得向來舟出時。", "更讀西行舊詩集，集中多是沌中詩。"]'),
('0f1b0da0-73b6-435e-bbe8-38b3a0e41a90','宿人老灣','王十朋','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','衮衮長江水，悠悠歸去船。',48,'全唐诗/poet.song.119000.json','["衮衮長江水，悠悠歸去船。", "片雲南岸雨，明月別州天。", "犬爲客驚盜，蚊令人廢眠。", "江灣號人老，驚我鬢皤然。"]'),
('296381f7-520e-44c4-aa89-f9205ccd23ab','烏沙鎮避風','王十朋','宋','宋诗','song-poetry','','[]','風避烏沙鎮，心懷白帝城。',24,'全唐诗/poet.song.119000.json','["風避烏沙鎮，心懷白帝城。", "峽中險已過，江上浪宜平。"]'),
('70bbd5ab-671c-4657-b7b1-d828c35cf4d6','維舟岳陽之西岸徐師汊風作不敢行再留一宿用韓昌黎洞庭阻風韻示同行朱仲文張子是','王十朋','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','月行南箕口，簸揚不肯休。',120,'全唐诗/poet.song.119000.json','["月行南箕口，簸揚不肯休。", "我至洞庭側，狂瀾阻行舟。", "東望岳陽城，一葦宿可投。", "吾欲破巨浪，試呼舟子謀。", "舟子笑謂我，官豈乘浮丘。", "同行一二官，好勇豈仲由。", "君子不行險，少遲勿煩啾。", "明朝風自定，鼓枻無憂愁。", "汗顔答舟子，汝語非謬悠。", "書以示同人，欲速不可求。"]'),
('8deb7436-cf0c-43e4-afea-e37def97999f','望洞庭','王十朋','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','端居灧澦兩經年，不戒瞿唐七月船。',32,'全唐诗/poet.song.119000.json','["端居灧澦兩經年，不戒瞿唐七月船。", "得得遥從洞庭過，要看湖漲水中天。"]'),
('b3d38baa-777a-4c47-a8ec-f0fd1b828e28','賈岳州以予阻風致酒肉之贈','王十朋','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','軒皇張樂洞庭旁，掀舞魚龍撼岳陽。',32,'全唐诗/poet.song.119000.json','["軒皇張樂洞庭旁，掀舞魚龍撼岳陽。", "巵酒豚肩使君意，知予肉味未能忘。"]'),
('6bbe8b9a-f0bc-46d2-b1b5-1194e9ab4a45','魚蝦','王十朋','宋','宋诗','song-poetry','','[]','買得巴陵金鯽魚，又逢公子奮長須。',32,'全唐诗/poet.song.119000.json','["買得巴陵金鯽魚，又逢公子奮長須。", "夜來江山秋風起，報道吳兒已鱠鱸。"]'),
('793ddcf6-364c-4fc8-ab28-0a64eb7b4f49','初欲維舟岳陽樓下適風作遂泊南津','王十朋','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','岳陽樓下風波惡，過客舟行不容泊。',64,'全唐诗/poet.song.119000.json','["岳陽樓下風波惡，過客舟行不容泊。", "遥從湖口入南津，看盡湖山與城郭。", "樓閣崢嶸照眼明，君山當面如蓬瀛。", "雄文誰繼范文正，妙曲亦無滕子京。"]'),
('6c56a223-68b5-4657-b312-712ce3b3c69b','岳陽樓','王十朋','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','後樂先憂記飽觀，茲樓今始得憑欄。',64,'全唐诗/poet.song.119000.json','["後樂先憂記飽觀，茲樓今始得憑欄。", "吐吞五水波濤闊，出納三光境界寬。", "黄帝樂聲喧廣宙，湘君山影侵晴瀾。", "江山何獨助張說，收拾清詩上筆端。"]'),
('4b961441-662a-4fb1-8e0b-c6a40001d49b','洞庭湖  其一','王十朋','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','江山好處未經眼，人道岳陽天下無。',32,'全唐诗/poet.song.119000.json','["江山好處未經眼，人道岳陽天下無。", "入筆波瀾自今闊，匈中已有洞庭湖。"]'),
('fb42e6ea-7feb-4508-8ff9-eb9bf516bbdc','洞庭湖  其二','王十朋','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','維舟便上岳陽樓，風定波瀾萬頃秋。',32,'全唐诗/poet.song.119000.json','["維舟便上岳陽樓，風定波瀾萬頃秋。", "聞說洞庭通震澤，水應先我到蘋洲。"]'),
('a7c7ee53-1de2-4e64-a814-093ce032d3a1','讀岳陽樓記','王十朋','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','先憂後樂范文正，此志此言高孟軻。',32,'全唐诗/poet.song.119000.json','["先憂後樂范文正，此志此言高孟軻。", "暇日登臨固宜樂，其如天下有憂何。"]'),
('101a7461-b63a-4242-85a2-8dbf92413cf4','君山  其一','王十朋','宋','宋诗','song-poetry','','[]','恃險三苗此爲國，不知諸夏有華勳。',32,'全唐诗/poet.song.119000.json','["恃險三苗此爲國，不知諸夏有華勳。", "兩階干羽七旬後，從此湖山方有君。"]'),
('e3c1fdc5-0793-42d4-b700-5eb4058a3e38','君山  其二','王十朋','宋','宋诗','song-poetry','','[]','祖龍遷怒色曾頳，帝子有靈山更青。',32,'全唐诗/poet.song.119000.json','["祖龍遷怒色曾頳，帝子有靈山更青。", "湖水如天冬亦涸，此君榮落一般形。"]'),
('5c1c8593-4de9-4d56-bbb2-b7880120b496','南津淑濟廟','王十朋','宋','宋诗','song-poetry','','[]','越國曹娥孝可書，惜無同氣與之俱。',32,'全唐诗/poet.song.119000.json','["越國曹娥孝可書，惜無同氣與之俱。", "武陵今有賢兒女，弟似靈均娣女須。"]'),
('2154e04f-fa67-4bab-a5bb-83615e145d49','過仙亭','王十朋','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','此處神仙幾度經，老松枯朽穉松青。',32,'全唐诗/poet.song.119000.json','["此處神仙幾度經，老松枯朽穉松青。", "如今想作天仙去，不復飛吟過洞庭。"]'),
('c9a13d14-f162-4a1c-8d54-5ac49ac81cb9','解舟遇風暫泊岳陽城下正對君山','王十朋','宋','宋诗','song-poetry','','[]','入湖初訝君山遠，無翼可隨鷗鷺群。',32,'全唐诗/poet.song.119000.json','["入湖初訝君山遠，無翼可隨鷗鷺群。", "繫纜中流忽相對，江湖心亦不忘君。"]'),
('cb802b1a-e97d-49fb-801a-126098f60984','岳陽城下岸赤色亦呼赤壁','王十朋','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','岳陽樓下有赤壁，照耀洞庭烟水東。',32,'全唐诗/poet.song.119000.json','["岳陽樓下有赤壁，照耀洞庭烟水東。", "鄂渚巴陵土多赭，周郎何處破曹公。"]'),
('a92a770b-da1c-446a-b8ce-5e86f96cf7f5','君山形如龍南有一小山如龜','王十朋','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','洞庭湖山山絕奇，大山如龍小如龜。',96,'全唐诗/poet.song.119000.json','["洞庭湖山山絕奇，大山如龍小如龜。", "弄珠曳尾自游戯，不肯吹浪如蛟螭。", "岳陽樓前鐵爲械，古人欲斷蛟螭害。", "蛟螭爲害甚巴蛇，遺冢猶存足爲戒。", "七百里湖涵太虛，春夏漲溢秋冬枯。", "惟有龜龍長自在，不知幾見桑田改。"]'),
('04e2952f-d9c5-4df2-b875-2161adca03b1','燕公樓','王十朋','宋','宋诗','song-poetry','','[]','燕公郡事暇，詩興滿滄波。',24,'全唐诗/poet.song.119000.json','["燕公郡事暇，詩興滿滄波。", "粉飾開元治，江山爲助多。"]'),
('276ccf79-a4d5-4bd7-9e80-89693e364037','道人磯  其一','王十朋','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','江中雙石如弟兄，呼得道人爲友生。',32,'全唐诗/poet.song.119000.json','["江中雙石如弟兄，呼得道人爲友生。", "秋夜扁舟泊磯下，洞庭湖近月華明。"]'),
('9b2253b8-33d6-4ef3-b0f9-9adee5835095','道人磯  其二','王十朋','宋','宋诗','song-poetry','','[]','道人身名兩俱槁，道其所道非吾道。',32,'全唐诗/poet.song.119000.json','["道人身名兩俱槁，道其所道非吾道。", "橫江兩石作釣磯，不似嚴陵臺上好。"]'),
('fd184347-8387-48f2-b4e2-8bba8807b215','泊潛江甲','王十朋','宋','宋诗','song-poetry','','[]','潛江甲口楚天涯，蘆荻舟中一兩家。',32,'全唐诗/poet.song.119000.json','["潛江甲口楚天涯，蘆荻舟中一兩家。", "呼酒敕厨無一味，天鵝亂眼似楊花。"]'),
('00690a2c-4fb7-4a18-be1a-e30433697103','舟遇逆風破浪賦詩','王十朋','宋','宋诗','song-poetry','','[]','風撼楚江水，雲橫鄂渚天。',48,'全唐诗/poet.song.119000.json','["風撼楚江水，雲橫鄂渚天。", "支頤看山色，破浪出詩篇。", "門掩瀕江舍，帆揚上水船。", "江神不借便，歸興自飄然。"]'),
('66f43a4c-d601-4b2a-809a-c1fa3a180b1c','舟中覽鏡','王十朋','宋','宋诗','song-poetry','','[]','來往成何事，霜毛滿鬢多。',24,'全唐诗/poet.song.119000.json','["來往成何事，霜毛滿鬢多。", "洋洋大江水，東去欲如何。"]'),
('68a52630-9ac4-4253-bece-7d910010cb8a','過嘉魚縣','王十朋','宋','宋诗','song-poetry','','[]','舟過嘉魚縣，買魚人道無。',24,'全唐诗/poet.song.119000.json','["舟過嘉魚縣，買魚人道無。", "青山不堪煮，彈鋏看銅符。"]'),
('3bdd59f1-46ff-4277-bea7-26e1a771feac','宿通濟口','王十朋','宋','宋诗','song-poetry','','[]','沌水從茲入，中藏寂寞鄉。',24,'全唐诗/poet.song.119000.json','["沌水從茲入，中藏寂寞鄉。", "相逢如故舊，爲我濟歸航。"]'),
('5b6b9499-a0b2-46a1-9982-a5d505a20e73','百人磯','王十朋','宋','宋诗','song-poetry','','[]','歸從三峽水，重見百人磯。',24,'全唐诗/poet.song.119000.json','["歸從三峽水，重見百人磯。", "山色只如舊，挽舟人已非。"]'),
('410b852a-4af7-4009-8306-b1bf0953c552','南浦','王十朋','宋','宋诗','song-poetry','','[]','江淹送客傷心處，萬里人從蜀道來。',32,'全唐诗/poet.song.119000.json','["江淹送客傷心處，萬里人從蜀道來。", "柳已三番見秋色，蕭蕭雙鬢若何哉。"]'),
('4f8e62ea-1e5b-4d33-9b54-47edc94c1645','南樓','王十朋','宋','宋诗','song-poetry','','[]','江漢西來於此會，朝宗東去不須分。',64,'全唐诗/poet.song.119000.json','["江漢西來於此會，朝宗東去不須分。", "銀濤遥带岷峨雪，烟渚高連巫峽雲。", "鸚鵡洲悲狂處士，蛟龍池化故將軍。", "登臨長願如今日，塵靜元規楚不氛。"]'),
('5720ebb9-c4a5-4c07-b22f-95375707bf14','解舟風猶未息暫止江口','王十朋','宋','宋诗','song-poetry','','[]','狂飆未息浪崢嶸，江口停舟不敢行。',32,'全唐诗/poet.song.119000.json','["狂飆未息浪崢嶸，江口停舟不敢行。", "自是吾儕畏行險，前頭波浪有舟橫。"]'),
('5e8d2671-5b0a-4602-8821-47c2a0e0c582','泊舟漢口','王十朋','宋','宋诗','song-poetry','','[]','稍稍風波定，悠悠舟楫移。',48,'全唐诗/poet.song.119000.json','["稍稍風波定，悠悠舟楫移。", "身雖到漢口，家尚在天涯。", "大別思大禹，古峯懷古夔。", "山城有廖廓，歸說是吾兒。"]'),
('9e63a9a9-17a4-40d8-80ae-81a69442645f','黄鶴樓','王十朋','宋','宋诗','song-poetry','','[]','雲鎖呂公洞，月明黄鶴樓。',24,'全唐诗/poet.song.119000.json','["雲鎖呂公洞，月明黄鶴樓。", "抱關非故卒，誰見羽衣游。"]'),
('f585e061-f89c-49cd-bbdb-876b224bfc25','七磯','王十朋','宋','宋诗','song-poetry','','[]','江上風波惡，江中洲渚多。',24,'全唐诗/poet.song.119000.json','["江上風波惡，江中洲渚多。", "回頭三峽遠，轉盼七磯過。"]'),
('ba0f7ac5-0c59-49ea-a43a-abc35905201e','黄州','王十朋','宋','宋诗','song-poetry','','[]','弭棹大江濱，江山入眼新。',48,'全唐诗/poet.song.119000.json','["弭棹大江濱，江山入眼新。", "地疑真赤壁，州是古黄人。", "水隔三分國，風遺兩逐臣。", "雪堂欣覿面，詩思定能神。"]'),
('a6af1f42-1bcd-4b5e-92a9-745806e77e5e','游東坡十一絕  其一','王十朋','宋','宋诗','song-poetry','','[]','道大才高世不容，堪嗟尺水困神龍。',32,'全唐诗/poet.song.119000.json','["道大才高世不容，堪嗟尺水困神龍。", "空游赤壁英姿發，却向小橋詩思濃。"]'),
('7d1b3649-0558-4c2c-bed0-cecbb5dfd93c','游東坡十一絕  其二','王十朋','宋','宋诗','song-poetry','','[]','出處平生慕樂天，東坡名自樂天傳。',32,'全唐诗/poet.song.119000.json','["出處平生慕樂天，東坡名自樂天傳。", "文章均得江山助，但覺前賢畏後賢。"]'),
('4fcec706-9282-4cb2-8be5-7fec59eb5154','游東坡十一絕  其三','王十朋','宋','宋诗','song-poetry','','[]','少年下筆已如神，文到黄州更絕塵。',32,'全唐诗/poet.song.119000.json','["少年下筆已如神，文到黄州更絕塵。", "我宋人才盛元祐，玉堂人是雪堂人。"]'),
('a46a1089-dae9-49e7-bf83-52991b09fd08','游東坡十一絕  其四','王十朋','宋','宋诗','song-poetry','','[]','世重元之重竹樓，雪堂名更重黄州。',32,'全唐诗/poet.song.119000.json','["世重元之重竹樓，雪堂名更重黄州。", "西山草木尤光彩，一一曾經杖屨遊。"]'),
('622055cd-66f6-4c8a-858f-72d2b6f70edc','游東坡十一絕  其五','王十朋','宋','宋诗','song-poetry','','[]','江遶山城柳暗村，五年詩亂謫仙魂。',32,'全唐诗/poet.song.119000.json','["江遶山城柳暗村，五年詩亂謫仙魂。", "欲尋遺老問前事，楚語兒童今不存。"]'),
('98cda883-7ef7-45ee-aaac-07c0571cb7b6','游東坡十一絕  其六','王十朋','宋','宋诗','song-poetry','','[]','再閏黄州正坐詩，詩因遷謫更瑰奇。',32,'全唐诗/poet.song.119000.json','["再閏黄州正坐詩，詩因遷謫更瑰奇。", "讀公赤壁詞并賦，如見周郎破賊時。"]'),
('39ac06ea-91c6-4642-8252-f81f64ffa80c','游東坡十一絕  其七','王十朋','宋','宋诗','song-poetry','','[]','供成詩案脫纍囚，天遣公來此地游。',32,'全唐诗/poet.song.119000.json','["供成詩案脫纍囚，天遣公來此地游。", "自有胸中雲夢澤，更居雲夢澤南州。"]'),
('9ae397a7-12e1-41e0-87f7-f501a71de182','游東坡十一絕  其八','王十朋','宋','宋诗','song-poetry','','[]','三道策成名烜赫，萬言書就迹危疑。',32,'全唐诗/poet.song.119000.json','["三道策成名烜赫，萬言書就迹危疑。", "易書論語忘憂患，天下三經字說時。"]'),
('fe3f6a8f-b439-402c-8eb5-6622b229472e','游東坡十一絕  其九','王十朋','宋','宋诗','song-poetry','','[]','口誦淵明歸去詞，岷峨歸去竟無欺。',32,'全唐诗/poet.song.119000.json','["口誦淵明歸去詞，岷峨歸去竟無欺。", "高安難弟來相訪，細說對床風雨時。"]'),
('333a32b5-59b7-4a3b-8e4c-d71b0c0988ca','游東坡十一絕  其一○','王十朋','宋','宋诗','song-poetry','','[]','批風抹月五經年，吟盡淮南盡處天。',32,'全唐诗/poet.song.119000.json','["批風抹月五經年，吟盡淮南盡處天。", "獨與元之韓魏國，神交千古作三賢。"]'),
('f71175bb-4adb-4d57-8fcb-25a43d64a1dc','游東坡十一絕  其一一','王十朋','宋','宋诗','song-poetry','','[]','向來茅屋僅容身，今日祠堂高更新。',32,'全唐诗/poet.song.119000.json','["向來茅屋僅容身，今日祠堂高更新。", "費盡丹青傳不得，靈臺一點與精神。"]'),
('6b7e7e7b-25f4-493d-8986-02b0a9bc41b6','至九江陪林守黄中登庾樓出示舊詩','王十朋','宋','宋诗','song-poetry','','[]','萬里相望牛馬風，茲樓邂逅一尊同。',64,'全唐诗/poet.song.119000.json','["萬里相望牛馬風，茲樓邂逅一尊同。", "烟生燕寢香爐上，黿在賓筵食指中。", "舟入滄波詠蘋白，飲陪文字勝裙紅。", "飛黄騰踏日邊去，回首群驚冀北空。"]'),
('ade64037-bfa0-413a-82d3-38798eaab8ea','喻叔奇自鄱陽來以詩見贈次韻以酬','王十朋','宋','宋诗','song-poetry','','[]','家居雁宕芙蓉側，身自瞿塘灧澦回。',64,'全唐诗/poet.song.119000.json','["家居雁宕芙蓉側，身自瞿塘灧澦回。", "覽盡江山歸路遠，舞翻烏鵲故人來。", "詩吟夔子相思句，酒飲鄱陽未盡盃。", "種學績文宜舘閣，二松那復久淹徊。"]'),
('c93a2e75-aa19-4636-98d2-f89ebd904cf4','琵琶亭','王十朋','宋','宋诗','song-poetry','','[]','繫舟琵琶秋水深，夜靜不聞琵琶音。',32,'全唐诗/poet.song.119000.json','["繫舟琵琶秋水深，夜靜不聞琵琶音。", "往來多少商婦怨，世無司馬誰沾巾。"]'),
('ed406f69-bc24-4716-9aa9-f77919bed8be','過彭澤','王十朋','宋','宋诗','song-poetry','','[]','萬里歸舟巨浪間，只將青眼對青山。',32,'全唐诗/poet.song.119000.json','["萬里歸舟巨浪間，只將青眼對青山。", "青山好處惟彭澤，出岫雲歸倦鳥還。"]'),
('db212b85-5960-40bd-ac38-2c23c64420f3','馬當山','王十朋','宋','宋诗','song-poetry','','[]','此地水如峽，有山名馬當。',24,'全唐诗/poet.song.119000.json','["此地水如峽，有山名馬當。", "猶疑是灧澦，更合戒舟航。"]'),
('9a5f5a66-fb3b-4b12-88d6-49607fc8717f','那剎石','王十朋','宋','宋诗','song-poetry','','[]','七月下三巴，孤舟近九華。',24,'全唐诗/poet.song.119000.json','["七月下三巴，孤舟近九華。", "魂猶驚灧澦，石更見那查。"]'),
('7ac1de81-b85a-4425-94bc-8b94c2995e54','池之清溪如杭之西湖某歸自三峽維舟弄水亭南望齊山翠微在眼登譙樓望九華見一峯奇甚呈提舉李子長知郡趙富文','王十朋','宋','宋诗','song-poetry','','["\u897f\u6e56"]','城南風物似西湖，萬里歸舟入畫圖。',64,'全唐诗/poet.song.119000.json','["城南風物似西湖，萬里歸舟入畫圖。", "光潔貯懷便弄水，翠微照眼稱提壺。", "浦無時節秋尤好，池有精神貴可呼。", "最是九華知客意，倚天遥露一峯孤。"]'),
('fee86bab-6619-4e31-973c-7f7c8d2c9120','子長和詩復酬二首  其一','王十朋','宋','宋诗','song-poetry','','[]','往歲遥從彭蠡湖，常山地閲武侯圖。',64,'全唐诗/poet.song.119000.json','["往歲遥從彭蠡湖，常山地閲武侯圖。", "忽乘雪裏子猷棹，欣對花間太白壺。", "雁宕寄書知有便，天台采藥定相呼。", "兩翁異日爲鄰舍，笑說江山大小孤。"]'),
('e2e399f5-86fc-46a8-8513-04cca3810e2c','子長和詩復酬二首  其二','王十朋','宋','宋诗','song-poetry','','[]','君往東湖我左湖，田園歸去亦良圖。',64,'全唐诗/poet.song.119000.json','["君往東湖我左湖，田園歸去亦良圖。", "縱如傅說妙調鼎，終羨淵明高引壺。", "清峭臺中各陳迹，翠微亭上偶歡呼。", "江東浙右從今後，永夜月同千里孤。"]'),
('bc0fc89d-1f99-4f50-bee8-324767c5b66a','富文和詩復用前韻','王十朋','宋','宋诗','song-poetry','','[]','四上祠章郡得湖，真同起廢躄浮圖。',64,'全唐诗/poet.song.119000.json','["四上祠章郡得湖，真同起廢躄浮圖。", "路經秋浦人如玉，洞入齊山天在壺。", "人物宜居國士選，吏民聊作使君呼。", "還鄉說與賈君子，官比廣昌風更孤。"]'),
('97406fab-8bfc-47a5-80f7-170a4104fc2a','子長招遊齊山','王十朋','宋','宋诗','song-poetry','','[]','路經秋浦上崔嵬，不負孤舟萬里回。',64,'全唐诗/poet.song.119000.json','["路經秋浦上崔嵬，不負孤舟萬里回。", "峯比九華微具體，洞疑三竺遠飛來。", "勝窮巖石玲瓏地，秀吸江湖浩渺盃。", "先却紫微期一月，菊花未放桂花開。"]'),
('8d1460a4-6247-4565-804d-6808a2fca3a8','富文贈桂花','王十朋','宋','宋诗','song-poetry','','[]','夔有百花無此香，兩年官舍負秋光。',32,'全唐诗/poet.song.119000.json','["夔有百花無此香，兩年官舍負秋光。", "使君元是蟾宮客，贈我數枝金粟黄。"]'),
('7288584c-ee66-4cff-919a-3753366c29db','泛清溪','王十朋','宋','宋诗','song-poetry','','[]','清者未必貴，貴者或不清。',108,'全唐诗/poet.song.119000.json','["清者未必貴，貴者或不清。", "胡爲貴池內，却有清溪名。", "清貴兩俱足，造物如有情。", "溪有夷屈風，池非趙孟榮。", "三秋冷浸月，十里光涵城。", "真可弄茲水，更堪濯吾纓。", "天亦知我意，故令居水精。", "水精豈吾居，龍湫老餘生。", "滿壁畫清溪，坐覺名利輕。"]'),
('63059812-5a6a-4d46-9a18-475503b87b8a','子長見示汪樞密游齊山詩因次其韻','王十朋','宋','宋诗','song-poetry','','[]','莫莫休休祇欲閑，貴池誤照野人顔。',64,'全唐诗/poet.song.119000.json','["莫莫休休祇欲閑，貴池誤照野人顔。", "好詩如見元樞面，佳境仍逢相國山。", "談笑從容禪榻畔，翠微彷彿夢魂間。", "吾儕相勉崇名節，峴首風流庶可攀。"]'),
('466f3aa8-a88f-4dd4-9b47-57776bdd1197','富文送鹿肉','王十朋','宋','宋诗','song-poetry','','[]','太尉前軍得活鹿，使君慇懃分我肉。',96,'全唐诗/poet.song.119000.json','["太尉前軍得活鹿，使君慇懃分我肉。", "定知應是秦失餘，苗裔仍爲世人逐。", "使君好客今平原，秋浦樓頭羅水陸。", "青州從事嘉屢拜，白鹿山人賜新沐。", "社風留客去未得，清溪山頭兩經宿。", "頻將口腹溷使君，大嚼戲吟詩一幅。"]'),
('763a699d-f409-46f6-a75c-a6daaadcf171','朱仲文和詩用齊山韻以酬','王十朋','宋','宋诗','song-poetry','','[]','蜀山同我上崔嵬，峽水相隨共載回。',64,'全唐诗/poet.song.119000.json','["蜀山同我上崔嵬，峽水相隨共載回。", "秋月迎人霅川去，義風吹客浙江來。", "山游未盡無窮力，酒興應嫌有限盃。", "準擬吳中作重九，菊花休道不須開。"]'),
('04fe7187-e94a-48a1-83d0-e6128c00a297','子長和詩并饋飲食再用泛清溪韻','王十朋','宋','宋诗','song-poetry','','[]','秋浦天作秋，清溪風更清。',108,'全唐诗/poet.song.119000.json','["秋浦天作秋，清溪風更清。", "三宿不忍去，山以齊爲名。", "天台李御史，傾蓋即鍾情。", "憐我峽中歸，笑談洗枯榮。", "携壺上翠微，舉首望赤城。", "相期老巖壑，便欲遺簪纓。", "贈我十首詩，字字工且精。", "從今似杜老，對酒懷李生。", "何當細論文，萬戶侯可輕。"]'),
('3fec6194-662d-4959-a256-663c79482b5f','溪口阻風寄子長富文','王十朋','宋','宋诗','song-poetry','','[]','風知主人意，吹浪留客舟。',48,'全唐诗/poet.song.119000.json','["風知主人意，吹浪留客舟。", "客子念行役，形留心不留。", "回望月峽月，坐悲秋浦秋。", "從今懷人夢，飛遶清溪樓。"]'),
('2f0f095a-3462-4fc5-89e7-ac672ec0bec8','子長和汪樞齊山詩復用前韻','王十朋','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','腐儒無用分投閑，吳蜀分符祇强顔。',64,'全唐诗/poet.song.119000.json','["腐儒無用分投閑，吳蜀分符祇强顔。", "去訪少陵三峽水，來尋太白九華山。", "小舟載酒清溪口，健卒傳詩白浪間。", "風伯相留作吟社，願低筆力許追攀。"]'),
('40ead910-42f0-4ade-9575-79bde6fdba5f','池陽阻風留十日','王十朋','宋','宋诗','song-poetry','','[]','舟楫何濡滯，秋深風未西。',48,'全唐诗/poet.song.119000.json','["舟楫何濡滯，秋深風未西。", "五旬從白帝，十日尚清溪。", "匈次澤吞楚，眼中山見齊。", "主人殊未厭，壺榼屢提携。"]'),
('d256829e-f1fd-4e81-8508-48b0dcc3925c','子長携具至溪口復用前韻','王十朋','宋','宋诗','song-poetry','','[]','有客雙蓬鬢，歸從灧澦西。',48,'全唐诗/poet.song.119000.json','["有客雙蓬鬢，歸從灧澦西。", "符分三竹使，地見兩梅溪。", "舟遇先逢李，盃行酒到齊。", "他年石橋路，歸去手應携。"]'),
('0b3cae69-0a14-40a3-b12e-09d468ee108b','寄林黄中','王十朋','宋','宋诗','song-poetry','','[]','郎星夜照貴池口，漸見祥光燭斗牛。',96,'全唐诗/poet.song.119000.json','["郎星夜照貴池口，漸見祥光燭斗牛。", "甘棠遺愛留潯陽，盡道前無此太守。", "我亦弭楫清溪灘，秋風吹浪高於山。", "與君相去纔咫尺，形影隔絕烟波間。", "晨起揚帆欲東去，風伯江神兩俱怒。", "吾儕行止端由天，天氣未佳聊且住。"]'),
('4a94cb50-8f2f-49f4-9e87-4e387e0ccaba','望舒山','王十朋','宋','宋诗','song-poetry','','[]','舟阻清溪十日風，旅懷秋思渺無窮。',32,'全唐诗/poet.song.119000.json','["舟阻清溪十日風，旅懷秋思渺無窮。", "開編細讀舒王句，一點舒山在眼中。"]'),
('b56e2f03-e33c-41d5-917e-521e3d62a2b9','出清溪','王十朋','宋','宋诗','song-poetry','','[]','歸舟十日阻池陽，風伯相留意亦良。',64,'全唐诗/poet.song.119000.json','["歸舟十日阻池陽，風伯相留意亦良。", "長喙參軍初薦熟，無腸公子正輸芒。", "齊山却向江南好，秋浦尤於社後凉。", "明日解維苕霅去，夢魂猶在水雲鄉。"]'),
('98ea5690-6ca0-4018-947d-ba4bc66f6c49','舟至梅根子長寄詩復用前韻','王十朋','宋','宋诗','song-poetry','','[]','使節淹江左，魚符換浙西。',48,'全唐诗/poet.song.119000.json','["使節淹江左，魚符換浙西。", "詩筒猶在道，客棹已移溪。", "戒險疑浮峽，行徐類去齊。", "壺觴更何日，重向翠微携。"]'),
('3db80729-5d5d-4e51-b59a-8a9002c45699','淮山','王十朋','宋','宋诗','song-poetry','','[]','淮山無數不知名，山色遥看點點青。',32,'全唐诗/poet.song.119000.json','["淮山無數不知名，山色遥看點點青。", "二百餘年仁草木，莫令污染犬羊腥。"]'),
('454b04c6-94a3-4063-8cf5-c782f33f2a62','九華山  其一','王十朋','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','九芙蓉自九天來，太史南游山未開。',32,'全唐诗/poet.song.119000.json','["九芙蓉自九天來，太史南游山未開。", "仙境曾經謫仙眼，佳名傑句兩崔嵬。"]'),
('fb076f10-4678-483f-9129-4e904ddc9820','九華山  其二','王十朋','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','舟出清溪尚逆風，觀山却得少從容。',32,'全唐诗/poet.song.119000.json','["舟出清溪尚逆風，觀山却得少從容。", "浮雲不礙天邊眼，放出神仙八九峯。"]'),
('8cd3ad33-1232-4696-acd4-e796a99ecea9','九華山  其三','王十朋','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','我在芙蓉山下家，四年秋色隔天涯。',32,'全唐诗/poet.song.119000.json','["我在芙蓉山下家，四年秋色隔天涯。", "如今漸覺鄉山近，已見芙蓉吐九華。"]'),
('08509a0c-5db4-4d80-8893-346ed6f68143','九華山  其四','王十朋','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','江南一嶽占青陽，多少神仙此地藏。',32,'全唐诗/poet.song.119000.json','["江南一嶽占青陽，多少神仙此地藏。", "聞說仙翁搗藥處，鳥聲依舊克丁當。"]'),
('29cc42e0-a1ce-4483-a190-88c3657bc312','九華山  其五','王十朋','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','九華山下化成寺，太白書堂高處開。',32,'全唐诗/poet.song.119000.json','["九華山下化成寺，太白書堂高處開。", "想見江山無此境，故宜頭白懶歸來。"]'),
('c0e85006-bb20-46dc-9f93-d180bd478473','九華山  其六','王十朋','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','峯巒列峙神仙境，子母相依孝義山。',32,'全唐诗/poet.song.119000.json','["峯巒列峙神仙境，子母相依孝義山。", "莫向山中摘花果，惜春啼鳥怒人攀。"]'),
('aafa1d0e-6afc-4568-ac35-16aa43bc17b8','九華山  其七','王十朋','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','郡樓初見一奇峯，深恐烟霞無路通。',32,'全唐诗/poet.song.119000.json','["郡樓初見一奇峯，深恐烟霞無路通。", "神母遥遥將九子，總將山色到舟中。"]'),
('86876af7-35c5-4e56-b42d-d3eb92dada59','九華山  其八','王十朋','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','曾見齊山小九華，夢游縹緲羽人家。',32,'全唐诗/poet.song.119000.json','["曾見齊山小九華，夢游縹緲羽人家。", "靈山面目忽相見，舟繫梅根秋日斜。"]'),
('fac03022-a5c9-4917-981e-98fdd4dc24aa','九華山  其九','王十朋','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','曰華曰子數俱九，細看峯巒何許多。',32,'全唐诗/poet.song.119000.json','["曰華曰子數俱九，細看峯巒何許多。", "今古畫工圖不足，冠卿詩奈九華何。"]'),
('29b28dd3-aa0c-4188-95bd-15719fd15a4c','銅陵阻風  其一','王十朋','宋','宋诗','song-poetry','','[]','兩年官絕塞，萬里下瞿唐。',48,'全唐诗/poet.song.119000.json','["兩年官絕塞，萬里下瞿唐。", "秋浦浪方息，銅陵風又狂。", "五松人憶白，雙竹句思黄。", "今夜舟中月，中秋何處光。"]'),
('2fa25c0e-3a2a-4872-845f-436602558bbc','銅陵阻風  其二','王十朋','宋','宋诗','song-poetry','','[]','江入銅陵縣，舟藏蘆葦間。',48,'全唐诗/poet.song.119000.json','["江入銅陵縣，舟藏蘆葦間。", "郵亭危壓浦，佛屋陋依山。", "月出烏將繞，風高雁欲還。", "江山不貧處，一覽見塵寰。"]'),
('4546e44c-9782-4ab8-93d0-4250c692c732','黄池對月','王十朋','宋','宋诗','song-poetry','','[]','白帝去年月，黄池今夜看。',48,'全唐诗/poet.song.119000.json','["白帝去年月，黄池今夜看。", "風將清玉宇，雲不礙金盆。", "明鏡飛邊遠，霓裳舞處寒。", "論文一尊酒，欣對舊同官。"]'),
('a0ff2c1b-0843-4225-ad6c-4705c72dcd77','宣城道中聞雁','王十朋','宋','宋诗','song-poetry','','[]','蟬噪景如夏，鳥鳴山似春。',24,'全唐诗/poet.song.119000.json','["蟬噪景如夏，鳥鳴山似春。", "數聲雲外過，却是雁來賓。"]'),
('6e22fe74-f8d8-4f45-97a1-6f256dd6522f','宿新豐驛','王十朋','宋','宋诗','song-poetry','','[]','小驛數椽屋，夜深風雨中。',24,'全唐诗/poet.song.119000.json','["小驛數椽屋，夜深風雨中。", "鄰家有鷄犬，不是漢新豐。"]'),
('df5685bb-42d8-46fa-9c23-6414713cfed7','塗中遇雨','王十朋','宋','宋诗','song-poetry','','[]','江流渺渺風吹浪，驛路迢迢雨作泥。',32,'全唐诗/poet.song.119000.json','["江流渺渺風吹浪，驛路迢迢雨作泥。", "好把金章換蓑笠，故山深處把鋤犁。"]'),
('db21c600-bb71-4413-9d18-8ed3e3657a30','過宛陵陪汪樞密登雙溪閣疊嶂樓游高齋望敬亭山誦謝元暉李太白詩用樞公游齊山韻','王十朋','宋','宋诗','song-poetry','','[]','天將大任未容閑，清峭依然御史顔。',64,'全唐诗/poet.song.119000.json','["天將大任未容閑，清峭依然御史顔。", "謝客能吟練江句，謫仙不厭敬亭山。", "雙溪風月壺觴裏，疊嶂烟霞几案間。", "天下蒼生望公起，歸轅行見郡人攀。"]'),
('ce89bf95-dac3-481a-8f56-22614a902143','離宣城天色陰晦望群山不見樞公和詩見寄復用前韵','王十朋','宋','宋诗','song-poetry','','[]','聖恩猶未許投閑，遥訪蘋洲柳與顔。',64,'全唐诗/poet.song.119000.json','["聖恩猶未許投閑，遥訪蘋洲柳與顔。", "羿婦解將風送月，麻姑莫遣雨遮山。", "心游孤嶼題詩處，名玷元樞薦墨間。", "旦夕公歸首臺鼎，高齋遺躅倘容攀。"]'),
('1fc4ca9b-2032-4326-98d0-1be34d74dd5b','過麻姑山','王十朋','宋','宋诗','song-poetry','','[]','出郭群山四望無，故將詩句禱麻姑。',32,'全唐诗/poet.song.119000.json','["出郭群山四望無，故將詩句禱麻姑。", "忽然雲破山開面，天色如春有鳥呼。"]'),
('e2f7fa4a-510e-4488-8a73-1cc35509a387','宿紅林驛遇交代王給事','王十朋','宋','宋诗','song-poetry','','[]','路入紅林林未紅，相逢俱是白頭翁。',32,'全唐诗/poet.song.119000.json','["路入紅林林未紅，相逢俱是白頭翁。", "郵亭燈火一尊酒，明日君西我向東。"]'),
('ff276a1c-e833-4157-8593-2371a9d9d8da','廣德途中觀刈稻','王十朋','宋','宋诗','song-poetry','','[]','田父欣相語，今年幸有秋。',48,'全唐诗/poet.song.119000.json','["田父欣相語，今年幸有秋。", "深憂水後爛，急向雨餘收。", "穗盡穴移鼠，畦空童放牛。", "何當速歸去，吾亦有西疇。"]'),
('101df38e-5159-4282-8701-2162b05b198e','祠山','王十朋','宋','宋诗','song-poetry','','[]','秋風吹客過祠山，水出平原礙往還。',32,'全唐诗/poet.song.119000.json','["秋風吹客過祠山，水出平原礙往還。", "呼吸雨暘神有力，掃除雲霧見天顔。"]'),
('c9c5d2dd-ae2c-4625-9e32-aed0e5bc5fc8','桐川三絕 遇太學三友','王十朋','宋','宋诗','song-poetry','','[]','歸從三峽過三峯，益友三人忽此逢。',32,'全唐诗/poet.song.119000.json','["歸從三峽過三峯，益友三人忽此逢。", "行李稽留三日雨，天教我輩得從容。"]'),
('d266da84-bfaf-4c9f-8f6e-6dc8be623016','桐川三絕 驛中阻雨','王十朋','宋','宋诗','song-poetry','','[]','浸淫秋雨阻桐川，無術那能補漏天。',32,'全唐诗/poet.song.119000.json','["浸淫秋雨阻桐川，無術那能補漏天。", "傳舍終宵不成寐，點燈重讀舊詩篇。"]'),
('7aec1d04-d22d-48f8-b16e-0aa9f6b7d9f2','桐川三絕 文籍遭水','王十朋','宋','宋诗','song-poetry','','[]','文書隨我下瞿唐，準擬家添萬卷藏。',32,'全唐诗/poet.song.119000.json','["文書隨我下瞿唐，準擬家添萬卷藏。", "水厄那知在平地，從今既濟要須防。"]'),
('7d82a081-15bb-4b38-8497-1e58911b895f','九月一日自道場山如臨安周德載夏廷茂自菁村乘舟來訪既別寄以小詩','王十朋','宋','宋诗','song-poetry','','[]','二十年前舊友生，扁州來訪見交情。',32,'全唐诗/poet.song.119000.json','["二十年前舊友生，扁州來訪見交情。", "相看容鬢俱非昔，記得爐亭笑語聲。"]'),
('5cdc0c90-05fc-4e11-a6fe-8518dc4c04f6','待對仙林九日登佛閣時寄家道場山思去年遊卧龍山遂用舊韻','王十朋','宋','宋诗','song-poetry','','[]','浮家東下路間關，地近家鄉尚未還。',64,'全唐诗/poet.song.119000.json','["浮家東下路間關，地近家鄉尚未還。", "風雨滿城欣已過，星霜入鬢早宜閑。", "去年嘉客同吹帽，今日仙林獨侍班。", "徧插茱萸憶兄弟，更添北望道場山。"]'),
('1da23e23-c60e-4bf2-ba8a-1fa81508b2be','九月十三日離仙林','王十朋','宋','宋诗','song-poetry','','[]','重入脩門鬢已華，君恩猶未許還家。',32,'全唐诗/poet.song.119000.json','["重入脩門鬢已華，君恩猶未許還家。", "木魚聲動催行李，蠟炬向人空自花。"]'),
('04a46edc-f690-458e-b98f-ffd02cb51318','過東林','王十朋','宋','宋诗','song-poetry','','[]','地入東林眼界奇，神仙遺迹在榴皮。',32,'全唐诗/poet.song.119000.json','["地入東林眼界奇，神仙遺迹在榴皮。", "湖山如舊無東老，酒爲嘉賓釀者誰。"]'),
('15e01405-d9ed-4469-a109-8fd7f341fc9f','郡中久雨入境而霽','王十朋','宋','宋诗','song-poetry','','[]','積雨喜初霽，湖山清更嘉。',48,'全唐诗/poet.song.119000.json','["積雨喜初霽，湖山清更嘉。", "船船漁晒網，岸岸稻烘芽。", "水漲魚蝦樂，年凶道路嗟。", "人言新太守，頭白似苕花。"]'),
('138c352d-fa13-4e50-a1a0-fab205f6098c','六客堂','王十朋','宋','宋诗','song-poetry','','[]','水晶宮中刺史宅，月□□堂遊六客。',224,'全唐诗/poet.song.119000.json','["水晶宮中刺史宅，月□□堂遊六客。", "中有一客爲主人，萬卷詩書李公擇。", "元□□揮玉堂手，令舉聲蜚制科策。", "五勸使君古遺直，三□郎官老詞伯。", "眉山有客何等人，退之少陵李太白。", "直道高才時不容，天遣數子爲遊從。", "吳興清絕山水國，五百年過人中龍。", "健峭銀鈎逼顔魯，點化湖山出奇語。", "高壓白蘋洲上詩，更肯區區談小杜。", "端如竹溪逢謫仙，並遊逸士名俱傳。", "飄飄乘風鼓長翮，兩兩照坐成臺躔。", "苕霅交流卞山碧，一代名賢已陳迹。", "我後百年登此堂，咀嚼姓名牙頰香。", "坐上何曾欠佳客，蘇仙一去難再得。"]'),
('fe9856c7-f9e1-4611-b0c8-664d8961f094','送朱仲文運幹還蜀  其一','王十朋','宋','宋诗','song-poetry','','[]','分閫濫曾游蜀口，得朋深喜遇坤爻。',64,'全唐诗/poet.song.119000.json','["分閫濫曾游蜀口，得朋深喜遇坤爻。", "澹臺至室必公事，平仲與人能久交。", "一葉共乘夔到霅，四方相逐愈隨郊。", "姓名已在諸公齒，引類行看似拔茅。"]'),
('f14848e4-a4bc-43ce-b01a-a37bf58580d5','送朱仲文運幹還蜀  其二','王十朋','宋','宋诗','song-poetry','','[]','君歸應過無喧室，我夢遥馳無隠齋。',64,'全唐诗/poet.song.119000.json','["君歸應過無喧室，我夢遥馳無隠齋。", "带得江山在詩卷，種成楊柳繫離懷。", "定先春到夔門裏，莫遣音踈霅水涯。", "故舊相逢倘相問，爲言老欲乞殘骸。"]'),
('c597f583-a34c-4670-989e-008528f1b2e2','讀喻叔奇遊廬山詩  其一','王十朋','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','前年我亦到廬山，杖屨烟霞縹緲間。',32,'全唐诗/poet.song.119000.json','["前年我亦到廬山，杖屨烟霞縹緲間。", "萬里東歸如倦鳥，不知飛過只知還。"]'),
('d3538bb9-5471-448c-ab31-5b9e212dbee4','讀喻叔奇遊廬山詩  其二','王十朋','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','路經湓浦嘆怱怱，不及從君訪遠公。',32,'全唐诗/poet.song.119000.json','["路經湓浦嘆怱怱，不及從君訪遠公。", "忽見廬山真面目，在君二十一時中。"]'),
('cf3283bc-a5a5-4f63-8633-6ff8708152c0','十月晦日會凌季文沈德和二尚書劉汝一大諫于六客堂','王十朋','宋','宋诗','song-poetry','','[]','夢寐思賢願與齊，一麾來守浙江西。',64,'全唐诗/poet.song.119000.json','["夢寐思賢願與齊，一麾來守浙江西。", "星躔舊識尚書履，玉府曾親太一藜。", "天遣門生依坐主，心隨峽水注苕溪。", "邦人異日談遺事，名姓應同六客題。"]'),
('8d3ef152-a8b1-408c-92b8-02f171f4c7e8','沈書和詩再用韻','王十朋','宋','宋诗','song-poetry','','[]','先生名與卞山齊，賤子來歸自瀼西。',64,'全唐诗/poet.song.119000.json','["先生名與卞山齊，賤子來歸自瀼西。", "自媿蒹葭難倚玉，暫教松柏俯同藜。", "萬言讜論驚天闕，八詠高才壓婺溪。", "柳惲蘇仙舊吟處，願陪杖屨徧留題。"]'),
('5b71f80e-2211-4d38-ba6f-ccfe3759b2a1','凌書和詩復用韻','王十朋','宋','宋诗','song-poetry','','[]','人物堂堂大國齊，難窺賜履地東西。',64,'全唐诗/poet.song.119000.json','["人物堂堂大國齊，難窺賜履地東西。", "心才遇日即傾藿，身或在山誰采藜。", "隠德猶能及枯骨，安車行見起磻溪。", "後生何幸依先達，誤辱山公一字題。"]'),
('030459c6-09ec-445c-855d-d189a30dee94','劉汝一和詩復用韻','王十朋','宋','宋诗','song-poetry','','[]','魯酒三盃却到齊，詩壇老將勝山西。',64,'全唐诗/poet.song.119000.json','["魯酒三盃却到齊，詩壇老將勝山西。", "氣餘殿上欲折檻，清見胸中不糝藜。", "聊復忘機對禪榻，未應采藥赴桃溪。", "吾儕會合真天意，清絕湖山盡共題。"]'),
('50e480db-91c0-43d0-a575-3467e954d0f6','十一月十日會于六客堂者十人宋子飛徐致雲章茂卿鄧叔厚莫子登俞仲明許子齊沈虞卿鄭壽淑酒三行予得詩','王十朋','宋','宋诗','song-poetry','','[]','六客高風不可追，吾儕生恨百年遲。',64,'全唐诗/poet.song.119000.json','["六客高風不可追，吾儕生恨百年遲。", "星光月滿舊游處，簪盍蓂開盈數時。", "訪古已仙圖上鶴，得朋今遇易中龜。", "吾夫子道欲墜地，不是四科誰與持。"]'),
('8b8dd1ef-24db-4999-9010-a256e9872453','汝一和十客詩語及貢院復用前韻','王十朋','宋','宋诗','song-poetry','','[]','洙泗家風尚可追，未應吾道便陵遲。',64,'全唐诗/poet.song.119000.json','["洙泗家風尚可追，未應吾道便陵遲。", "要令士有歡顔地，如見公爲舉首時。", "山遶苕溪翻振鷺，水通震澤錫神龜。", "眼中突兀行將見，大厦端由衆木持。"]'),
('2ddacefd-25f1-4067-9d75-a61b0cebf691','晦日會于六客堂者十二人','王十朋','宋','宋诗','song-poetry','','[]','湖山清絕多佳士，暇日壺觴得共携。',64,'全唐诗/poet.song.119000.json','["湖山清絕多佳士，暇日壺觴得共携。", "堂上合成前後客，詩中分得建除題。", "不容閏位參卿月，坐覺巫山在霅溪。", "麟閣功名屬公輩，老夫惟願把鋤犁。"]'),
('6d1283f0-8cd4-4a39-bcb7-266435a9564d','次韻張叔清見寄','王十朋','宋','宋诗','song-poetry','','[]','太學年時識一夔，婺溪摻別越三朞。',64,'全唐诗/poet.song.119000.json','["太學年時識一夔，婺溪摻別越三朞。", "閩中大府子爲掾，峽內孤城予把麾。", "去隔關山共明月，歸逢魚雁寄新詩。", "苕溪昨夜梅花發，目對清標有所思。"]'),
('35ade19a-f51c-47b0-beb2-553aac1e869a','次韻林明仲見寄','王十朋','宋','宋诗','song-poetry','','[]','憶昔相逢未白頭，別來歲月迅如流。',64,'全唐诗/poet.song.119000.json','["憶昔相逢未白頭，別來歲月迅如流。", "自從江左分符去，長念城南載酒遊。", "君似老松姿耐雪，我猶弱柳葉經秋。", "梅溪梅嶼不相遠，歸去定乘尋戴舟。"]'),
('984c17ec-23bb-47ef-8ebc-deb6dc313a9c','貢院上梁','王十朋','宋','宋诗','song-poetry','','[]','清絕湖山映白蘋，翬飛梁棟眼中新。',64,'全唐诗/poet.song.119000.json','["清絕湖山映白蘋，翬飛梁棟眼中新。", "雪花先作曉來瑞，桂魄正圓天上輪。", "夫子廟還元氣象，水晶宮發舊精神。", "書生戰藝真餘事，移孝爲忠要致身。"]'),
('1a48c340-432b-4a67-a1a9-febd2c1f563c','諸公和詩再用韻并簡沈虞卿教授','王十朋','宋','宋诗','song-poetry','','[]','來采汀洲柳惲蘋，要觀草色賜袍新。',64,'全唐诗/poet.song.119000.json','["來采汀洲柳惲蘋，要觀草色賜袍新。", "士由德行首科第，木就方圓在梓輪。", "山峙浮圖聳千佛，水迎仙子上三神。", "耽耽廣厦榮歸日，應話林泉老病身。"]'),
('d5310bd2-7864-49cb-b279-13f95149f817','寄夔州張君玉撫幹','王十朋','宋','宋诗','song-poetry','','[]','天上張公子，同僚半載餘。',48,'全唐诗/poet.song.119000.json','["天上張公子，同僚半載餘。", "令人思灧澦，有客泛芙蕖。", "一自離夔子，頻蒙寄鯉魚。", "江山元不遠，面目在來書。"]'),
('725469cb-0fda-4c88-98d7-c4108c7c5735','送張光大赴長沙簿','王十朋','宋','宋诗','song-poetry','','[]','同舍張公子，長沙遠宦游。',48,'全唐诗/poet.song.119000.json','["同舍張公子，長沙遠宦游。", "讀書真有用，謀道了無憂。", "賦鵩休悲賈，棲鸞暫屈仇。", "薦章行引類，文帥是鼇頭。"]'),
('f3feac68-9cd1-4e11-96d2-5cfe859570d6','送柑姚子才','王十朋','宋','宋诗','song-poetry','','[]','少年懷橘獻慈親，今見黄柑淚滿巾。',32,'全唐诗/poet.song.119000.json','["少年懷橘獻慈親，今見黄柑淚滿巾。", "同舍故人堂有母，可能羅帕不分珍。"]'),
('e42ec724-3d46-4a2e-af72-eb1b550035dc','過孺人挽詞  其一','王十朋','宋','宋诗','song-poetry','','[]','扁舟昔訪戴逵居，早識奇兒骨相殊。',64,'全唐诗/poet.song.119000.json','["扁舟昔訪戴逵居，早識奇兒骨相殊。", "不是剡溪能藴秀，祇應蚌腹解生珠。", "家從機斷知爲學，身自鷄鳴起奉姑。", "儒術登科有猶子，大書遺懿照龜趺。"]'),
('cefaa251-d86c-4743-a542-2152ff021285','過孺人挽詞  其二','王十朋','宋','宋诗','song-poetry','','[]','過從有夏孕遺芳，作配于周婦德良。',64,'全唐诗/poet.song.119000.json','["過從有夏孕遺芳，作配于周婦德良。", "目不泛觀惟貝葉，舍無他物有天香。", "魚軒欲動喜家近，烏冢忽歸驚夜長。", "年到古希子孫足，人生如此尚何傷。"]'),
('e5b06007-8d52-49ae-8397-b2f32356469b','重刊戒石銘  其一','王十朋','宋','宋诗','song-poetry','','[]','戒石重刊照眼明，良辰又遇臘嘉平。',32,'全唐诗/poet.song.119000.json','["戒石重刊照眼明，良辰又遇臘嘉平。", "黄堂坐處天威近，一點欺心事莫萌。"]'),
('7003b83b-b03e-400b-8093-648db24720a1','重刊戒石銘  其二','王十朋','宋','宋诗','song-poetry','','[]','淫浸秋潦壞垂成，忍聽閭閻愁嘆聲。',32,'全唐诗/poet.song.119000.json','["淫浸秋潦壞垂成，忍聽閭閻愁嘆聲。", "撫字催科勞更拙，欲逃吏責負斯銘。"]'),
('d749e3c7-ab42-4ac4-ac4f-eca7e6590f46','謁顔魯公祠','王十朋','宋','宋诗','song-poetry','','[]','卞山苕溪高且清，魯公祠堂貌如生。',64,'全唐诗/poet.song.119000.json','["卞山苕溪高且清，魯公祠堂貌如生。", "言言千古英雄在，吉吉一點仙丹成。", "姦臣必欲置之死，天下不敢呼其名。", "當時節義誰可並，常山太守公難兄。"]'),
('b8f39468-b3fc-4977-994d-e2f0c106db35','懷忠堂','王十朋','宋','宋诗','song-poetry','','[]','嚴霜日烈與時乖，前後姦邪屢見排。',32,'全唐诗/poet.song.119000.json','["嚴霜日烈與時乖，前後姦邪屢見排。", "苕霅祠堂境清絕，孤忠千古有人懷。"]'),
('1dcbd555-36f3-4b7e-af61-42cca3c16b51','放生池','王十朋','宋','宋诗','song-poetry','','[]','畏死貪生物我同，仁心要在擴而充。',32,'全唐诗/poet.song.119000.json','["畏死貪生物我同，仁心要在擴而充。", "江湖魚鱉知多少，盡在恩波浩渺中。"]'),
('d9ef3834-e3fc-48f1-a667-cd3b7e817af4','次韵翁東叟知縣見寄并簡戴俊仲  其一','王十朋','宋','宋诗','song-poetry','','[]','濫把江東蜀口麾，中原入望涕頻揮。',64,'全唐诗/poet.song.119000.json','["濫把江東蜀口麾，中原入望涕頻揮。", "每嗟風俗愧東晉，那得功名如合肥。", "賢士憂時尚家食，聖君求治正宵衣。", "腐儒老矣身多病，日日言歸猶未歸。"]'),
('aa820873-b97c-436b-982c-599fc0f29bdc','次韵翁東叟知縣見寄并簡戴俊仲  其二','王十朋','宋','宋诗','song-poetry','','[]','年時我忝楚東守，邂逅君從湖北來。',64,'全唐诗/poet.song.119000.json','["年時我忝楚東守，邂逅君從湖北來。", "携手篇章擬蘇李，論交風義薄陳雷。", "棲遲百里淹賢甚，奔走三州覺老催。", "如見高人戴安道，爲言我意最憐才。"]'),
('8aefeead-0c13-4772-a796-e745be63ed5c','送師教授','王十朋','宋','宋诗','song-poetry','','[]','同年四百二十六，尊酒相逢得我師。',64,'全唐诗/poet.song.119000.json','["同年四百二十六，尊酒相逢得我師。", "方喜書來自天目，忽驚人去向峨眉。", "囊開蜀錦留佳句，棹拂汀蘋索惡詩。", "莫道冷官無一物，扁舟遥載義風歸。"]'),
('d002b15f-a9e9-40cc-b3b3-a57bd2dd33db','用貢院韻寄當塗吳給事明可','王十朋','宋','宋诗','song-poetry','','[]','鄉校當年與薦蘋，蕭臺氣象自公新。',64,'全唐诗/poet.song.119000.json','["鄉校當年與薦蘋，蕭臺氣象自公新。", "老成猶滯甘泉橐，晚進叨乘刺史輪。", "陸凱寄梅情愈重，謝公夢草句尤神。", "何時更作龍門客，共話樽前見在身。"]'),
('35fc5d25-47b9-47ef-a85f-0d5b20ec295b','王夷仲校書挽詞  其一','王十朋','宋','宋诗','song-poetry','','[]','同姓同年友，吾心久已降。',48,'全唐诗/poet.song.119000.json','["同姓同年友，吾心久已降。", "賓王誤第四，江夏本無雙。", "刺不投東閣，吟惟坐北窗。", "胸中藴經濟，可惜未施邦。"]'),
('c98bd655-be1e-4f1f-8eb9-5191c377c7c6','王夷仲校書挽詞  其二','王十朋','宋','宋诗','song-poetry','','[]','明月雙溪地，三年兩度逢。',48,'全唐诗/poet.song.119000.json','["明月雙溪地，三年兩度逢。", "君登群玉府，我到白鹽峯。", "方喜書傳鯉，俄驚劒化龍。", "守符嗟未解，執紼恨無從。"]'),
('d4fc266c-7eb6-4d77-af91-1abd10123042','仲冬釋奠于學同諸公登稽古閣觀弁山望太湖閲壁上題名誦范文正公吳興先生富道德詵詵弟子皆賢才之句','王十朋','宋','宋诗','song-poetry','','["\u592a\u6e56"]','吳興學校規模壯，安定先生道德崇。',64,'全唐诗/poet.song.119000.json','["吳興學校規模壯，安定先生道德崇。", "苕霅溪同洙泗水，汀洲蘋有藻芹風。", "山知尊道猶端弁，湖欲依光故近宮。", "壁上題名觀尚友，諸儒事業聖賢中。"]'),
('74a9a111-d0b0-4a10-af00-4a2cd10cc28b','次韻錢郎中豫六客堂碧瀾堂二絕  其一','王十朋','宋','宋诗','song-poetry','','[]','六客高風久已無，花間誰對謫仙壺。',32,'全唐诗/poet.song.119000.json','["六客高風久已無，花間誰對謫仙壺。", "星躔一夕光芒動，如有仙舟入畫圖。"]'),
('07a35f17-734c-4c94-97fd-08006ea2ea4b','次韻錢郎中豫六客堂碧瀾堂二絕  其二','王十朋','宋','宋诗','song-poetry','','[]','一樽相對眼俱明，細話同僚舊日情。',32,'全唐诗/poet.song.119000.json','["一樽相對眼俱明，細話同僚舊日情。", "漢世郎官亦華髮，恨無詩句似君清。"]'),
('08760a99-6c07-4d0d-bd53-c6cd5ad2e6ee','錢再賦二詩復用前韻錢云家無置錐之地寓居僧舍有爲題米疏者  其一','王十朋','宋','宋诗','song-poetry','','[]','老來官况兩俱無，惟有詩情寄酒壺。',32,'全唐诗/poet.song.119000.json','["老來官况兩俱無，惟有詩情寄酒壺。", "記取碧瀾堂上語，衣冠早掛亦良圖。"]'),
('e41c180f-b243-44fa-a084-5d5ac25aa949','錢再賦二詩復用前韻錢云家無置錐之地寓居僧舍有爲題米疏者  其二','王十朋','宋','宋诗','song-poetry','','[]','無田種秫似淵明，却說歸耕似不情。',32,'全唐诗/poet.song.119000.json','["無田種秫似淵明，却說歸耕似不情。", "食粥魯公宜乞米，不妨千載有餘清。"]'),
('4783e832-c3c6-47fc-b776-68ef68738a8e','送柴常之赴汀州教官','王十朋','宋','宋诗','song-poetry','','[]','有客神珠玉，訪予雲水鄉。',48,'全唐诗/poet.song.119000.json','["有客神珠玉，訪予雲水鄉。", "虞庠同舍友，虎榜甲科郎。", "送別汀蘋白，之官芹藻香。", "南溟九萬里，拭目看翱翔。"]'),
('67cdff26-2664-491d-847d-412e96140e93','送朱舜卿赴汀州司戶','王十朋','宋','宋诗','song-poetry','','[]','家塾游從久，賢關聲譽馳。',48,'全唐诗/poet.song.119000.json','["家塾游從久，賢關聲譽馳。", "初官三語掾，餘事九章辭。", "子正强而仕，予嗟久矣衰。", "願言行所學，滿慰素相期。"]'),
('97328700-199a-43b0-b86b-a5ecc9661f44','二月望日欲勞農于弁山會風雨作遂出南門因登峴山觀漥尊訪五花亭遺迹晚霽游何山觀讀書堂薄暮而還  其一','王十朋','宋','宋诗','song-poetry','','[]','卞山龍欲阻吾行，怪雨盲風不肯晴。',32,'全唐诗/poet.song.119000.json','["卞山龍欲阻吾行，怪雨盲風不肯晴。", "但得出郊脩故事，此中亦可勸深耕。"]'),
('cef58b02-5963-4146-b432-a2fa063d9d67','二月望日欲勞農于弁山會風雨作遂出南門因登峴山觀漥尊訪五花亭遺迹晚霽游何山觀讀書堂薄暮而還  其二','王十朋','宋','宋诗','song-poetry','','[]','天遣吾來此勞農，要令遺躅訪顔公。',32,'全唐诗/poet.song.119000.json','["天遣吾來此勞農，要令遺躅訪顔公。", "雖無二十四賓客，詩酒略追前輩風。"]'),
('2673cc35-6f0a-44af-89c4-78c371726f8a','二月望日欲勞農于弁山會風雨作遂出南門因登峴山觀漥尊訪五花亭遺迹晚霽游何山觀讀書堂薄暮而還  其三','王十朋','宋','宋诗','song-poetry','','[]','久欲歸耕竟未歸，又吟苕霅勸農詩。',32,'全唐诗/poet.song.119000.json','["久欲歸耕竟未歸，又吟苕霅勸農詩。", "流錢腐粟慚無術，稼穡艱難或稍知。"]'),
('3d30cadd-2a1c-4154-80d7-fce95558d0dd','勞農峴山乘興游何山同行宋子飛沈虞卿霍從周范文質','王十朋','宋','宋诗','song-poetry','','[]','去秋遊道場，俯瞰何山路。',144,'全唐诗/poet.song.119000.json','["去秋遊道場，俯瞰何山路。", "林泉雖在眼，未暇飛杖屨。", "塵埃汩城市，遥望隔烟霧。", "春光忽已半，播穀催農務。", "欲作卞山行，偶逢風伯怒。", "肩輿出城南，乘興訪幽趣。", "山藏佛屋深，迹躡陳朝故。", "老松不記年，脩竹莫知數。", "鳥鳴說法池，花落在禪處。", "書空何公堂，木拱安定墓。", "青山看未足，回首日已暮。", "小溪何處是，歸誦蘇仙句。"]'),
('48e60d37-1a39-40d7-bde0-c07b178e6c02','寄沈虞卿寒食上安定冢','王十朋','宋','宋诗','song-poetry','','[]','先生宋儒宗，風義起人聳。',48,'全唐诗/poet.song.119000.json','["先生宋儒宗，風義起人聳。", "何山如孔林，世俗豈知重。", "廣文領諸生，寒食親上冢。", "我獨不得行，爲義慙無勇。"]'),
('27e60e55-3b4c-4fdc-8431-137270fb1774','登清風樓呈通判宋子飛','王十朋','宋','宋诗','song-poetry','','[]','苕霅水會處，樓高風快哉。',48,'全唐诗/poet.song.119000.json','["苕霅水會處，樓高風快哉。", "洲中白蘋動，天半故人來。", "穆入周臣頌，雄勝楚客臺。", "飄飄玉川子，乘興上蓬萊。"]'),
('3393da12-fa9b-4a83-a140-dad86a868bd0','郡僚展餞席上賦詩','王十朋','宋','宋诗','song-poetry','','[]','五年三郡厭驅馳，聖主隆恩許奉祠。',64,'全唐诗/poet.song.119000.json','["五年三郡厭驅馳，聖主隆恩許奉祠。", "孤嶼衆山重對酒，清風明月欠吟詩。", "心勞撫字政尤拙，田不荒蕪去亦宜。", "餞別同僚三十二，雲臺功業滿相期。"]'),
('585b4a11-372e-4c1c-9e2e-963ef671af8a','父老','王十朋','宋','宋诗','song-poetry','','[]','父老自何處，同來送使君。',120,'全唐诗/poet.song.119000.json','["父老自何處，同來送使君。", "手中一爐香，敬爲使君焚。", "使君無善政，父老何慇懃。", "同辭答使君，去秋稼如雲。", "淫雨害垂成，一年計徒勤。", "使君體上意，租苗放三分。", "父子免流離，歡然事耕耘。", "年凶米不貴，夜靜犬不聞。", "顰眉答父老，正緣此紛紛。", "黄堂非坐處，歸歟老桑枌。"]'),
('7ca6638f-5507-40fc-91a9-78b4b011ff69','至德清懷送別諸公','王十朋','宋','宋诗','song-poetry','','["\u592a\u6e56"]','舟泝餘不水，回頭憶兩溪。',48,'全唐诗/poet.song.119000.json','["舟泝餘不水，回頭憶兩溪。", "川長太湖隔，天遠卞峯迷。", "左顧龜何在，南飛烏欲棲。", "從今到家夢，却到浙江西。"]'),
('a7356ce4-0e8f-409c-9b50-9a26c89667b2','金仙院','王十朋','宋','宋诗','song-poetry','','[]','金仙何處不曾游，小小精藍亦自幽。',32,'全唐诗/poet.song.119000.json','["金仙何處不曾游，小小精藍亦自幽。", "有客倦游歸欲速，可能一宿爲山留。"]'),
('3c77c2db-7a9d-401d-ac2f-8b9844992334','宿妙庭觀','王十朋','宋','宋诗','song-poetry','','[]','小小琳宮氣象清，雲軿遐想董雙成。',64,'全唐诗/poet.song.119000.json','["小小琳宮氣象清，雲軿遐想董雙成。", "靈丹煉就覆金鼎，仙鶴歸來聞玉笙。", "兩絕老坡吟處境，千秋太白曲中名。", "塵埃奔走東歸客，寄卧一庵聽雨聲。"]'),
('0f1a78db-607d-4a02-9202-2d4dc81af81b','宿富春舟中','王十朋','宋','宋诗','song-poetry','','[]','苦雨冷朱夏，小舟眠富春。',24,'全唐诗/poet.song.119000.json','["苦雨冷朱夏，小舟眠富春。", "餘生今可樂，歸作太平人。"]'),
('c64885c4-0c45-4e0d-852b-b256b89dcb17','泊桐廬分水港','王十朋','宋','宋诗','song-poetry','','[]','何處繫歸舟，桐廬舊日游。',48,'全唐诗/poet.song.119000.json','["何處繫歸舟，桐廬舊日游。", "港從分水出，亭瞰合江流。", "疊嶂雲披絮，遥天月吐鈎。", "紛紛釣魚者，無復見羊裘。"]'),
('dc526a2e-9b2a-4445-80db-87d0964acad9','小瀑布','王十朋','宋','宋诗','song-poetry','','[]','釣瀨雲山外，巖花瀑布邊。',24,'全唐诗/poet.song.119000.json','["釣瀨雲山外，巖花瀑布邊。", "却疑方處士，詩思湧成泉。"]'),
('28393b50-5fea-40f2-bf83-1613200a65c6','釣臺三絕  其一','王十朋','宋','宋诗','song-poetry','','[]','聖主中興急用人，小臣無術贊經綸。',32,'全唐诗/poet.song.119000.json','["聖主中興急用人，小臣無術贊經綸。", "功名分付雲臺士，願學先生事隠淪。"]'),
('53371c86-54ba-4dbb-9691-aacee8e19c38','釣臺三絕  其二','王十朋','宋','宋诗','song-poetry','','[]','竊食三州媿不才，扁舟又過子陵臺。',32,'全唐诗/poet.song.119000.json','["竊食三州媿不才，扁舟又過子陵臺。", "心知敬慕先生節，乞得祠宮歸去來。"]'),
('9ea7b4b3-804b-43d8-b8b1-2fe7fa1c3c01','釣臺三絕  其三','王十朋','宋','宋诗','song-poetry','','[]','山水高長子陵節，桐廬蕭灑范公詩。',32,'全唐诗/poet.song.119000.json','["山水高長子陵節，桐廬蕭灑范公詩。", "又吟處士清新句，蟬拽殘聲過別枝。"]'),
('2bcaa834-e992-4376-8a08-69724c54cbbb','吳明可自當塗以詩見寄因次其韻  其一','王十朋','宋','宋诗','song-poetry','','[]','五年三郡厭間關，心逐東歸見雁山。',64,'全唐诗/poet.song.119000.json','["五年三郡厭間關，心逐東歸見雁山。", "力上祠章期得請，果回天意可投閑。", "踈慵似我宜歸去，名德如公合召還。", "珍重詩來二千里，義風高韻兩難攀。"]'),
('b27537b6-2650-42d2-9ca3-c9274221c480','吳明可自當塗以詩見寄因次其韻  其二','王十朋','宋','宋诗','song-poetry','','[]','夢到江南詠采蘋，眼中時事一番新。',64,'全唐诗/poet.song.119000.json','["夢到江南詠采蘋，眼中時事一番新。", "在官未幾髮就種，語別又成腸轉輪。", "老境衣冠宜掛壁，祠宮香火謾頤神。", "吳公治行今第一，也問君王欲乞身。"]'),
('9c2b64d2-c602-4a9c-afcd-af5e34bc585d','端午日陪柳嚴州登千峯榭  其一','王十朋','宋','宋诗','song-poetry','','[]','偶上千峯榭，遥思八陣臺。',24,'全唐诗/poet.song.119000.json','["偶上千峯榭，遥思八陣臺。", "去年重午日，僚友共銜杯。"]'),
('9f540efc-b253-4909-b965-b60684f4b98f','端午日陪柳嚴州登千峯榭  其二','王十朋','宋','宋诗','song-poetry','','[]','偶上千峯榭，因思小范公。',24,'全唐诗/poet.song.119000.json','["偶上千峯榭，因思小范公。", "桐廬蕭灑處，盡在十詩中。"]'),
('ae435d0d-d065-4eed-bf5d-896bc746c96f','端午日陪柳嚴州登千峯榭  其三','王十朋','宋','宋诗','song-poetry','','[]','偶上千峯榭，遥思六客堂。',24,'全唐诗/poet.song.119000.json','["偶上千峯榭，遥思六客堂。", "前時賦詩處，烟水路茫茫。"]'),
('6ad154dc-b16d-4435-85f8-ebc3040e518f','端午日陪柳嚴州登千峯榭  其四','王十朋','宋','宋诗','song-poetry','','[]','偶上千峯榭，當時恨不來。',24,'全唐诗/poet.song.119000.json','["偶上千峯榭，當時恨不來。", "使君留過客，高處酌金罍。"]'),
('f123ed86-3802-4c8f-9574-9125200aeff3','宿安流亭','王十朋','宋','宋诗','song-poetry','','[]','弭棹宿溪亭，全家夢寐驚。',24,'全唐诗/poet.song.119000.json','["弭棹宿溪亭，全家夢寐驚。", "明朝速解纜，莫待濁流平。"]'),
('c4a644d3-410e-4ec0-82ee-fbcf57e6179e','過老鼠岐  其一','王十朋','宋','宋诗','song-poetry','','[]','去年灘下黄牛峽，今日舟逢老鼠岐。',32,'全唐诗/poet.song.119000.json','["去年灘下黄牛峽，今日舟逢老鼠岐。", "莫恃巖崖起波浪，可無天定水平時。"]'),
('5600427b-fcb2-4dea-8019-d8d47230c589','過老鼠岐  其二','王十朋','宋','宋诗','song-poetry','','[]','風水雨俱逆，舟行何太稽。',24,'全唐诗/poet.song.119000.json','["風水雨俱逆，舟行何太稽。", "安心出三峽，破膽上雙溪。"]'),
('71f56ca2-b6e6-47da-843a-5c74e0cd8c5d','予至蘭溪買扇題歸去來字吏忽報有潘淵明相訪戲書二十字','王十朋','宋','宋诗','song-poetry','','[]','扇題歸去來，客遇潘淵明。',24,'全唐诗/poet.song.119000.json','["扇題歸去來，客遇潘淵明。", "舉扇謝佳客，歸耕吾已成。"]'),
('fae7450b-eed6-4c42-8278-e70c9c008ce4','泝婺溪同年雍堯佐周堯夫同王與道尚書子姪拏舟來迓','王十朋','宋','宋诗','song-poetry','','[]','路入雙溪暑氣清，故人短棹遠相迎。',32,'全唐诗/poet.song.119000.json','["路入雙溪暑氣清，故人短棹遠相迎。", "隔船認我疑非我，白髮當時尚未生。"]'),
('f5e86bed-1d79-4308-a1e9-07399d37b317','婺女廣文官舍舊有五柳蕭侍郎德起爲教官時取以名堂歲月浸久柳既剪伐名亦更矣周堯夫欲復其舊詩以贊之','王十朋','宋','宋诗','song-poetry','','[]','何人栽五柳，雅目自蕭公。',48,'全唐诗/poet.song.119000.json','["何人栽五柳，雅目自蕭公。", "要使廣文舍，長存彭澤風。", "名因賢者復，趣與昔人同。", "留取先生傳，他年國史中。"]'),
('6873e63a-3db9-47c4-85a1-52537acbbd2d','戊子八月二日得泉州','王十朋','宋','宋诗','song-poetry','','[]','五年符竹換三州，乞得祠宮欲少休。',32,'全唐诗/poet.song.119000.json','["五年符竹換三州，乞得祠宮欲少休。", "名姓誤蒙君相記，泉南千里又分憂。"]'),
('987a487f-b3b6-4baa-abb7-c78594fe61ac','解舟','王十朋','宋','宋诗','song-poetry','','[]','解舟城之南，橙橘半青黄。',144,'全唐诗/poet.song.119000.json','["解舟城之南，橙橘半青黄。", "時節豈不好，胡爲辭故鄉。", "親朋送我行，殷勤餽壺觴。", "我欲與之飲，舟去留靡遑。", "僮僕別我歸，黯然顔色傷。", "問我何時還，田園又成荒。", "我心媿其言，老矣身皇皇。", "五載走三州，道路險且長。", "屢請方得祠，暫歸又懷章。", "挈家入南閩，兒女不盡將。", "餘生疾病多，滿鏡鬚髯蒼。", "到官即有乞，行將返耕桑。"]'),
('704d6256-bb7e-473b-80b1-c5aa50bb7267','過瑞安','王十朋','宋','宋诗','song-poetry','','[]','我家古樂成，老未識安固。',168,'全唐诗/poet.song.119000.json','["我家古樂成，老未識安固。", "偶把清源麾，首問南塘路。", "解維日已晏，入境天欲莫。", "張子自陶山，扁舟惠然顧。", "沈君壯年別，相見髮垂素。", "訪舊多不存，來觀莫知數。", "平原二十人，邂逅喜相遇。", "謂我宜少留，欲敕不腆具。", "我驅不敢疾，曲爲一宵住。", "臨江有高閣，登覽可以賦。", "瀾同孟子觀，目作少陵注。", "燈火照魚龍，談笑驚鷗鷺。", "銜盃鄉意濃，竊食君恩誤。", "晨起酒未醒，潮來報催渡。"]'),
('4472f2a6-36d1-4b12-b48f-be57923da0fe','贈沈敦謨','王十朋','宋','宋诗','song-poetry','','[]','三十年前硯席同，懷人長在夢魂中。',64,'全唐诗/poet.song.119000.json','["三十年前硯席同，懷人長在夢魂中。", "徒勞州縣知何補，高蹈丘園不是窮。", "歷問舊游多故鬼，偶餘我輩亦衰翁。", "相逢又却怱怱別，無復從容似泮宮。"]'),
('21e03c3f-d6fd-4497-89d0-42d74425a220','觀潮閣','王十朋','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','高臨無地屹山腰，今古知觀幾度潮。',64,'全唐诗/poet.song.119000.json','["高臨無地屹山腰，今古知觀幾度潮。", "水鑑掛空波正滿，鯨魚八穴浪還消。", "雷初出地神龍怒，銀忽成山海若驕。", "聖世風濤合平靜，不應泛溢似唐朝。"]'),
('97997a88-d62f-4f3d-8ca7-98217a6b196f','訪曹夢良','王十朋','宋','宋诗','song-poetry','','[]','我自簫峯下，遥來訪許峯。',48,'全唐诗/poet.song.119000.json','["我自簫峯下，遥來訪許峯。", "川塗何敢憚，筆硯久相從。", "故里行將遠，吾人豈易逢。", "何當繼韓孟，相逐似雲龍。"]'),
('11809fe9-cc4c-4005-a8ee-77b583197a53','鳳凰巖','王十朋','宋','宋诗','song-poetry','','[]','鳳鳥久不至，胡爲於此藏。',24,'全唐诗/poet.song.119000.json','["鳳鳥久不至，胡爲於此藏。", "德輝如可覽，應不戀高崗。"]'),
('af689e04-d194-41ca-8e5e-1408b6ebf53c','蕭家渡','王十朋','宋','宋诗','song-poetry','','[]','渡頭問舟子，此渡胡名蕭。',144,'全唐诗/poet.song.119000.json','["渡頭問舟子，此渡胡名蕭。", "舟子笑答我，使君家匪遥。", "豈不聞侍郎，名德重本朝。", "屢爲二千石，兩至萬里橋。", "渡旁乃其宅，人亡木惟喬。", "陰德滿鄉閭，嘉話傳魚樵。", "江水流有盡，姓名磨不消。", "近同池號謝，遠類江稱姚。", "赧顔謝舟子，講聞非一朝。", "恨生晚且賤，無繇際清標。", "坡公不識范，韓子思之僑。", "敬瞻通德門，魂徃不可招。"]'),
('3e8b021e-2ef9-4c88-a249-00dcb9e70151','入長溪境','王十朋','宋','宋诗','song-poetry','','[]','老矣倦游宦，入閩如山川。',48,'全唐诗/poet.song.119000.json','["老矣倦游宦，入閩如山川。", "三山疑隔海，九嶺類鑽天。", "種稻到山頂，栽松侵日邊。", "溪長水無盡，前更有清泉。"]'),
('0ee7b0cb-2d39-4dd0-860b-e169e466c893','贈程天祐秀才','王十朋','宋','宋诗','song-poetry','','[]','程生嗜好與人殊，杖屨遥遥訪我廬。',32,'全唐诗/poet.song.119000.json','["程生嗜好與人殊，杖屨遥遥訪我廬。", "不踏槐花隨舉子，手持醫國惠民書。"]'),
('4478540c-910f-4b33-943f-62e05a669af9','宿飯溪驛  其一','王十朋','宋','宋诗','song-poetry','','[]','甑嶼飽曾見，飯溪名始聞。',24,'全唐诗/poet.song.119000.json','["甑嶼飽曾見，飯溪名始聞。", "老懷如子美，到處不忘君。"]'),
('705699be-b56b-4ca4-bb70-83450b4d67a3','宿飯溪驛  其二','王十朋','宋','宋诗','song-poetry','','[]','門擁千峯翠，溪無一點塵。',24,'全唐诗/poet.song.119000.json','["門擁千峯翠，溪無一點塵。", "松風清入耳，山月白隨人。"]'),
('781f0db2-f7e9-4be9-8230-ef8cb4273be3','宿雙巖寺','王十朋','宋','宋诗','song-poetry','','[]','崎嶇九嶺更雙巖，遥望閩山未見三。',32,'全唐诗/poet.song.119000.json','["崎嶇九嶺更雙巖，遥望閩山未見三。", "來訪神鍾隠見處，翠微深鎖古精藍。"]'),
('2fda81f8-a8bb-472d-a777-5601bc34f128','至福唐會鄉人丁鎮叔張器先甄雲卿項用中趙知錄薛主簿同年孫彥忠草酌試院','王十朋','宋','宋诗','song-poetry','','[]','一同年友七鄉人，勸酒那容耳不聞。',64,'全唐诗/poet.song.119000.json','["一同年友七鄉人，勸酒那容耳不聞。", "尚齒自驚多白髮，論文堪笑有紅裙。", "詩篇共約題孤嶼，游宦猶疑在五雲。", "此會此時寧易得，明朝風月兩州分。"]'),
('91a21fc0-2bfb-4523-a54a-20be9af2c855','宿真隠寺','王十朋','宋','宋诗','song-poetry','','[]','我亦欲真隠，區區愧此身。',24,'全唐诗/poet.song.119000.json','["我亦欲真隠，區區愧此身。", "山林與城市，何處隠非真。"]'),
('370b0f57-61a8-4afd-8c11-48193a0caed2','飯枕峯  其一','王十朋','宋','宋诗','song-poetry','','[]','門外峯如枕，宜眠清凈身。',24,'全唐诗/poet.song.119000.json','["門外峯如枕，宜眠清凈身。", "禪僧自面壁，誰是枕峯人。"]'),
('c5c2e8ad-6bf4-4e6a-b067-d934659b90b2','飯枕峯  其二','王十朋','宋','宋诗','song-poetry','','[]','飯罷怱怱別，勞生可奈何。',24,'全唐诗/poet.song.119000.json','["飯罷怱怱別，勞生可奈何。", "不能留一宿，有愧此峯多。"]'),
('2dc5d3a1-e19a-4c71-94d8-32be07c29717','宿囊山寺  其一','王十朋','宋','宋诗','song-poetry','','[]','荔子枝中古道場，石門有路探懸囊。',32,'全唐诗/poet.song.119000.json','["荔子枝中古道場，石門有路探懸囊。", "怱怱不著游山屐，只辦嵩呼一瓣香。"]'),
('cacbeb88-b5ba-45f6-9b81-32403a56655f','宿囊山寺  其二','王十朋','宋','宋诗','song-poetry','','[]','我來萬籟正號風，壁上觀詩憶蔡公。',32,'全唐诗/poet.song.119000.json','["我來萬籟正號風，壁上觀詩憶蔡公。", "惟有秋林舊時月，夜深猶照梵王宮。"]'),
('385b69cf-5ec9-41e9-b450-d9fc5668848b','過蔡端明故居','王十朋','宋','宋诗','song-poetry','','[]','懷章南過蔡公鄉，駐馬遥瞻數仞牆。',64,'全唐诗/poet.song.119000.json','["懷章南過蔡公鄉，駐馬遥瞻數仞牆。", "丹荔株株經品藻，喬松葉葉惠清凉。", "四賢詩出人增氣，三諫章成國有光。", "真是濟川三昧手，清源游戯作虹梁。"]'),
('f7aef34c-df9e-41de-8950-cd6f5c862c6d','讌七邑宰','王十朋','宋','宋诗','song-poetry','','[]','九重宵旰愛民深，令尹宜懷撫字心。',32,'全唐诗/poet.song.119000.json','["九重宵旰愛民深，令尹宜懷撫字心。", "今日黄堂一盃酒，殷勤端爲慶民斟。"]'),
('47eadd9f-e356-4f7f-b0ee-f0193ad6df24','送赴省諸先輩','王十朋','宋','宋诗','song-poetry','','[]','國朝人物盛溫陵，秋賦呦呦鹿食苹。',64,'全唐诗/poet.song.119000.json','["國朝人物盛溫陵，秋賦呦呦鹿食苹。", "人倍平原門下士，文聯韓愈榜中名。", "丹墀何止三千字，雲翼行看九萬程。", "勸駕龍鍾老太守，籃輿準擬出郊迎。"]'),
('5a985191-60d5-4f38-9252-a02564dc4915','次韻夔漕趙若拙見寄  其一','王十朋','宋','宋诗','song-poetry','','[]','去秋移郡近家鄉，便殿狂言拜手敭。',64,'全唐诗/poet.song.119000.json','["去秋移郡近家鄉，便殿狂言拜手敭。", "何敢許身爲稷契，偶因論事及堯湯。", "民雖屢試如馮翊，詔未能焚愧益昌。", "乞得祠宮養衰病，夢中依舊坐黄堂。"]'),
('a96765ee-c8df-47c7-8272-b25316faf505','次韻夔漕趙若拙見寄  其二','王十朋','宋','宋诗','song-poetry','','[]','夔門邂逅恨怱怱，君駕重來我已東。',64,'全唐诗/poet.song.119000.json','["夔門邂逅恨怱怱，君駕重來我已東。", "陳迹徒勞長者記，清樽那復故人同。", "光華持節花溪上，老病分符佛國中。", "吾輩棲棲不黔突，此生休更問天公。"]'),
('afa1648a-f093-4a41-9f52-d7a12330792c','知宗生日','王十朋','宋','宋诗','song-poetry','','[]','天工未放二陽生，留得堯階一莢蓂。',64,'全唐诗/poet.song.119000.json','["天工未放二陽生，留得堯階一莢蓂。", "慶誕仙源貴公子，祥開南極老人星。", "日垂宮線添無盡，貌比莊椿看更清。", "歲歲華堂祝眉壽，笙歌聲裏雪梅馨。"]'),
('d365c54f-37fa-4a47-820e-a07a9e068db7','哭令人','王十朋','宋','宋诗','song-poetry','','[]','三十年間共苦辛，忽然驚斷夢中因。',64,'全唐诗/poet.song.119000.json','["三十年間共苦辛，忽然驚斷夢中因。", "鍾情正是我輩事，鼓缶忍同方外人。", "熊膽未酬平昔志，牛衣猶是向來貧。", "閩山滿眼同來路，木落風號淚滿巾。"]'),
('0448574f-cf36-4245-8a76-87c1978eea62','貢院車水築基諸公懼傷魚鼈活之別沼','王十朋','宋','宋诗','song-poetry','','[]','塞沼增基大厦成，群鮮亦免校人烹。',32,'全唐诗/poet.song.119000.json','["塞沼增基大厦成，群鮮亦免校人烹。", "洋洋圉圉諸公賜，要與吾君廣好生。"]'),
('39bf39a2-32c6-4344-b428-55b35fffc66a','出郊勸農  其一','王十朋','宋','宋诗','song-poetry','','[]','六年四郡勸農耕，自欲歸耕尚未成。',32,'全唐诗/poet.song.119000.json','["六年四郡勸農耕，自欲歸耕尚未成。", "游宦何如在家好，一廛從此願爲氓。"]'),
('5c267d81-edba-48c6-bbb7-08f2e22cd0e0','出郊勸農  其二','王十朋','宋','宋诗','song-poetry','','[]','守臣憂國願年豐，半刺雙鳬此念同。',32,'全唐诗/poet.song.119000.json','["守臣憂國願年豐，半刺雙鳬此念同。", "安得時暘時雨若，有生均在泰和中。"]'),
('d40bcf07-af34-4272-9fed-fb89cca61f8c','出郊勸農  其三','王十朋','宋','宋诗','song-poetry','','[]','小麥含花大麥黄，一年春事已相將。',32,'全唐诗/poet.song.119000.json','["小麥含花大麥黄，一年春事已相將。", "籃輿遍入三精舍，撥得公家半日忙。"]'),
('641effc9-5e61-4cb9-a4d4-bf5a0c03a0c9','出郊勸農  其四','王十朋','宋','宋诗','song-poetry','','[]','一千石俸竊南州，老病餘生厭宦游。',32,'全唐诗/poet.song.119000.json','["一千石俸竊南州，老病餘生厭宦游。", "已上祠章即歸去，一犁烟雨事西疇。"]'),
('6edac367-9c0d-4da3-9638-5a12b0b8d063','題靈秀峯禪院','王十朋','宋','宋诗','song-poetry','','[]','小小精藍亦自奇，一峯靈秀藴幽姿。',32,'全唐诗/poet.song.119000.json','["小小精藍亦自奇，一峯靈秀藴幽姿。", "無緣細聽山僧話，太守偷閑止片時。"]'),
('2faab440-e32b-43e7-bd64-0b767dba3a61','送九座訥老  其一','王十朋','宋','宋诗','song-poetry','','[]','禪老遥從九座來，一言爲我洗塵埃。',32,'全唐诗/poet.song.119000.json','["禪老遥從九座來，一言爲我洗塵埃。", "飄然又向山中去，白首相逢更幾回。"]'),
('cd49abf9-cd60-4d14-a5bd-554a2e6e5306','送九座訥老  其二','王十朋','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','至樂亭中半月留，溪山杖屨飽尋幽。',32,'全唐诗/poet.song.119000.json','["至樂亭中半月留，溪山杖屨飽尋幽。", "見師忽起廬山夢，夢向舊時游處游。"]'),
('7bc73598-7708-49ef-90db-589d98713908','崔肅之自湖至泉遷二親之喪歸葬詩以送之','王十朋','宋','宋诗','song-poetry','','[]','鄱水同僚舊，遥從霅水來。',48,'全唐诗/poet.song.119000.json','["鄱水同僚舊，遥從霅水來。", "異鄉欣覿面，清話洗銜哀。", "葱欝佳城就，勤勞孝子回。", "不應淹榷酤，中外正須才。"]'),
('44d49090-d315-4622-9b90-16663c56e4a4','夜聞子規痛念亡者','王十朋','宋','宋诗','song-poetry','','[]','夢覺音容杳莫追，子規聲裏涕霑衣。',32,'全唐诗/poet.song.119000.json','["夢覺音容杳莫追，子規聲裏涕霑衣。", "催歸無計同歸去，耘後耕前事已非。"]'),
('659ee005-7f93-459c-b462-1ed64c13d346','南宮揭榜溫陵得人爲盛提舶馬寺丞有詩贊喜次韻','王十朋','宋','宋诗','song-poetry','','[]','龍虎鄉邦地最靈，鯤鵬相繼上南溟。',64,'全唐诗/poet.song.119000.json','["龍虎鄉邦地最靈，鯤鵬相繼上南溟。", "已聞元凱賓虞國，行見淵騫冠孔庭。", "帝遣伏波持使節，天教平海會文星。", "鈴齋忽報捷音至，一炷清香千佛經。"]'),
('3be12e45-1c43-4326-a0cf-a3ce269034fb','諸公廷對甫邇復用前韻','王十朋','宋','宋诗','song-poetry','','[]','清源紫帽發英靈，萬斛詞源水注溟。',64,'全唐诗/poet.song.119000.json','["清源紫帽發英靈，萬斛詞源水注溟。", "遥想恩袍動草色，定知喜氣徹天庭。", "名高虎榜唐文傑，人半雲臺漢列星。", "累月笞兒幾翁嫗，夜深燈火督窮經。"]'),
('00274bf3-ad8c-4915-b73d-5137cc47d213','次韻知宗春陰','王十朋','宋','宋诗','song-poetry','','[]','行人怨雨農憂旱，永叔元之事可明。',64,'全唐诗/poet.song.119000.json','["行人怨雨農憂旱，永叔元之事可明。", "不歎花前無客飲，且欣郊外有農耕。", "知公興已烟霞重，顧我心尤勢利輕。", "天意稍佳民事急，總將行樂付宗盟。"]'),
('7a12bb22-0476-4a72-ac24-f3c110d2a4c5','次韻知宗游北山','王十朋','宋','宋诗','song-poetry','','[]','州北有山幽更幽，皇天閣雨爲公游。',64,'全唐诗/poet.song.119000.json','["州北有山幽更幽，皇天閣雨爲公游。", "登高如入上下竺，宴坐疑臨大小湫。", "掃地焚香烟縷嫋，煎泉瀹茗乳花浮。", "觀詩起我家山興，身在閩南夢在甌。"]'),
('950e12ba-7c7a-449d-86be-35778e8ea7c2','悼亡  其一','王十朋','宋','宋诗','song-poetry','','[]','燕寢焚香老病身，細君相對坐如賓。',32,'全唐诗/poet.song.119000.json','["燕寢焚香老病身，細君相對坐如賓。", "而今一榻維摩室，唯與無言法喜親。"]'),
('16cf661d-1857-4496-9caf-f271baa3de6e','悼亡  其二','王十朋','宋','宋诗','song-poetry','','[]','不見音容忽三月，無從涕泗已千行。',32,'全唐诗/poet.song.119000.json','["不見音容忽三月，無從涕泗已千行。", "家山準擬欲歸隠，堪嘆相隨無孟光。"]'),
('516252ac-42b7-4b9e-8928-5137930a7be5','悼亡  其三','王十朋','宋','宋诗','song-poetry','','[]','偕老相期未及期，回頭人事已成非。',32,'全唐诗/poet.song.119000.json','["偕老相期未及期，回頭人事已成非。", "逢春尚擬風光轉，過眼忽驚花片飛。"]'),
('5c5547cc-5a40-4293-af2d-2b1135803068','悼亡  其四','王十朋','宋','宋诗','song-poetry','','[]','夤緣偶作于飛侶，夢寐相隨到數州。',32,'全唐诗/poet.song.119000.json','["夤緣偶作于飛侶，夢寐相隨到數州。", "泥上迹留鴻已去，舟中刻在劍難求。"]'),
('5363aa8a-a51c-4ccb-961a-61fe70329638','次韻知宗酴醾','王十朋','宋','宋诗','song-poetry','','[]','萬斛虬珠眩眼明，傲春遲吐冠園英。',64,'全唐诗/poet.song.119000.json','["萬斛虬珠眩眼明，傲春遲吐冠園英。", "詩因居士價方重，酒賜名臣花遂榮。", "香異竹間吹細細，韻如堂上出盈盈。", "芳姿自可友蘭蕙，惜不當時遇獨清。"]'),
('c90cfaa6-8f8d-4757-899a-e4b4aadc6afb','游承天寺後園登月臺贈潛老  其一','王十朋','宋','宋诗','song-poetry','','[]','三徑荒蕪未許尋，籃輿來訪小園林。',32,'全唐诗/poet.song.119000.json','["三徑荒蕪未許尋，籃輿來訪小園林。", "因知燕寢凝香地，不似禪房花木深。"]'),
('550f2cf4-b738-4586-869d-c31e0d62fbf8','游承天寺後園登月臺贈潛老  其二','王十朋','宋','宋诗','song-poetry','','[]','月臺無屋有空壇，空處觀空眼界寬。',32,'全唐诗/poet.song.119000.json','["月臺無屋有空壇，空處觀空眼界寬。", "不惹世間塵一點，氷輪心鏡兩團團。"]'),
('d8a18ef5-ca43-43e6-be36-11114f4e679a','送賈巖老還鄉  其一','王十朋','宋','宋诗','song-poetry','','[]','閩江艱險嶺崔嵬，不憚衝寒冒雪來。',32,'全唐诗/poet.song.119000.json','["閩江艱險嶺崔嵬，不憚衝寒冒雪來。", "留我鈴齋兩三月，扁舟載得義風回。"]'),
('49a6ae4f-4ff9-4c3a-9040-afa3f21a017d','送賈巖老還鄉  其二','王十朋','宋','宋诗','song-poetry','','[]','堂上慈親數月違，片心遥逐白雲飛。',32,'全唐诗/poet.song.119000.json','["堂上慈親數月違，片心遥逐白雲飛。", "傷心盡聽秭歸鳥，難弟言歸秭不歸。"]'),
('e96d5f68-5263-4b07-bf4a-90becb677b6e','送賈巖老還鄉  其三','王十朋','宋','宋诗','song-poetry','','[]','乃翁賢德冠吾鄉，伯氏聲名藹上庠。',32,'全唐诗/poet.song.119000.json','["乃翁賢德冠吾鄉，伯氏聲名藹上庠。", "更喜君如里曾子，少年孝義已非常。"]'),
('7e8c81ae-99e3-48ac-8f80-48f6604ae928','送巖老出北門  其一','王十朋','宋','宋诗','song-poetry','','[]','暮春送客北山門，厭坐黄堂喜見村。',32,'全唐诗/poet.song.119000.json','["暮春送客北山門，厭坐黄堂喜見村。", "麥熟秧青農事急，十分歸興在田園。"]'),
('a07d5673-f430-46a2-b63e-5265bd07e892','送巖老出北門  其二','王十朋','宋','宋诗','song-poetry','','[]','客欲東歸出北門，又聞聯騎過西村。',32,'全唐诗/poet.song.119000.json','["客欲東歸出北門，又聞聯騎過西村。", "慇勤爲遣十從事，莫惜醉吟祇樹園。"]'),
('19cc35e8-6766-4d98-a9f8-1f72853a8252','送傅興化','王十朋','宋','宋诗','song-poetry','','[]','五馬躬迎八十親，甘棠如舊治惟新。',64,'全唐诗/poet.song.119000.json','["五馬躬迎八十親，甘棠如舊治惟新。", "歡傳此日來廉范，記得當時借寇恂。", "江海聊淹把麾手，廟堂無是薦賢入。", "送君爲守泉南守，政拙才踈藉寶鄰。"]'),
('95743640-a038-4bae-8e44-f6d6563aa3e0','曹夢良寄柑聞詩聞禮輩取以祭母哭泣不已','王十朋','宋','宋诗','song-poetry','','[]','嘉果遥來自故鄉，去冬初熟記同嘗。',32,'全唐诗/poet.song.119000.json','["嘉果遥來自故鄉，去冬初熟記同嘗。", "爾銜懷橘無窮恨，我亦傳柑念不忘。"]'),
('d07ba6e1-22fd-4d13-9203-098f14e42bde','四月八日貢院上梁','王十朋','宋','宋诗','song-poetry','','[]','廣厦初成萬柱標，脩梁巍跨玉虹腰。',64,'全唐诗/poet.song.119000.json','["廣厦初成萬柱標，脩梁巍跨玉虹腰。", "况逢此日生千佛，定引群仙上九霄。", "下筆蠶聲紛戰藝，出林鶑友競遷喬。", "清源人物從今盛，孝子忠臣滿聖朝。"]'),
('fbd5263b-f848-4c21-869b-41bb12bbc4fb','諸公和詩復用前韻  其一','王十朋','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','脩梁欲舉綵先標，聲撼春雷鼓百腰。',64,'全唐诗/poet.song.119000.json','["脩梁欲舉綵先標，聲撼春雷鼓百腰。", "谿蟄蛟龍欣得雨，桐棲鸞鳳合沖霄。", "清源水接南溟闊，紫帽山齊泰嶽喬。", "學不負人宜自勉，前賢勳業著三朝。"]'),
('e0125ee9-faa1-47b3-997f-e1982c6376c7','諸公和詩復用前韻  其二','王十朋','宋','宋诗','song-poetry','','[]','梁脊連年姓誤標，兩州騷客瘦吟腰。',64,'全唐诗/poet.song.119000.json','["梁脊連年姓誤標，兩州騷客瘦吟腰。", "月河月滿燕賀厦，佛國佛生虹掛霄。", "多士顔歡歌杜老，一輪香滿賦張喬。", "此途不止爲科第，名節崔嵬看立朝。"]'),
('c4f64f5c-061c-4085-846c-1653bffce349','悼亡  其一','王十朋','宋','宋诗','song-poetry','','[]','傷哉無復見，老矣不成偕。',24,'全唐诗/poet.song.119000.json','["傷哉無復見，老矣不成偕。", "牢落凝香地，同誰話此懷。"]'),
('9d6959e4-146b-4b90-84ae-7c3020decc78','悼亡  其二','王十朋','宋','宋诗','song-poetry','','[]','相勉惟清白，囊如四壁空。',24,'全唐诗/poet.song.119000.json','["相勉惟清白，囊如四壁空。", "難忘將絕語，勸我莫言窮。"]'),
('747fb361-dfc5-4a8c-a986-c915802e4b2e','薛士昭主管母夫人加封送酒爲壽薛有詩謝次韻以酬','王十朋','宋','宋诗','song-poetry','','[]','慶事公家奕世傳，生封錦告出甘泉。',64,'全唐诗/poet.song.119000.json','["慶事公家奕世傳，生封錦告出甘泉。", "榮親行有千鍾祿，爲壽慚無百斛船。", "喜氣在顔窺貴客，清風滿枕扇高眠。", "朝廷指日先封薛，歸侍萱堂冕有蟬。"]'),
('d1ca4408-7bab-48cd-b4c0-10767a0651c7','送吳憲知叔','王十朋','宋','宋诗','song-poetry','','[]','出郊聞好語，盡道憲車賢。',48,'全唐诗/poet.song.119000.json','["出郊聞好語，盡道憲車賢。", "郡不留三宿，人皆仰二天。", "薦章先白屋，貢宇給青錢。", "上正開宣室，公歸席定前。"]'),
('da29519e-b76f-42bd-9510-287bde283f83','祈雨未應提舶知宗道觀焚香明日遂雨提舶有詩次韻','王十朋','宋','宋诗','song-poetry','','[]','一雨誰之力，因公發善心。',48,'全唐诗/poet.song.119000.json','["一雨誰之力，因公發善心。", "同爲上公請，小作傅巖霖。", "高廩行將實，南風日已駸。", "涓辰祈善利，感應亦猶今。"]'),
('f745d5a8-53a1-47ab-9c14-c057a68bde26','次韵知宗賀雨','王十朋','宋','宋诗','song-poetry','','[]','雲飛初類愈隨郊，珠忽跳空室舞蛟。',64,'全唐诗/poet.song.119000.json','["雲飛初類愈隨郊，珠忽跳空室舞蛟。", "但願農多大田稼，不愁風捲少陵茅。", "才疏政事由來拙，天遠精誠未易交。", "三日禱祈纔一雨，自知無處避謳嘲。"]'),
('c42bd4a2-9238-4672-ab35-95fe295e9eee','次韵陸倅賀雨','王十朋','宋','宋诗','song-poetry','','[]','目注雲霓爲國憂，何心肥馬更輕裘。',64,'全唐诗/poet.song.119000.json','["目注雲霓爲國憂，何心肥馬更輕裘。", "庶民愁恨旱無雨，三日滂沱農有秋。", "且喜上公容我請，不辭大白共君浮。", "人言太守無才術，端藉士龍監此州。"]'),
('d87847b5-5712-4ef1-abd1-684bc8778e74','夏四月不雨守臣不職之罪也將有請于神雨忽大作陳賀州有詩贊喜次韵以酬  其一','王十朋','宋','宋诗','song-poetry','','[]','不是尋常喜雨詩，言存軌物類臧僖。',32,'全唐诗/poet.song.119000.json','["不是尋常喜雨詩，言存軌物類臧僖。", "相將歸賀天朝雨，定有忠言結主知。"]'),
('866d49e4-e46f-4da2-8efc-54e7f28d8fd1','夏四月不雨守臣不職之罪也將有請于神雨忽大作陳賀州有詩贊喜次韵以酬  其二','王十朋','宋','宋诗','song-poetry','','[]','郡人方切望雲霓，忽見高田水入低。',32,'全唐诗/poet.song.119000.json','["郡人方切望雲霓，忽見高田水入低。", "正好歸田飽黄犢，不須騎馬聽朝鷄。"]'),
('2047cb27-545e-486b-a46c-a96c0113cd6c','夏四月不雨守臣不職之罪也將有請于神雨忽大作陳賀州有詩贊喜次韵以酬  其三','王十朋','宋','宋诗','song-poetry','','[]','賀州賀雨句如何，不減夔州夢得歌。',32,'全唐诗/poet.song.119000.json','["賀州賀雨句如何，不減夔州夢得歌。", "更有一犁江上曲，它年傳誦出金坡。"]'),
('6a7be116-9d99-4ee9-b240-fab9f0b3fca8','夏四月不雨守臣不職之罪也將有請于神雨忽大作陳賀州有詩贊喜次韵以酬  其四','王十朋','宋','宋诗','song-poetry','','[]','政拙年年厭禱祈，心香一炷逐雲飛。',32,'全唐诗/poet.song.119000.json','["政拙年年厭禱祈，心香一炷逐雲飛。", "老農問我何良苦，薄有田園胡不歸。"]'),
('76493862-8a88-4e7c-a624-2c1e654f8450','夏四月不雨守臣不職之罪也將有請于神雨忽大作陳賀州有詩贊喜次韵以酬  其五','王十朋','宋','宋诗','song-poetry','','[]','刺桐抽葉張青蓋，紫帽蒙霞麗錦籠。',32,'全唐诗/poet.song.119000.json','["刺桐抽葉張青蓋，紫帽蒙霞麗錦籠。", "今歲家家定高廩，多苗寧復羨吳儂。"]'),
('c20b0bce-03f0-4caa-8818-e2da31a9d7a1','次韵蔣教授喜雨','王十朋','宋','宋诗','song-poetry','','[]','我來遥自東甌東，賢非朱邑鄉守桐。',160,'全唐诗/poet.song.119000.json','["我來遥自東甌東，賢非朱邑鄉守桐。", "半年爲郡治亡狀，四月不雨心憂農。", "水田龜拆秧已老，雲霓望斷天穹隆。", "少學春秋老欲用，區區願請應上公。", "真人不待瓣香禱，紫帽已有微雲蒙。", "沛然一雨四境足，眼見䆉䅉青連空。", "皇天愛民恕守罪，有始其賜寧無終。", "既令地免晉國赤，亦不水似堯時洪。", "廣文先生坐絳帳，憂國心與黄堂同。", "揮毫作誦繼吉甫，開卷穆穆生清風。"]'),
('c9dae7bd-804a-4465-a6e4-3a78ad2a047d','知宗游延福有詩見懷次韻以酬','王十朋','宋','宋诗','song-poetry','','[]','向來雲榭倚闌干，興已遥馳郭外山。',64,'全唐诗/poet.song.119000.json','["向來雲榭倚闌干，興已遥馳郭外山。", "風伯如嫌俗駕至，禪房疑爲病夫關。", "鈴齋倦卧眼界寂，詩社免陪心境閑。", "蠟屐何時破吾願，與君舒嘯翠微間。"]'),
('91aa3131-9669-415f-a266-3a9f4cbe0622','提舉延福祈風道中有作次韻','王十朋','宋','宋诗','song-poetry','','[]','雨初欲乞下俄沛，風不待祈來已薰。',64,'全唐诗/poet.song.119000.json','["雨初欲乞下俄沛，風不待祈來已薰。", "瑞氣遥看騰紫帽，豐年行見割黄雲。", "大商航海蹈萬死，遠物輸官被八垠。", "頼有舶臺賢使者，端能薄斂體吾君。"]'),
('d06335db-c680-48fe-b818-11c493d4b5ae','病中食火山荔枝','王十朋','宋','宋诗','song-poetry','','[]','前年夔州食荔支，同僚共賦新紅詩。',128,'全唐诗/poet.song.119000.json','["前年夔州食荔支，同僚共賦新紅詩。", "妃子名園世所貴，不似詩史堂前奇。", "去冬分符來南土，半月身行荔支圃。", "三州嘉木皆眼見，更閲君謨向來譜。", "臨漳一種名火山，品雖云下熟則先。", "從今漸入荔佳境，陳江未擘先流涎。", "老病餘生怯嘉果，日啗那能三百顆。", "慇勤爲破絳紗囊，心火驚添火山火。"]'),
('a6b6eb20-1475-4644-9bc0-66cac5508b1b','諸公和詩再用前韻','王十朋','宋','宋诗','song-poetry','','[]','屏間觀畫頤頻支，想像風味哦新詩。',131,'全唐诗/poet.song.119000.json','["屏間觀畫頤頻支，想像風味哦新詩。", "火山太早反遭駡，陳紫未顯誰稱奇。", "氣稟南方君子土，不近長安帝王圃。", "安排名字知何人，誤與牡丹同入譜。", "泉南老守思故山，荔熟我去誰後先。", "但願丁香一株熟，添入藥裹痊痰{疒延}。", "平生夢寐南州果，瘦腹如蟬消幾顆。", "明年何處飣杯盤，雁蕩山前月流火。"]'),
('93f8e260-86f1-4b6d-8bfe-145790704a68','漳州石教授寄火山荔支','王十朋','宋','宋诗','song-poetry','','[]','炎方摘實走筠籠，千顆遥遥寄病翁。',64,'全唐诗/poet.song.119000.json','["炎方摘實走筠籠，千顆遥遥寄病翁。", "未啗吾州法石白，且嘗鄰郡火山紅。", "攙先趁得楊盧雨，珍重來從芹藻宮。", "我欲細論香色味，一尊何日廣文同。"]'),
('694ca750-bb7f-4bbd-a724-58cc81d48da1','東湖小飲','王十朋','宋','宋诗','song-poetry','','["\u897f\u6e56"]','微凉散梅潤，濃綠敷桐陰。',120,'全唐诗/poet.song.119000.json','["微凉散梅潤，濃綠敷桐陰。", "送客出東郊，駕言事幽尋。", "湖光照我眼，荷香清我襟。", "平疇入遠望，歲有其自今。", "牛眠種已畢，蛤吠苗初深。", "古亭懷二公，遥望羅千岑。", "邂逅得良友，欣然契予心。", "喬松喜客來，風枝出清音。", "手持荷葉杯，共對蓮花斟。", "東湖異西湖，有詩不妨吟。"]'),
('708e983c-dca8-4a2d-9028-9852a0300785','東湖','王十朋','宋','宋诗','song-poetry','','["\u897f\u6e56"]','二公亭挿芰荷間，綠蓋紅粧四面環。',32,'全唐诗/poet.song.119000.json','["二公亭挿芰荷間，綠蓋紅粧四面環。", "若把西湖比西子，東湖自合比東山。"]'),
('3add7829-9ff5-4a51-9eb5-a27956e8d6e5','愛松堂','王十朋','宋','宋诗','song-poetry','','[]','炎炎畏日愛濃陰，穆穆清風愛好音。',32,'全唐诗/poet.song.119000.json','["炎炎畏日愛濃陰，穆穆清風愛好音。", "不獨愛松兼愛竹，此君亦有歲寒心。"]'),
('b8be5789-f1fc-4a7c-a8fe-6b2ee0c2ae81','食瓜呈知宗','王十朋','宋','宋诗','song-poetry','','[]','荔子勞民疏伯游，蒲萄釀酒博凉州。',32,'全唐诗/poet.song.119000.json','["荔子勞民疏伯游，蒲萄釀酒博凉州。", "何人傳得東陵種，大勝家封萬戶侯。"]'),
('9f24f190-7c1d-40d1-9461-6fa4914062d4','題節推納凉軒','王十朋','宋','宋诗','song-poetry','','[]','有客游蓮幕，開軒更傍蓮。',48,'全唐诗/poet.song.119000.json','["有客游蓮幕，開軒更傍蓮。", "披襟風未賦，遞嘯句先聯。", "境凈凉偏乏，心清暑自蠲。", "快哉誰與共，廣厦集群仙。"]'),
('4e9c49b5-3dc9-4cf4-b2e8-69be30d3e3c3','州宅即事','王十朋','宋','宋诗','song-poetry','','[]','泉南古州宅，草木有遺芳。',48,'全唐诗/poet.song.119000.json','["泉南古州宅，草木有遺芳。", "鷹爪冬猶綠，闍提夜更香。", "佛桑朝暮異，荔子歲年長。", "惟有松并竹，青青似故鄉。"]'),
('6253b782-dedd-407a-ac61-ba7f06d81b49','修鷹爪花架','王十朋','宋','宋诗','song-poetry','','[]','有花藤蔓生，封植傍州宅。',48,'全唐诗/poet.song.119000.json','["有花藤蔓生，封植傍州宅。", "狀類鷙禽爪，葉作翻風翮。", "酸分含笑香，黄带薝蔔色。", "架倒吾爲扶，清凉納朝夕。"]'),
('4fc6f432-45cd-4aa8-9517-316e40d0aca2','鷹爪花','王十朋','宋','宋诗','song-poetry','','[]','誰把名鷹爪，天然狀不殊。',24,'全唐诗/poet.song.119000.json','["誰把名鷹爪，天然狀不殊。", "無心事搏擊，中有鳥相呼。"]'),
('7a58b683-8e30-40ef-8aac-afd3fa8e1039','長生草','王十朋','宋','宋诗','song-poetry','','[]','草有長生者，無根葉自抽。',24,'全唐诗/poet.song.119000.json','["草有長生者，無根葉自抽。", "秦皇不知此，誤向海山求。"]'),
('1a2d7ba8-db87-433a-96ac-61d12bd02a03','榕木','王十朋','宋','宋诗','song-poetry','','[]','南國有喬木，老非梁棟材。',24,'全唐诗/poet.song.119000.json','["南國有喬木，老非梁棟材。", "清陰可以覆，亦足報栽培。"]'),
('6d5d4059-140e-4815-b15a-47a31854337c','安靜堂','王十朋','宋','宋诗','song-poetry','','[]','前賢治迹尚堪尋，留得堂名直至今。',32,'全唐诗/poet.song.119000.json','["前賢治迹尚堪尋，留得堂名直至今。", "若欲斯民盡安靜，要須安靜自家心。"]'),
('06728503-6723-44af-97e6-0e80457cfe90','中和堂','王十朋','宋','宋诗','song-poetry','','[]','堂前老木幾經春，閲徧泉南舊守臣。',32,'全唐诗/poet.song.119000.json','["堂前老木幾經春，閲徧泉南舊守臣。", "盡向中和堂上坐，中和爲治有何人。"]'),
('8f68ae8e-a576-4d67-9b9f-3a9e6119fdc6','雲榭','王十朋','宋','宋诗','song-poetry','','[]','山生取地榭侵雲，土木多應役鬼神。',32,'全唐诗/poet.song.119000.json','["山生取地榭侵雲，土木多應役鬼神。", "好向危欄高著眼，閭閻無限困窮人。"]'),
('012ca45b-53d7-4dfe-a645-524a84ddf887','二山亭','王十朋','宋','宋诗','song-poetry','','[]','連年行役厭間關，踏遍千山見二山。',32,'全唐诗/poet.song.119000.json','["連年行役厭間關，踏遍千山見二山。", "欲識泉南山面目，群山總在一亭間。"]'),
('39a6129f-a228-40be-b8a9-ab0c400be43d','清暑堂','王十朋','宋','宋诗','song-poetry','','[]','九夏炎方氣欝蒸，沉沉廣厦有凉生。',32,'全唐诗/poet.song.119000.json','["九夏炎方氣欝蒸，沉沉廣厦有凉生。", "仁風未慰黎民意，何忍堂中暑獨清。"]'),
('7890f5d0-eded-4b07-af38-5b37b4594bca','貢院納凉分韻得湖字','王十朋','宋','宋诗','song-poetry','','[]','突兀千間屋，清凉五月湖。',48,'全唐诗/poet.song.119000.json','["突兀千間屋，清凉五月湖。", "人才此塗出，暑氣坐中無。", "虎榜唐文傑，雄風楚大夫。", "相期游廣厦，慷慨論唐虞。"]'),
('7e91a40e-57bd-45e8-9ad6-f2f66a4bc076','知宗游東湖用貢院納凉韻見寄次韻奉酬','王十朋','宋','宋诗','song-poetry','','[]','東湖曾一到，想像賀家湖。',48,'全唐诗/poet.song.119000.json','["東湖曾一到，想像賀家湖。", "花似越女好，人如狂客無。", "高吟還老手，野趣屬潛夫。", "歸奏南風曲，薰兮欲和虞。"]'),
('a8ffd363-9089-4664-9c54-90080e2926fd','再和','王十朋','宋','宋诗','song-poetry','','[]','宗老呼佳客，同觀郭外湖。',48,'全唐诗/poet.song.119000.json','["宗老呼佳客，同觀郭外湖。", "融樽常喜滿，參酒不言無。", "草色懷三徑，松聲憶五夫。", "公游更何日，旌至定招虞。"]'),
('52b80268-5001-44af-8966-2c59aaab076f','比和知宗詩牽於押韻以招虞爲戲果蒙見招復用前韻','王十朋','宋','宋诗','song-poetry','','[]','宗英真好事，呼客共游湖。',48,'全唐诗/poet.song.119000.json','["宗英真好事，呼客共游湖。", "携具臨平遠，觀山對有無。", "十花逢凈友，千頃和雲夫。", "得玉又求劍，無厭慚似虞。"]'),
('f793ef7c-e7a0-4860-b53a-9a4711c7c9ac','游湖值雨薛士昭衣巾霑濕意氣自若戲用前韻','王十朋','宋','宋诗','song-poetry','','[]','薛侯真不俗，十日兩東湖。',48,'全唐诗/poet.song.119000.json','["薛侯真不俗，十日兩東湖。", "俊逸詩篇有，倉皇雨具無。", "袍雖濕毅父，眉不皺堯夫。", "異夕月離畢，游宜備不虞。"]'),
('042e798b-2348-463a-b406-3b9c51adacdf','次韻知宗游二公亭','王十朋','宋','宋诗','song-poetry','','[]','前日同登二山亭，清源入望清更清。',96,'全唐诗/poet.song.119000.json','["前日同登二山亭，清源入望清更清。", "宗英載酒挾兩客，破暑共作城東行。", "東湖未到聞人說，香有荷華如鄭隰。", "社中未爲三笑游，亭上姑尋二公跡。", "銜盃適意論交情，江山照眼增雙明。", "聊效韓公文字飲，奚用鼎沸笙篁聲。"]'),
('ea0b0447-898a-4a83-bd27-b40f7288570c','提舶示觀楚東集用張安國韻因思鄱陽與唱酬者五人今六年矣陳何二公已物故餘亦離索爲之慨然復用元韻','王十朋','宋','宋诗','song-poetry','','[]','憶昔江東會衆仙，詩筒來徃走山川。',64,'全唐诗/poet.song.119000.json','["憶昔江東會衆仙，詩筒來徃走山川。", "造樓游戲偶成鳳，煉石辛勤同補天。", "堪嘆交游隔生死，尚餘文字带芳鮮。", "欲收膏馥增前集，舶使新詩自合編。"]'),
('9877d4f3-3662-4788-9818-e506cff8e32f','五月晦日會知宗提舶通判納凉雲榭提舶用仙字韻即席賦詩中寓四字次韻以酬','王十朋','宋','宋诗','song-poetry','','[]','雲榭銜盃半八仙，却疑來自蜀山川。',64,'全唐诗/poet.song.119000.json','["雲榭銜盃半八仙，却疑來自蜀山川。", "地如洙泗占高第，人似羲和分昊天。", "單騎聯翩成駟馬，杯羹淡薄從三鮮。", "國風雅頌寂寥久，太史採詩宜與編。"]'),
('40277c0b-ab5a-470a-b479-912cd9a2f058','知宗提舶即席贈詩用元韻以酬并簡通判','王十朋','宋','宋诗','song-poetry','','[]','子政堂堂漢列仙，清標况對馬文淵。',64,'全唐诗/poet.song.119000.json','["子政堂堂漢列仙，清標况對馬文淵。", "催詩風送千山雨，把酒凉生五月天。", "老子濫分南郡竹，貳車行擊故家鮮。", "誤蒙好語相提拂，豈有功名上簡編。"]'),
('37a23594-e5b0-437c-8cf2-0b4e603ee556','提舶欲移厨過雲榭示詩次韻','王十朋','宋','宋诗','song-poetry','','[]','雨中前日過蘇端，又欲移厨就稍寬。',64,'全唐诗/poet.song.119000.json','["雨中前日過蘇端，又欲移厨就稍寬。", "古榭有風聊可共，衰顔得酒定須丹。", "謫仙醉後句尤勁，東野老來詩更寒。", "繼取洛中真率會，他年要作畫圖看。"]'),
('6f69df51-a60d-4f10-8b81-c53281cb870c','提舶携具過雲榭知宗出示和章復用韻  其一','王十朋','宋','宋诗','song-poetry','','[]','不須蠟屐上林端，高處登臨眼自寬。',64,'全唐诗/poet.song.119000.json','["不須蠟屐上林端，高處登臨眼自寬。", "䆉䅉風翻梅裏白，離支日照鶴頂丹。", "山川滿目如京洛，臺榭侵雲類廣寒。", "賓主徃來俱不遠，如棠不比魯侯觀。"]'),
('363c17d2-1baa-415e-a5af-0d01b171d220','提舶携具過雲榭知宗出示和章復用韻  其二','王十朋','宋','宋诗','song-poetry','','[]','老來憂患苦無端，一笑相逢强自寬。',64,'全唐诗/poet.song.119000.json','["老來憂患苦無端，一笑相逢强自寬。", "詩律頻調代音樂，壽觴滿引當仙丹。", "二山坐對事非偶，三徑思歸盟不寒。", "出岫白雲知幾許，榭中矯首共遐觀。"]'),
('3f7f0c13-a430-4f43-81ee-ca4ce927b420','知宗即席和端字韻三首提舶退即足之予第三詩經夕方和錄呈二家','王十朋','宋','宋诗','song-poetry','','[]','毫禿中山硯滌端，社中詩令不容寬。',64,'全唐诗/poet.song.119000.json','["毫禿中山硯滌端，社中詩令不容寬。", "難追老杜風騷手，徒費昌黎點勘丹。", "搜我枯腸鬚鬢皓，吟公佳句齒牙寒。", "自慙淺陋如曹鄶，季子觀風定不觀。"]'),
('4de06b0e-159a-4556-a5cf-6866ee899279','傅興化送蔡端明集報以溫公文因求端明帖','王十朋','宋','宋诗','song-poetry','','[]','迂叟遺文整頓初，寄君聊當報瓊琚。',32,'全唐诗/poet.song.119000.json','["迂叟遺文整頓初，寄君聊當報瓊琚。", "南鄰尚有無厭意，更覓皇朝第一書。"]'),
('473d0e12-29e6-4022-8630-9a458e8dc493','陳賀州速客送酒','王十朋','宋','宋诗','song-poetry','','[]','賀州呼客細論文，我欲相過與共論。',64,'全唐诗/poet.song.119000.json','["賀州呼客細論文，我欲相過與共論。", "正恐俗他真率會，不如分去聖賢樽。", "簪當濃綠畫中盍，杯向輕紅擘處翻。", "即席有詩應寄我，敲門來送月黄昏。"]'),
('b44653eb-2f3c-4608-b061-5f3d0fedc75f','丁惠安贈肉蓯蓉','王十朋','宋','宋诗','song-poetry','','[]','老子當歸興已濃，令君何事寄蓯蓉。',32,'全唐诗/poet.song.119000.json','["老子當歸興已濃，令君何事寄蓯蓉。", "行將卜築前湖去，簑笠牽牛作老農。"]'),
('3652cf3f-3e46-460c-aba6-0ed0cf5a0666','修戒石','王十朋','宋','宋诗','song-poetry','','[]','君以民脂膏，祿爾大夫士。',132,'全唐诗/poet.song.119000.json','["君以民脂膏，祿爾大夫士。", "脂膏飽其腹，曾不念赤子。", "貪暴以自誅，誅求不知恥。", "指呼有鷹犬，嗜慾肆蛇豕。", "但言民至愚，孰謂天在邇。", "昭然甚可畏，殃必反乎爾。", "聖訓十有六，簡嚴具天理。", "大字刻山骨，朝夕臨坐起。", "一念苟或違，方寸寧不愧。", "清源庭中石，整頓自今始。", "何敢警同僚，兢兢惟敕己。"]'),
('69c20b7a-135a-4e16-9779-2b612e1bb501','知宗送玉友酒','王十朋','宋','宋诗','song-poetry','','[]','鈴齋晝寢夢初醒，忽見雙罌眼欲驚。',32,'全唐诗/poet.song.119000.json','["鈴齋晝寢夢初醒，忽見雙罌眼欲驚。", "誰送甕頭新玉友，人言天上老宗英。"]'),
('b65e2c46-f003-49a4-b571-4d41e0ad751e','林漕世傳贈莆中荔子名狀元紅分送陸倅陸有詩次韻','王十朋','宋','宋诗','song-poetry','','[]','譜中不見見屏中，正與花王雅目同。',32,'全唐诗/poet.song.119000.json','["譜中不見見屏中，正與花王雅目同。", "別駕破荒吟好句，少陵詩裏擘輕紅。"]'),
('308a2665-15d0-4d7d-9568-546c1332fdd2','提舶送荔支借用前韻','王十朋','宋','宋诗','song-poetry','','[]','舶臺丹荔新秋熟，風味如人自不同。',32,'全唐诗/poet.song.119000.json','["舶臺丹荔新秋熟，風味如人自不同。", "名字未安真缺典，從今呼作馬家紅。"]'),
('4610e995-bd7c-47ea-9151-1872f29ec616','州治有忠獻堂以韓魏公始生得名廢於俗吏更以清暑今復之','王十朋','宋','宋诗','song-poetry','','[]','相出相州生此州，巍巍勳業宋伊周。',32,'全唐诗/poet.song.119000.json','["相出相州生此州，巍巍勳業宋伊周。", "後人莫要輕更改，別有堂名勝此不。"]'),
('64b79a36-478a-4035-b4d7-41c257d1da51','六月二十五日會同官于貢院用前一絕分韻得相字','王十朋','宋','宋诗','song-poetry','','[]','天作元聖配，公非淺夫相。',240,'全唐诗/poet.song.119000.json','["天作元聖配，公非淺夫相。", "乘風來帝旁，捧日到天上。", "兵戎在呼吸，端委見力量。", "三朝社稷臣，勳業誰輩行。", "堂堂國伊周，勃輩安敢望。", "清源始生地，風土至今王。", "釋氏從何得，抱送真不妄。", "好事榜其堂，嘉名無以尚。", "何人輒更改，有識爲悽愴。", "端同聖削迹，又類玄覆醤。", "思賢舊觀復，聞風懦夫壯。", "堂上生輝光，如公名始唱。", "姦骨死猶寒，如公昔爲將。", "畫象出貂蟬，疑公尚亡恙。", "平生蓼莪心，眷此應不忘。", "嗟予生太晚，不識天人狀。", "版圖猶未復，晝錦無由訪。", "維揚金繫腰，歎息爲誰放。", "一麾忽南來，遺迹增慕嚮。", "當於異夢處，祠堂爲公創。"]'),
('e843d9a5-7aeb-451f-a2ba-2e6a76ebcef3','新第先歸者五人燕于黄堂故事也酒半啜茶于忠獻堂持盃以勸即席贈詩','王十朋','宋','宋诗','song-poetry','','[]','四海英才入網羅，清源龍虎姓名多。',64,'全唐诗/poet.song.119000.json','["四海英才入網羅，清源龍虎姓名多。", "經魁蘭省得人傑，策射楓庭收甲科。", "奎宿呈祥前未見，緯星還舍首相過。", "一盃忠獻堂中酒，名節相期要不磨。"]'),
('05120202-5315-41af-b11a-ef3665277c8a','寫真自題','王十朋','宋','宋诗','song-poetry','','[]','顔蒼髮白少精神，傳得泉南老病身。',32,'全唐诗/poet.song.119000.json','["顔蒼髮白少精神，傳得泉南老病身。", "莫著金章著蓑笠，丹青寫出更須真。"]'),
('86b65db4-1a55-449f-8386-5a1b87a0d28c','士昭贈寸金魚子','王十朋','宋','宋诗','song-poetry','','[]','三印子魚猶未食，寸金魚子輒先嘗。',32,'全唐诗/poet.song.119000.json','["三印子魚猶未食，寸金魚子輒先嘗。", "鄉人得得分鄉味，轉使鄉心念故鄉。"]'),
('9f8fac07-517e-4f1c-91b6-7b304d796bc4','贈第二人石察判','王十朋','宋','宋诗','song-poetry','','[]','策冠諸儒已奏聞，不妨居次避平津。',64,'全唐诗/poet.song.119000.json','["策冠諸儒已奏聞，不妨居次避平津。", "坐看萬石門闌大，轉覺朋山氣象新。", "黄卷更窮稽古力，青雲莫負致君身。", "試觀忠獻堂中像，亦是當時第二人。"]'),
('9db1e456-59be-4b36-9c99-1f127c8bd624','荔支七絕 陳紫','王十朋','宋','宋诗','song-poetry','','[]','端明品第首推陳，花裏姚黄是等倫。',32,'全唐诗/poet.song.119000.json','["端明品第首推陳，花裏姚黄是等倫。", "郡圃一株稱小紫，故家風味自宜珍。"]'),
('414f32f6-efc8-480e-ba66-9a20c6f2c1c0','荔支七絕 江綠','王十朋','宋','宋诗','song-poetry','','[]','枝頭已熟疑非熟，蔡譜江家綠荔支。',32,'全唐诗/poet.song.119000.json','["枝頭已熟疑非熟，蔡譜江家綠荔支。", "真與泉南人物稱，果中猶作亞魁推。"]'),
('c2567cfa-86cd-4474-b23f-c94cbea07854','荔支七絕 皺玉','王十朋','宋','宋诗','song-poetry','','[]','莆中皺玉價傾城，品第吾何敢妄評。',32,'全唐诗/poet.song.119000.json','["莆中皺玉價傾城，品第吾何敢妄評。", "只恐此非真皺玉，果然是玉亦虛名。"]');
